window.KJV1769_STRONG_BOOKS["Rom"] = {"osis":"Rom","book":"로마서","verses":{"1:1":{"text":"Paul, a servant of Jesus Christ, called to be an apostle, separated unto the gospel of God,","words":[["G3972","Paul",0,4],["G1401","a servant",6,15],["G2424","of Jesus",16,24],["G5547","Christ",25,31],["G2822","called",33,39],["G0652","to be an apostle",40,56],["G0873","separated",58,67],["G1519","unto",68,72],["G2098","the gospel",73,83],["G2316","of God",84,90]]},"1:2":{"text":"(Which he had promised afore by his prophets in the holy scriptures,)","words":[["G3739","(Which",0,6],["G4279","he had promised afore",7,28],["G1223","by",29,31],["G0846","his",32,35],["G4396","prophets",36,44],["G1722","in",45,47],["G0040","the holy",48,56],["G1124","scriptures",57,67]]},"1:3":{"text":"Concerning his Son Jesus Christ our Lord, which was made of the seed of David according to the flesh;","words":[["G4012","Concerning",0,10],["G0846","his",11,14],["G5207","Son",15,18],["G2424","Jesus",19,24],["G5547","Christ",25,31],["G2257","our",32,35],["G2962","Lord",36,40],["G3588","which",42,47],["G1096","was made",48,56],["G1537","of",57,59],["G4690","the seed",60,68],["G1138","of David",69,77],["G2596","according",78,87],["G4561","to the flesh",88,100]]},"1:4":{"text":"And declared to be the Son of God with power, according to the spirit of holiness, by the resurrection from the dead:","words":[["G3724","And declared",0,12],["G5207","to be the Son",13,26],["G2316","of God",27,33],["G1722","with",34,38],["G1411","power",39,44],["G2596","according",46,55],["G4151","to the spirit",56,69],["G0042","of holiness",70,81],["G1537","by",83,85],["G0386","the resurrection",86,102],["G3498","from the dead",103,116]]},"1:5":{"text":"By whom we have received grace and apostleship, for obedience to the faith among all nations, for his name:","words":[["G1223","By",0,2],["G3739","whom",3,7],["G2983","we have received",8,24],["G5485","grace",25,30],["G2532","and",31,34],["G0651","apostleship",35,46],["G1519","for",48,51],["G5218","obedience",52,61],["G4102","to the faith",62,74],["G1722","among",75,80],["G3956","all",81,84],["G1484","nations",85,92],["G5228","for",94,97],["G0846","his",98,101],["G3686","name",102,106]]},"1:6":{"text":"Among whom are ye also the called of Jesus Christ:","words":[["G1722","Among",0,5],["G3739","whom",6,10],["G2075","are",11,14],["G5210","ye",15,17],["G2532","also",18,22],["G2822","the called",23,33],["G2424","of Jesus",34,42],["G5547","Christ",43,49]]},"1:7":{"text":"To all that be in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father, and the Lord Jesus Christ.","words":[["G3956","To all",0,6],["G5607","that be",7,14],["G1722","in",15,17],["G4516","Rome",18,22],["G0027","beloved",24,31],["G2316","of God",32,38],["G2822","called",40,46],["G0040","to be saints",47,59],["G5485","Grace",61,66],["G5213","to you",67,73],["G2532","and",74,77],["G1515","peace",78,83],["G0575","from",84,88],["G2316","God",89,92],["G2257","our",93,96],["G3962","Father",97,103],["G2532","and",105,108],["G2962","the Lord",109,117],["G2424","Jesus",118,123],["G5547","Christ",124,130]]},"1:8":{"text":"First, I thank my God through Jesus Christ for you all, that your faith is spoken of throughout the whole world.","words":[["G4412","First",0,5],["G3303","First",0,5],["G2168","I thank",7,14],["G3450","my",15,17],["G2316","God",18,21],["G1223","through",22,29],["G2424","Jesus",30,35],["G5547","Christ",36,42],["G5228","for",43,46],["G5216","you",47,50],["G3956","all",51,54],["G3754","that",56,60],["G5216","your",61,65],["G4102","faith",66,71],["G2605","is spoken",72,81],["G1722","of throughout",82,95],["G3650","the whole",96,105],["G2889","world",106,111]]},"1:9":{"text":"For God is my witness, whom I serve with my spirit in the gospel of his Son, that without ceasing I make mention of you always in my prayers;","words":[["G1063","For",0,3],["G2316","God",4,7],["G2076","is",8,10],["G3450","my",11,13],["G3144","witness",14,21],["G3739","whom",23,27],["G3000","I serve",28,35],["G1722","with",36,40],["G3450","my",41,43],["G4151","spirit",44,50],["G1722","in",51,53],["G2098","the gospel",54,64],["G0846","of his",65,71],["G5207","Son",72,75],["G5613","that",77,81],["G0089","without ceasing",82,97],["G4160","I make",98,104],["G3417","mention",105,112],["G5216","of you",113,119],["G3842","always",120,126],["G1909","in",127,129],["G3450","my",130,132],["G4335","prayers",133,140]]},"1:10":{"text":"Making request, if by any means now at length I might have a prosperous journey by the will of God to come unto you.","words":[["G1189","Making request",0,14],["G1513","if by any means",16,31],["G2235","now",32,35],["G4218","at length",36,45],["G2137","I might have a prosperous journey",46,79],["G1722","by",80,82],["G2307","the will",83,91],["G2316","of God",92,98],["G2064","to come",99,106],["G4314","unto",107,111],["G5209","you",112,115]]},"1:11":{"text":"For I long to see you, that I may impart unto you some spiritual gift, to the end ye may be established;","words":[["G1063","For",0,3],["G1971","I long",4,10],["G1492","to see",11,17],["G5209","you",18,21],["G2443","that",23,27],["G3330","I may impart",28,40],["G5213","unto you",41,49],["G5100","some",50,54],["G4152","spiritual",55,64],["G5486","gift",65,69],["G1519","to the end",71,81],["G5209","ye",82,84],["G4741","may be established",85,103]]},"1:12":{"text":"That is, that I may be comforted together with you by the mutual faith both of you and me.","words":[["G1161","That",0,4],["G5124","That",0,4],["G2076","is",5,7],["G4837","that I may be comforted together",9,41],["G1722","with",42,46],["G5213","you",47,50],["G1223","by",51,53],["G1722","by",51,53],["G0240","the mutual",54,64],["G4102","faith",65,70],["G5037","both",71,75],["G5216","of you",76,82],["G2532","and",83,86],["G1700","me",87,89]]},"1:13":{"text":"Now I would not have you ignorant, brethren, that oftentimes I purposed to come unto you, (but was let hitherto,) that I might have some fruit among you also, even as among other Gentiles.","words":[["G1161","Now",0,3],["G2309","I would",4,11],["G3756","not",12,15],["G0050","have",16,20],["G5209","you",21,24],["G0050","ignorant",25,33],["G0080","brethren",35,43],["G3754","that",45,49],["G4178","oftentimes",50,60],["G4388","I purposed",61,71],["G2064","to come",72,79],["G4314","unto",80,84],["G5209","you",85,88],["G2532","(but",90,94],["G2967","was let",95,102],["G0891","hitherto",103,111],["G1204","hitherto",103,111],["G2443",") that",112,118],["G2192","I might have",119,131],["G5100","some",132,136],["G2590","fruit",137,142],["G1722","among",143,148],["G5213","you",149,152],["G2532","also",153,157],["G2531","even as",159,166],["G2532","even as",159,166],["G1722","among",167,172],["G3062","other",173,178],["G1484","Gentiles",179,187]]},"1:14":{"text":"I am debtor both to the Greeks, and to the Barbarians; both to the wise, and to the unwise.","words":[["G1510","I am",0,4],["G3781","debtor",5,11],["G5037","both",12,16],["G1672","to the Greeks",17,30],["G2532","and",32,35],["G0915","to the Barbarians",36,53],["G5037","both",55,59],["G4680","to the wise",60,71],["G2532","and",73,76],["G0453","to the unwise",77,90]]},"1:15":{"text":"So, as much as in me is, I am ready to preach the gospel to you that are at Rome also.","words":[["G3779","So",0,2],["G2596","as much as",4,14],["G1691","in me is",15,23],["G4289","I am ready",25,35],["G2097","to preach the gospel",36,56],["G5213","to you",57,63],["G1722","that are at",64,75],["G4516","Rome",76,80],["G2532","also",81,85]]},"1:16":{"text":"For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek.","words":[["G1063","For",0,3],["G1870","I am",4,8],["G3756","not",9,12],["G1870","ashamed",13,20],["G2098","of the gospel",21,34],["G5547","of Christ",35,44],["G1063","for",46,49],["G2076","it is",50,55],["G1411","the power",56,65],["G2316","of God",66,72],["G1519","unto",73,77],["G4991","salvation",78,87],["G3956","to every one",88,100],["G4100","that believeth",101,115],["G2453","to the Jew",117,127],["G4412","first",128,133],["G5037","and",135,138],["G2532","also",139,143],["G1672","to the Greek",144,156]]},"1:17":{"text":"For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith.","words":[["G1063","For",0,3],["G1722","therein",4,11],["G0846","therein",4,11],["G0601","is",12,14],["G1343","the righteousness",15,32],["G2316","of God",33,39],["G0601","revealed",40,48],["G1537","from",49,53],["G4102","faith",54,59],["G1519","to",60,62],["G4102","faith",63,68],["G2531","as",70,72],["G1125","it is written",73,86],["G1161","",-1,-1],["G1342","The just",88,96],["G2198","shall live",97,107],["G1537","by",108,110],["G4102","faith",111,116]]},"1:18":{"text":"For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth in unrighteousness;","words":[["G1063","For",0,3],["G3709","the wrath",4,13],["G2316","of God",14,20],["G0601","is revealed",21,32],["G0575","from",33,37],["G3772","heaven",38,44],["G1909","against",45,52],["G3956","all",53,56],["G0763","ungodliness",57,68],["G2532","and",69,72],["G0093","unrighteousness",73,88],["G0444","of men",89,95],["G2722","who hold",97,105],["G0225","the truth",106,115],["G1722","in",116,118],["G0093","unrighteousness",119,134]]},"1:19":{"text":"Because that which may be known of God is manifest in them; for God hath shewed it unto them.","words":[["G1360","Because",0,7],["G1110","that which may be known",8,31],["G2316","of God",32,38],["G2076","is",39,41],["G5318","manifest",42,50],["G1722","in",51,53],["G0846","them",54,58],["G1063","for",60,63],["G2316","God",64,67],["G5319","hath shewed",68,79],["G0846","it unto them",80,92]]},"1:20":{"text":"For the invisible things of him from the creation of the world are clearly seen, being understood by the things that are made, even his eternal power and Godhead; so that they are without excuse:","words":[["G1063","For",0,3],["G0517","the invisible things",4,24],["G0846","of him",25,31],["G0575","from",32,36],["G2937","the creation",37,49],["G2889","of the world",50,62],["G2529","are clearly seen",63,79],["G3539","being understood",81,97],["G4161","by the things that are made",98,125],["G5037","even",127,131],["G0846","his",132,135],["G0126","eternal",136,143],["G1411","power",144,149],["G2532","and",150,153],["G2305","Godhead",154,161],["G1519","so",163,165],["G0846","that they",166,175],["G1511","are",176,179],["G0379","without excuse",180,194]]},"1:21":{"text":"Because that, when they knew God, they glorified him not as God, neither were thankful; but became vain in their imaginations, and their foolish heart was darkened.","words":[["G1360","Because",0,7],["G1097","that, when they knew",8,28],["G2316","God",29,32],["G1392","they glorified",34,48],["G3756","him not",49,56],["G5613","as",57,59],["G2316","God",60,63],["G2228","neither",65,72],["G2168","were thankful",73,86],["G0235","but",88,91],["G3154","became vain",92,103],["G1722","in",104,106],["G0846","their",107,112],["G1261","imaginations",113,125],["G2532","and",127,130],["G0846","their",131,136],["G0801","foolish",137,144],["G2588","heart",145,150],["G4654","was darkened",151,163]]},"1:22":{"text":"Professing themselves to be wise, they became fools,","words":[["G5335","Professing themselves",0,21],["G1511","to be",22,27],["G4680","wise",28,32],["G3471","they became fools",34,51]]},"1:23":{"text":"And changed the glory of the uncorruptible God into an image made like to corruptible man, and to birds, and fourfooted beasts, and creeping things.","words":[["G2532","And",0,3],["G0236","changed",4,11],["G1391","the glory",12,21],["G0862","of the uncorruptible",22,42],["G2316","God",43,46],["G1722","into",47,51],["G1504","an image",52,60],["G3667","made like",61,70],["G5349","to corruptible",71,85],["G0444","man",86,89],["G2532","and",91,94],["G4071","to birds",95,103],["G2532","and",105,108],["G5074","fourfooted beasts",109,126],["G2532","and",128,131],["G2062","creeping things",132,147]]},"1:24":{"text":"Wherefore God also gave them up to uncleanness through the lusts of their own hearts, to dishonour their own bodies between themselves:","words":[["G1352","Wherefore",0,9],["G2316","God",10,13],["G2532","also",14,18],["G3860","gave",19,23],["G0846","them",24,28],["G3860","up",29,31],["G1519","to",32,34],["G0167","uncleanness",35,46],["G1722","through",47,54],["G1939","the lusts",55,64],["G0846","of their own",65,77],["G2588","hearts",78,84],["G0818","to dishonour",86,98],["G0846","their own",99,108],["G4983","bodies",109,115],["G1722","between",116,123],["G1438","themselves",124,134]]},"1:25":{"text":"Who changed the truth of God into a lie, and worshipped and served the creature more than the Creator, who is blessed for ever. Amen.","words":[["G3748","Who",0,3],["G3337","changed",4,11],["G0225","the truth",12,21],["G2316","of God",22,28],["G1722","into",29,33],["G5579","a lie",34,39],["G2532","and",41,44],["G4573","worshipped",45,55],["G2532","and",56,59],["G3000","served",60,66],["G2937","the creature",67,79],["G3844","more than",80,89],["G2936","the Creator",90,101],["G3739","who",103,106],["G2076","is",107,109],["G2128","blessed",110,117],["G1519","for",118,121],["G0165","ever",122,126],["G0281","Amen",128,132]]},"1:26":{"text":"For this cause God gave them up unto vile affections: for even their women did change the natural use into that which is against nature:","words":[["G1223","For",0,3],["G5124","this",4,8],["G2316","cause God",9,18],["G3860","gave",19,23],["G0846","them",24,28],["G3860","up",29,31],["G1519","unto",32,36],["G0819","vile",37,41],["G3806","affections",42,52],["G1063","for",54,57],["G5037","even",58,62],["G0846","their",63,68],["G2338","women",69,74],["G3337","did change",75,85],["G5446","the natural",86,97],["G5540","use",98,101],["G1519","into",102,106],["G3844","that which is against",107,128],["G5449","nature",129,135]]},"1:27":{"text":"And likewise also the men, leaving the natural use of the woman, burned in their lust one toward another; men with men working that which is unseemly, and receiving in themselves that recompence of their error which was meet.","words":[["G5037","And",0,3],["G3668","likewise",4,12],["G2532","also",13,17],["G0730","the men",18,25],["G0863","leaving",27,34],["G5446","the natural",35,46],["G5540","use",47,50],["G2338","of the woman",51,63],["G1572","burned",65,71],["G1722","in",72,74],["G0846","their",75,80],["G3715","lust",81,85],["G1519","one toward another",86,104],["G0240","one toward another",86,104],["G0730","men",106,109],["G1722","with",110,114],["G0730","men",115,118],["G2716","working",119,126],["G0808","that which is unseemly",127,149],["G2532","and",151,154],["G0618","receiving",155,164],["G1722","in",165,167],["G1438","themselves",168,178],["G0489","that recompence",179,194],["G0846","of their",195,203],["G4106","error",204,209],["G3739","which",210,215],["G1163","was meet",216,224]]},"1:28":{"text":"And even as they did not like to retain God in their knowledge, God gave them over to a reprobate mind, to do those things which are not convenient;","words":[["G2532","And",0,3],["G2531","even as",4,11],["G1381","they did",12,20],["G3756","not",21,24],["G1381","like",25,29],["G2192","to retain",30,39],["G2316","God",40,43],["G1722","in",44,46],["G1922","their knowledge",47,62],["G2316","God",64,67],["G3860","gave",68,72],["G0846","them",73,77],["G3860","over",78,82],["G1519","to",83,85],["G0096","a reprobate",86,97],["G3563","mind",98,102],["G4160","to do",104,109],["G2520","those things which are",110,132],["G3361","not",133,136],["G2520","convenient",137,147]]},"1:29":{"text":"Being filled with all unrighteousness, fornication, wickedness, covetousness, maliciousness; full of envy, murder, debate, deceit, malignity; whisperers,","words":[["G4137","Being filled with",0,17],["G3956","all",18,21],["G0093","unrighteousness",22,37],["G4202","fornication",39,50],["G4189","wickedness",52,62],["G4124","covetousness",64,76],["G2549","maliciousness",78,91],["G3324","full",93,97],["G5355","of envy",98,105],["G5408","murder",107,113],["G2054","debate",115,121],["G1388","deceit",123,129],["G2550","malignity",131,140],["G5588","whisperers",142,152]]},"1:30":{"text":"Backbiters, haters of God, despiteful, proud, boasters, inventors of evil things, disobedient to parents,","words":[["G2637","Backbiters",0,10],["G2319","haters of God",12,25],["G5197","despiteful",27,37],["G5244","proud",39,44],["G0213","boasters",46,54],["G2182","inventors",56,65],["G2556","of evil things",66,80],["G0545","disobedient",82,93],["G1118","to parents",94,104]]},"1:31":{"text":"Without understanding, covenantbreakers, without natural affection, implacable, unmerciful:","words":[["G0801","Without understanding",0,21],["G0802","covenantbreakers",23,39],["G0794","without natural affection",41,66],["G0786","implacable",68,78],["G0415","unmerciful",80,90]]},"1:32":{"text":"Who knowing the judgment of God, that they which commit such things are worthy of death, not only do the same, but have pleasure in them that do them.","words":[["G3748","Who",0,3],["G1921","knowing",4,11],["G1345","the judgment",12,24],["G2316","of God",25,31],["G3754","that",33,37],["G4238","they which commit",38,55],["G5108","such things",56,67],["G1526","are",68,71],["G0514","worthy",72,78],["G2288","of death",79,87],["G3756","not",89,92],["G3440","only",93,97],["G4160","do",98,100],["G0846","the same",101,109],["G0235","but",111,114],["G2532","but",111,114],["G4909","have pleasure",115,128],["G4238","in them that do",129,144]]},"2:1":{"text":"Therefore thou art inexcusable, O man, whosoever thou art that judgest: for wherein thou judgest another, thou condemnest thyself; for thou that judgest doest the same things.","words":[["G1352","Therefore",0,9],["G1488","thou art",10,18],["G0379","inexcusable",19,30],["G5599","O",32,33],["G0444","man",34,37],["G3956","whosoever",39,48],["G2919","thou art that judgest",49,70],["G1063","for",72,75],["G1722","wherein",76,83],["G3739","wherein",76,83],["G2919","thou judgest",84,96],["G2087","another",97,104],["G2632","thou condemnest",106,121],["G4572","thyself",122,129],["G1063","for",131,134],["G2919","thou that judgest",135,152],["G4238","doest",153,158],["G0846","the same things",159,174]]},"2:2":{"text":"But we are sure that the judgment of God is according to truth against them which commit such things.","words":[["G1161","But",0,3],["G1492","we are sure",4,15],["G3754","that",16,20],["G2917","the judgment",21,33],["G2316","of God",34,40],["G2076","is",41,43],["G2596","according",44,53],["G0225","to truth",54,62],["G1909","against",63,70],["G4238","them which commit",71,88],["G5108","such things",89,100]]},"2:3":{"text":"And thinkest thou this, O man, that judgest them which do such things, and doest the same, that thou shalt escape the judgment of God?","words":[["G1161","And",0,3],["G3049","thinkest thou",4,17],["G5124","this",18,22],["G5599","O",24,25],["G0444","man",26,29],["G2919","that judgest",31,43],["G4238","them which do",44,57],["G5108","such things",58,69],["G2532","and",71,74],["G4160","doest",75,80],["G0846","the same",81,89],["G3754","that",91,95],["G4771","thou",96,100],["G1628","shalt escape",101,113],["G2917","the judgment",114,126],["G2316","of God",127,133]]},"2:4":{"text":"Or despisest thou the riches of his goodness and forbearance and longsuffering; not knowing that the goodness of God leadeth thee to repentance?","words":[["G2228","Or",0,2],["G2706","despisest thou",3,17],["G4149","the riches",18,28],["G0846","of his",29,35],["G5544","goodness",36,44],["G2532","and",45,48],["G0463","forbearance",49,60],["G2532","and",61,64],["G3115","longsuffering",65,78],["G0050","not knowing",80,91],["G3754","that",92,96],["G5543","the goodness",97,109],["G2316","of God",110,116],["G0071","leadeth",117,124],["G4571","thee",125,129],["G1519","to",130,132],["G3341","repentance",133,143]]},"2:5":{"text":"But after thy hardness and impenitent heart treasurest up unto thyself wrath against the day of wrath and revelation of the righteous judgment of God;","words":[["G1161","But",0,3],["G2596","after",4,9],["G4675","thy",10,13],["G4643","hardness",14,22],["G2532","and",23,26],["G0279","impenitent",27,37],["G2588","heart",38,43],["G2343","treasurest up",44,57],["G4572","unto thyself",58,70],["G3709","wrath",71,76],["G1722","against",77,84],["G2250","the day",85,92],["G3709","of wrath",93,101],["G2532","and",102,105],["G0602","revelation",106,116],["G1341","of the righteous judgment",117,142],["G2316","of God",143,149]]},"2:6":{"text":"Who will render to every man according to his deeds:","words":[["G3739","Who",0,3],["G0591","will render",4,15],["G1538","to every man",16,28],["G2596","according",29,38],["G0846","to his",39,45],["G2041","deeds",46,51]]},"2:7":{"text":"To them who by patient continuance in well doing seek for glory and honour and immortality, eternal life:","words":[["G3303","To them who by",0,14],["G2596","To them who by",0,14],["G5281","patient continuance",15,34],["G0018","in well",35,42],["G2041","doing",43,48],["G2212","seek",49,53],["G1391","for glory",54,63],["G2532","and",64,67],["G5092","honour",68,74],["G2532","and",75,78],["G0861","immortality",79,90],["G0166","eternal",92,99],["G2222","life",100,104]]},"2:8":{"text":"But unto them that are contentious, and do not obey the truth, but obey unrighteousness, indignation and wrath,","words":[["G1161","But",0,3],["G1537","unto them that are contentious",4,34],["G2052","unto them that are contentious",4,34],["G2532","and",36,39],["G0544","do not obey",40,51],["G3303","do not obey",40,51],["G0225","the truth",52,61],["G1161","but",63,66],["G3982","obey",67,71],["G0093","unrighteousness",72,87],["G2372","indignation",89,100],["G2532","and",101,104],["G3709","wrath",105,110]]},"2:9":{"text":"Tribulation and anguish, upon every soul of man that doeth evil, of the Jew first, and also of the Gentile;","words":[["G2347","Tribulation",0,11],["G2532","and",12,15],["G4730","anguish",16,23],["G1909","upon",25,29],["G3956","every",30,35],["G5590","soul",36,40],["G0444","of man",41,47],["G2716","that doeth",48,58],["G2556","evil",59,63],["G2453","of the Jew",65,75],["G4412","first",76,81],["G5037","and",83,86],["G2532","also",87,91],["G1672","of the Gentile",92,106]]},"2:10":{"text":"But glory, honour, and peace, to every man that worketh good, to the Jew first, and also to the Gentile:","words":[["G1161","But",0,3],["G2532","But",0,3],["G1391","glory",4,9],["G5092","honour",11,17],["G2532","and",19,22],["G1515","peace",23,28],["G3956","to every man",30,42],["G2038","that worketh",43,55],["G0018","good",56,60],["G2453","to the Jew",62,72],["G4412","first",73,78],["G5037","and",80,83],["G2532","also",84,88],["G1672","to the Gentile",89,103]]},"2:11":{"text":"For there is no respect of persons with God.","words":[["G1063","For",0,3],["G2076","there is",4,12],["G3756","no",13,15],["G4382","respect of persons",16,34],["G3844","with",35,39],["G2316","God",40,43]]},"2:12":{"text":"For as many as have sinned without law shall also perish without law: and as many as have sinned in the law shall be judged by the law;","words":[["G1063","For",0,3],["G3745","as many as",4,14],["G0264","have sinned",15,26],["G0460","without law",27,38],["G0622","shall",39,44],["G2532","also",45,49],["G0622","perish",50,56],["G0460","without law",57,68],["G2532","and",70,73],["G3745","as many as",74,84],["G0264","have sinned",85,96],["G1722","in",97,99],["G3551","the law",100,107],["G2919","shall be judged",108,123],["G1223","by",124,126],["G3551","the law",127,134]]},"2:13":{"text":"(For not the hearers of the law are just before God, but the doers of the law shall be justified.","words":[["G1063","(For",0,4],["G3756","not",5,8],["G0202","the hearers",9,20],["G3551","of the law",21,31],["G1342","are just",32,40],["G3844","before",41,47],["G2316","God",48,51],["G0235","but",53,56],["G4163","the doers",57,66],["G3551","of the law",67,77],["G1344","shall be justified",78,96]]},"2:14":{"text":"For when the Gentiles, which have not the law, do by nature the things contained in the law, these, having not the law, are a law unto themselves:","words":[["G1063","For",0,3],["G3752","when",4,8],["G1484","the Gentiles",9,21],["G3588","which",23,28],["G2192","have",29,33],["G3361","not",34,37],["G3551","the law",38,45],["G4160","do",47,49],["G5449","by nature",50,59],["G3588","the things",60,70],["G3551","contained in the law",71,91],["G3778","these",93,98],["G2192","having",100,106],["G3361","not",107,110],["G3551","the law",111,118],["G1526","are",120,123],["G3551","a law",124,129],["G1438","unto themselves",130,145]]},"2:15":{"text":"Which shew the work of the law written in their hearts, their conscience also bearing witness, and their thoughts the mean while accusing or else excusing one another;)","words":[["G3748","Which",0,5],["G1731","shew",6,10],["G2041","the work",11,19],["G3551","of the law",20,30],["G1123","written",31,38],["G1722","in",39,41],["G0846","their",42,47],["G2588","hearts",48,54],["G0846","their",56,61],["G4893","conscience",62,72],["G4828","also bearing witness",73,93],["G2532","and",95,98],["G3053","their thoughts",99,113],["G2723","the mean while accusing",114,137],["G2228","or",138,140],["G2532","else",141,145],["G0626","excusing",146,154],["G3342","one another",155,166],["G0240","one another",155,166]]},"2:16":{"text":"In the day when God shall judge the secrets of men by Jesus Christ according to my gospel.","words":[["G1722","In",0,2],["G2250","the day",3,10],["G3753","when",11,15],["G2316","God",16,19],["G2919","shall judge",20,31],["G2927","the secrets",32,43],["G0444","of men",44,50],["G1223","by",51,53],["G2424","Jesus",54,59],["G5547","Christ",60,66],["G2596","according",67,76],["G3450","to my",77,82],["G2098","gospel",83,89]]},"2:17":{"text":"Behold, thou art called a Jew, and restest in the law, and makest thy boast of God,","words":[["G2396","Behold",0,6],["G4771","thou",8,12],["G2028","art called",13,23],["G2453","a Jew",24,29],["G2532","and",31,34],["G1879","restest",35,42],["G3551","in the law",43,53],["G2532","and",55,58],["G2744","makest thy boast",59,75],["G1722","of",76,78],["G2316","God",79,82]]},"2:18":{"text":"And knowest his will, and approvest the things that are more excellent, being instructed out of the law;","words":[["G2532","And",0,3],["G1097","knowest",4,11],["G2307","his will",12,20],["G2532","and",22,25],["G1381","approvest",26,35],["G1308","the things that are more excellent",36,70],["G2727","being instructed",72,88],["G1537","out of",89,95],["G3551","the law",96,103]]},"2:19":{"text":"And art confident that thou thyself art a guide of the blind, a light of them which are in darkness,","words":[["G5037","And",0,3],["G3982","art confident",4,17],["G4572","that thou thyself",18,35],["G1511","art",36,39],["G3595","a guide",40,47],["G5185","of the blind",48,60],["G5457","a light",62,69],["G1722","of them which are in",70,90],["G4655","darkness",91,99]]},"2:20":{"text":"An instructor of the foolish, a teacher of babes, which hast the form of knowledge and of the truth in the law.","words":[["G3810","An instructor",0,13],["G0878","of the foolish",14,28],["G1320","a teacher",30,39],["G3516","of babes",40,48],["G2192","which hast",50,60],["G3446","the form",61,69],["G1108","of knowledge",70,82],["G2532","and",83,86],["G0225","of the truth",87,99],["G1722","in",100,102],["G3551","the law",103,110]]},"2:21":{"text":"Thou therefore which teachest another, teachest thou not thyself? thou that preachest a man should not steal, dost thou steal?","words":[["G3767","Thou therefore",0,14],["G3588","which",15,20],["G1321","teachest",21,29],["G2087","another",30,37],["G1321","teachest thou",39,52],["G3756","not",53,56],["G4572","thyself",57,64],["G2784","thou that preachest",66,85],["G2813","a man should",86,98],["G3361","not",99,102],["G2813","steal",103,108],["G2813","dost thou steal",110,125]]},"2:22":{"text":"Thou that sayest a man should not commit adultery, dost thou commit adultery? thou that abhorrest idols, dost thou commit sacrilege?","words":[["G3004","Thou that sayest",0,16],["G3431","a man should",17,29],["G3361","not",30,33],["G3431","commit adultery",34,49],["G3431","dost thou commit adultery",51,76],["G0948","thou that abhorrest",78,97],["G1497","idols",98,103],["G2416","dost thou commit sacrilege",105,131]]},"2:23":{"text":"Thou that makest thy boast of the law, through breaking the law dishonourest thou God?","words":[["G3739","Thou",0,4],["G2744","that makest thy boast",5,26],["G1722","of",27,29],["G3551","the law",30,37],["G1223","through",39,46],["G3847","breaking",47,55],["G3551","the law",56,63],["G0818","dishonourest thou",64,81],["G2316","God",82,85]]},"2:24":{"text":"For the name of God is blasphemed among the Gentiles through you, as it is written.","words":[["G1063","For",0,3],["G3686","the name",4,12],["G2316","of God",13,19],["G0987","is blasphemed",20,33],["G1722","among",34,39],["G1484","the Gentiles",40,52],["G1223","through",53,60],["G5209","you",61,64],["G2531","as",66,68],["G1125","it is written",69,82]]},"2:25":{"text":"For circumcision verily profiteth, if thou keep the law: but if thou be a breaker of the law, thy circumcision is made uncircumcision.","words":[["G1063","For",0,3],["G4061","circumcision",4,16],["G3303","verily",17,23],["G5623","profiteth",24,33],["G1437","if",35,37],["G4238","thou keep",38,47],["G3551","the law",48,55],["G1161","but",57,60],["G1437","if",61,63],["G5600","thou be",64,71],["G3848","a breaker",72,81],["G3551","of the law",82,92],["G4675","thy",94,97],["G4061","circumcision",98,110],["G1096","is made",111,118],["G0203","uncircumcision",119,133]]},"2:26":{"text":"Therefore if the uncircumcision keep the righteousness of the law, shall not his uncircumcision be counted for circumcision?","words":[["G3767","Therefore",0,9],["G1437","if",10,12],["G0203","the uncircumcision",13,31],["G5442","keep",32,36],["G1345","the righteousness",37,54],["G3551","of the law",55,65],["G3049","shall",67,72],["G3780","not",73,76],["G0846","his",77,80],["G0203","uncircumcision",81,95],["G3049","be counted",96,106],["G1519","for",107,110],["G4061","circumcision",111,123]]},"2:27":{"text":"And shall not uncircumcision which is by nature, if it fulfil the law, judge thee, who by the letter and circumcision dost transgress the law?","words":[["G2532","And",0,3],["G2919","shall not",4,13],["G0203","uncircumcision",14,28],["G1537","which is by",29,40],["G5449","nature",41,47],["G5055","if it fulfil",49,61],["G3551","the law",62,69],["G2919","judge",71,76],["G4571","thee",77,81],["G1223","who by",83,89],["G1121","the letter",90,100],["G2532","and",101,104],["G4061","circumcision",105,117],["G3848","dost transgress",118,133],["G3551","the law",134,141]]},"2:28":{"text":"For he is not a Jew, which is one outwardly; neither is that circumcision, which is outward in the flesh:","words":[["G1063","For",0,3],["G2076","he is",4,9],["G3756","not",10,13],["G2453","a Jew",14,19],["G1722","which is one outwardly",21,43],["G5318","which is one outwardly",21,43],["G3761","neither",45,52],["G4061","is that circumcision",53,73],["G1722","which is outward",75,91],["G5318","which is outward",75,91],["G1722","in",92,94],["G4561","the flesh",95,104]]},"2:29":{"text":"But he is a Jew, which is one inwardly; and circumcision is that of the heart, in the spirit, and not in the letter; whose praise is not of men, but of God.","words":[["G0235","But",0,3],["G2453","he is a Jew",4,15],["G1722","which is one inwardly",17,38],["G2927","which is one inwardly",17,38],["G2532","and",40,43],["G4061","circumcision",44,56],["G2588","is that of the heart",57,77],["G1722","in",79,81],["G4151","the spirit",82,92],["G3756","and not",94,101],["G1121","in the letter",102,115],["G3739","whose",117,122],["G1868","praise",123,129],["G3756","is not",130,136],["G1537","of",137,139],["G0444","men",140,143],["G0235","but",145,148],["G1537","of",149,151],["G2316","God",152,155]]},"3:1":{"text":"What advantage then hath the Jew? or what profit is there of circumcision?","words":[["G5101","What",0,4],["G4053","advantage",5,14],["G3767","then",15,19],["G2453","hath the Jew",20,32],["G2228","or",34,36],["G5101","what",37,41],["G5622","profit",42,48],["G4061","is there of circumcision",49,73]]},"3:2":{"text":"Much every way: chiefly, because that unto them were committed the oracles of God.","words":[["G4183","Much",0,4],["G2596","every",5,10],["G3956","every",5,10],["G5158","way",11,14],["G4412","chiefly",16,23],["G3303","because",25,32],["G1063","because",25,32],["G3754","that",33,37],["G4100","unto them were committed",38,62],["G3051","the oracles",63,74],["G2316","of God",75,81]]},"3:3":{"text":"For what if some did not believe? shall their unbelief make the faith of God without effect?","words":[["G1063","For",0,3],["G5101","what",4,8],["G1487","if",9,11],["G5100","some",12,16],["G0569","did not believe",17,32],["G3361","",-1,-1],["G2673","shall",34,39],["G0846","their",40,45],["G0570","unbelief",46,54],["G2673","make",55,59],["G4102","the faith",60,69],["G2316","of God",70,76],["G2673","without effect",77,91]]},"3:4":{"text":"God forbid: yea, let God be true, but every man a liar; as it is written, That thou mightest be justified in thy sayings, and mightest overcome when thou art judged.","words":[["G3361","God forbid",0,10],["G1096","God forbid",0,10],["G1161","yea",12,15],["G1096","let",17,20],["G2316","God",21,24],["G1096","be",25,27],["G0227","true",28,32],["G1161","but",34,37],["G3956","every",38,43],["G0444","man",44,47],["G5583","a liar",48,54],["G2531","as",56,58],["G1125","it is written",59,72],["G3704","That",74,78],["G0302","thou mightest",79,92],["G1344","be justified",93,105],["G1722","in",106,108],["G4675","thy",109,112],["G3056","sayings",113,120],["G2532","and",122,125],["G3528","mightest overcome",126,143],["G1722","when",144,148],["G4571","thou",149,153],["G2919","art judged",154,164]]},"3:5":{"text":"But if our unrighteousness commend the righteousness of God, what shall we say? Is God unrighteous who taketh vengeance? (I speak as a man)","words":[["G1161","But",0,3],["G1487","if",4,6],["G2257","our",7,10],["G0093","unrighteousness",11,26],["G4921","commend",27,34],["G1343","the righteousness",35,52],["G2316","of God",53,59],["G5101","what",61,65],["G2046","shall we say",66,78],["G3361","",-1,-1],["G2316","Is God",80,86],["G0094","unrighteous",87,98],["G2018","who taketh",99,109],["G3709","vengeance",110,119],["G3004","(I speak",121,129],["G2596","as",130,132],["G0444","a man",133,138]]},"3:6":{"text":"God forbid: for then how shall God judge the world?","words":[["G3361","God forbid",0,10],["G1096","God forbid",0,10],["G1893","for then",12,20],["G4459","how",21,24],["G2919","shall",25,30],["G2316","God",31,34],["G2919","judge",35,40],["G2889","the world",41,50]]},"3:7":{"text":"For if the truth of God hath more abounded through my lie unto his glory; why yet am I also judged as a sinner?","words":[["G1063","For",0,3],["G1487","if",4,6],["G0225","the truth",7,16],["G2316","of God",17,23],["G4052","hath more abounded",24,42],["G1722","through",43,50],["G1699","my",51,53],["G5582","lie",54,57],["G1519","unto",58,62],["G0846","his",63,66],["G1391","glory",67,72],["G5101","why",74,77],["G2089","yet",78,81],["G2919","am",82,84],["G2504","I also",85,91],["G2919","judged",92,98],["G5613","as",99,101],["G0268","a sinner",102,110]]},"3:8":{"text":"And not rather, (as we be slanderously reported, and as some affirm that we say,) Let us do evil, that good may come? whose damnation is just.","words":[["G2532","And",0,3],["G3361","not",4,7],["G2531","rather, (as",8,19],["G0987","we be slanderously reported",20,47],["G2532","and",49,52],["G2531","as",53,55],["G5100","some",56,60],["G5346","affirm",61,67],["G2248","that we",68,75],["G3004","say",76,79],["G3754",")",80,81],["G4160","Let us do",82,91],["G2556","evil",92,96],["G2443","that",98,102],["G0018","good",103,107],["G2064","may come",108,116],["G3739","whose",118,123],["G2917","damnation",124,133],["G2076","is",134,136],["G1738","just",137,141]]},"3:9":{"text":"What then? are we better than they? No, in no wise: for we have before proved both Jews and Gentiles, that they are all under sin;","words":[["G5101","What",0,4],["G3767","then",5,9],["G4284","are we better",11,24],["G3756","than they? No",25,38],["G3843","in no wise",40,50],["G1063","for",52,55],["G4256","we have before proved",56,77],["G5037","both",78,82],["G2453","Jews",83,87],["G2532","and",88,91],["G1672","Gentiles",92,100],["G1511","that they are",102,115],["G3956","all",116,119],["G5259","under",120,125],["G0266","sin",126,129]]},"3:10":{"text":"As it is written, There is none righteous, no, not one:","words":[["G2531","As",0,2],["G1125","it is written",3,16],["G3754","",-1,-1],["G2076","There is",18,26],["G3756","none",27,31],["G1342","righteous",32,41],["G3761","no, not",43,50],["G1520","one",51,54]]},"3:11":{"text":"There is none that understandeth, there is none that seeketh after God.","words":[["G2076","There is",0,8],["G3756","none",9,13],["G4920","that understandeth",14,32],["G2076","there is",34,42],["G3756","none",43,47],["G1567","that seeketh after",48,66],["G2316","God",67,70]]},"3:12":{"text":"They are all gone out of the way, they are together become unprofitable; there is none that doeth good, no, not one.","words":[["G1578","They are",0,8],["G3956","all",9,12],["G1578","gone out of the way",13,32],["G0889","they are",34,42],["G0260","together",43,51],["G0889","become unprofitable",52,71],["G2076","there is",73,81],["G3756","none",82,86],["G4160","that doeth",87,97],["G5544","good",98,102],["G3756","no, not",104,111],["G2076","one",112,115],["G2193","one",112,115],["G1520","one",112,115]]},"3:13":{"text":"Their throat is an open sepulchre; with their tongues they have used deceit; the poison of asps is under their lips:","words":[["G0846","Their",0,5],["G2995","throat",6,12],["G0455","is an open",13,23],["G5028","sepulchre",24,33],["G0846","with their",35,45],["G1100","tongues",46,53],["G1387","they have used deceit",54,75],["G2447","the poison",77,87],["G0785","of asps",88,95],["G5259","is under",96,104],["G0846","their",105,110],["G5491","lips",111,115]]},"3:14":{"text":"Whose mouth is full of cursing and bitterness:","words":[["G3739","Whose",0,5],["G4750","mouth",6,11],["G1073","is full",12,19],["G0685","of cursing",20,30],["G2532","and",31,34],["G4088","bitterness",35,45]]},"3:15":{"text":"Their feet are swift to shed blood:","words":[["G0846","Their",0,5],["G4228","feet",6,10],["G3691","are swift",11,20],["G1632","to shed",21,28],["G0129","blood",29,34]]},"3:16":{"text":"Destruction and misery are in their ways:","words":[["G4938","Destruction",0,11],["G2532","and",12,15],["G5004","misery",16,22],["G1722","are in",23,29],["G0846","their",30,35],["G3598","ways",36,40]]},"3:17":{"text":"And the way of peace have they not known:","words":[["G2532","And",0,3],["G3598","the way",4,11],["G1515","of peace",12,20],["G1097","have",21,25],["G3756","they not",26,34],["G1097","known",35,40]]},"3:18":{"text":"There is no fear of God before their eyes.","words":[["G2076","There is",0,8],["G3756","no",9,11],["G5401","fear",12,16],["G2316","of God",17,23],["G0561","before",24,30],["G0846","their",31,36],["G3788","eyes",37,41]]},"3:19":{"text":"Now we know that what things soever the law saith, it saith to them who are under the law: that every mouth may be stopped, and all the world may become guilty before God.","words":[["G1161","Now",0,3],["G1492","we know",4,11],["G3754","that",12,16],["G3745","what things soever",17,35],["G3551","the law",36,43],["G3004","saith",44,49],["G2980","it saith",51,59],["G1722","to them who are under",60,81],["G3551","the law",82,89],["G2443","that",91,95],["G3956","every",96,101],["G4750","mouth",102,107],["G5420","may be stopped",108,122],["G2532","and",124,127],["G3956","all",128,131],["G2889","the world",132,141],["G1096","may become",142,152],["G5267","guilty",153,159],["G2316","before God",160,170]]},"3:20":{"text":"Therefore by the deeds of the law there shall no flesh be justified in his sight: for by the law is the knowledge of sin.","words":[["G1360","Therefore",0,9],["G1537","by",10,12],["G2041","the deeds",13,22],["G3551","of the law",23,33],["G1344","there shall",34,45],["G3956","no",46,48],["G3756","no",46,48],["G4561","flesh",49,54],["G1344","be justified",55,67],["G0846","in his",68,74],["G1799","sight",75,80],["G1063","for",82,85],["G1223","by",86,88],["G3551","the law",89,96],["G1922","is the knowledge",97,113],["G0266","of sin",114,120]]},"3:21":{"text":"But now the righteousness of God without the law is manifested, being witnessed by the law and the prophets;","words":[["G1161","But",0,3],["G3570","now",4,7],["G1343","the righteousness",8,25],["G2316","of God",26,32],["G5565","without",33,40],["G3551","the law",41,48],["G5319","is manifested",49,62],["G3140","being witnessed",64,79],["G5259","by",80,82],["G3551","the law",83,90],["G2532","and",91,94],["G4396","the prophets",95,107]]},"3:22":{"text":"Even the righteousness of God which is by faith of Jesus Christ unto all and upon all them that believe: for there is no difference:","words":[["G1161","Even",0,4],["G1343","the righteousness",5,22],["G2316","of God",23,29],["G1223","which is by",30,41],["G4102","faith",42,47],["G2424","of Jesus",48,56],["G5547","Christ",57,63],["G1519","unto",64,68],["G3956","all",69,72],["G2532","and",73,76],["G1909","upon",77,81],["G3956","all",82,85],["G4100","them that believe",86,103],["G1063","for",105,108],["G2076","there is",109,117],["G3756","no",118,120],["G1293","difference",121,131]]},"3:23":{"text":"For all have sinned, and come short of the glory of God;","words":[["G1063","For",0,3],["G3956","all",4,7],["G0264","have sinned",8,19],["G2532","and",21,24],["G5302","come short",25,35],["G1391","of the glory",36,48],["G2316","of God",49,55]]},"3:24":{"text":"Being justified freely by his grace through the redemption that is in Christ Jesus:","words":[["G1344","Being justified",0,15],["G1432","freely",16,22],["G0846","by his",23,29],["G5485","grace",30,35],["G1223","through",36,43],["G0629","the redemption",44,58],["G1722","that is in",59,69],["G5547","Christ",70,76],["G2424","Jesus",77,82]]},"3:25":{"text":"Whom God hath set forth to be a propitiation through faith in his blood, to declare his righteousness for the remission of sins that are past, through the forbearance of God;","words":[["G3739","Whom",0,4],["G2316","God",5,8],["G4388","hath set forth",9,23],["G2435","to be a propitiation",24,44],["G1223","through",45,52],["G4102","faith",53,58],["G1722","in",59,61],["G0846","his",62,65],["G0129","blood",66,71],["G1519","to",73,75],["G1732","declare",76,83],["G0846","his",84,87],["G1343","righteousness",88,101],["G1223","for",102,105],["G3929","the remission",106,119],["G0265","of sins",120,127],["G4266","that are past",128,141],["G1722","through",143,150],["G0463","the forbearance",151,166],["G2316","of God",167,173]]},"3:26":{"text":"To declare, I say, at this time his righteousness: that he might be just, and the justifier of him which believeth in Jesus.","words":[["G4314","To",0,2],["G1732","declare",3,10],["G1722","I say, at",12,21],["G3568","this",22,26],["G2540","time",27,31],["G0846","his",32,35],["G1343","righteousness",36,49],["G1519","that",51,55],["G1511","he might be",56,67],["G1342","just",68,72],["G2532","and",74,77],["G1344","the justifier",78,91],["G0846","of him",92,98],["G4102","which believeth",99,114],["G1537","in",115,117],["G2424","Jesus",118,123]]},"3:27":{"text":"Where is boasting then? It is excluded. By what law? of works? Nay: but by the law of faith.","words":[["G4226","Where",0,5],["G2746","is boasting",6,17],["G3767","then",18,22],["G1576","It is excluded",24,38],["G1223","By",40,42],["G4169","what",43,47],["G3551","law",48,51],["G2041","of works",53,61],["G3780","Nay",63,66],["G0235","but",68,71],["G1223","by",72,74],["G3551","the law",75,82],["G4102","of faith",83,91]]},"3:28":{"text":"Therefore we conclude that a man is justified by faith without the deeds of the law.","words":[["G3767","Therefore",0,9],["G3049","we conclude",10,21],["G0444","that a man",22,32],["G1344","is justified",33,45],["G4102","by faith",46,54],["G5565","without",55,62],["G2041","the deeds",63,72],["G3551","of the law",73,83]]},"3:29":{"text":"Is he the God of the Jews only? is he not also of the Gentiles? Yes, of the Gentiles also:","words":[["G2228","Is he",0,5],["G2316","the God",6,13],["G2453","of the Jews",14,25],["G3440","only",26,30],["G3780","is he not",32,41],["G1161","also",42,46],["G2532","also",42,46],["G1484","of the Gentiles",47,62],["G3483","Yes",64,67],["G1484","of the Gentiles",69,84],["G2532","also",85,89]]},"3:30":{"text":"Seeing it is one God, which shall justify the circumcision by faith, and uncircumcision through faith.","words":[["G1897","Seeing",0,6],["G1520","it is one",7,16],["G2316","God",17,20],["G3739","which",22,27],["G1344","shall justify",28,41],["G4061","the circumcision",42,58],["G1537","by",59,61],["G4102","faith",62,67],["G2532","and",69,72],["G0203","uncircumcision",73,87],["G1223","through",88,95],["G4102","faith",96,101]]},"3:31":{"text":"Do we then make void the law through faith? God forbid: yea, we establish the law.","words":[["G2673","Do we",0,5],["G3767","then",6,10],["G2673","make void",11,20],["G3551","the law",21,28],["G1223","through",29,36],["G4102","faith",37,42],["G3361","God forbid",44,54],["G1096","God forbid",44,54],["G0235","yea",56,59],["G2476","we establish",61,73],["G3551","the law",74,81]]},"4:1":{"text":"What shall we say then that Abraham our father, as pertaining to the flesh, hath found?","words":[["G5101","What",0,4],["G2046","shall we say",5,17],["G3767","then",18,22],["G0011","that Abraham",23,35],["G2257","our",36,39],["G3962","father",40,46],["G2596","as pertaining",48,61],["G4561","to the flesh",62,74],["G2147","hath found",76,86]]},"4:2":{"text":"For if Abraham were justified by works, he hath whereof to glory; but not before God.","words":[["G1063","For",0,3],["G1487","if",4,6],["G0011","Abraham",7,14],["G1344","were justified",15,29],["G1537","by",30,32],["G2041","works",33,38],["G2192","he hath",40,47],["G2745","whereof to glory",48,64],["G0235","but",66,69],["G3756","not",70,73],["G4314","before",74,80],["G2316","God",81,84]]},"4:3":{"text":"For what saith the scripture? Abraham believed God, and it was counted unto him for righteousness.","words":[["G1063","For",0,3],["G5101","what",4,8],["G3004","saith",9,14],["G1124","the scripture",15,28],["G1161","",-1,-1],["G0011","Abraham",30,37],["G4100","believed",38,46],["G2316","God",47,50],["G2532","and",52,55],["G3049","it was counted",56,70],["G0846","unto him",71,79],["G1519","for",80,83],["G1343","righteousness",84,97]]},"4:4":{"text":"Now to him that worketh is the reward not reckoned of grace, but of debt.","words":[["G1161","Now",0,3],["G2038","to him that worketh",4,23],["G3049","is",24,26],["G3408","the reward",27,37],["G3756","not",38,41],["G3049","reckoned",42,50],["G2596","of",51,53],["G5485","grace",54,59],["G0235","but",61,64],["G2596","of",65,67],["G3783","debt",68,72]]},"4:5":{"text":"But to him that worketh not, but believeth on him that justifieth the ungodly, his faith is counted for righteousness.","words":[["G1161","But",0,3],["G2038","to him that worketh",4,23],["G3361","not",24,27],["G1161","but",29,32],["G4100","believeth",33,42],["G1909","on",43,45],["G1344","him that justifieth",46,65],["G0765","the ungodly",66,77],["G0846","his",79,82],["G4102","faith",83,88],["G3049","is counted",89,99],["G1519","for",100,103],["G1343","righteousness",104,117]]},"4:6":{"text":"Even as David also describeth the blessedness of the man, unto whom God imputeth righteousness without works,","words":[["G2509","Even as",0,7],["G1138","David",8,13],["G2532","also",14,18],["G3004","describeth",19,29],["G3108","the blessedness",30,45],["G0444","of the man",46,56],["G3739","unto whom",58,67],["G2316","God",68,71],["G3049","imputeth",72,80],["G1343","righteousness",81,94],["G5565","without",95,102],["G2041","works",103,108]]},"4:7":{"text":"Saying, Blessed are they whose iniquities are forgiven, and whose sins are covered.","words":[["G3107","Saying, Blessed",0,15],["G3739","are they whose",16,30],["G0458","iniquities",31,41],["G0863","are forgiven",42,54],["G2532","and",56,59],["G3739","whose",60,65],["G0266","sins",66,70],["G1943","are covered",71,82]]},"4:8":{"text":"Blessed is the man to whom the Lord will not impute sin.","words":[["G3107","Blessed",0,7],["G0435","is the man",8,18],["G3739","to whom",19,26],["G2962","the Lord",27,35],["G3049","will",36,40],["G3364","not",41,44],["G3049","impute",45,51],["G0266","sin",52,55]]},"4:9":{"text":"Cometh this blessedness then upon the circumcision only, or upon the uncircumcision also? for we say that faith was reckoned to Abraham for righteousness.","words":[["G3778","Cometh this",0,11],["G3108","blessedness",12,23],["G3767","then",24,28],["G1909","upon",29,33],["G4061","the circumcision",34,50],["G2228","only, or",51,59],["G1909","upon",60,64],["G0203","the uncircumcision",65,83],["G2532","also",84,88],["G1063","for",90,93],["G3004","we say",94,100],["G3754","that",101,105],["G4102","faith",106,111],["G3049","was reckoned",112,124],["G0011","to Abraham",125,135],["G1519","for",136,139],["G1343","righteousness",140,153]]},"4:10":{"text":"How was it then reckoned? when he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision.","words":[["G4459","How",0,3],["G3049","was it",4,10],["G3767","then",11,15],["G3049","reckoned",16,24],["G5607","when he was",26,37],["G1722","in",38,40],["G4061","circumcision",41,53],["G2228","or",55,57],["G1722","in",58,60],["G0203","uncircumcision",61,75],["G3756","Not",77,80],["G1722","in",81,83],["G4061","circumcision",84,96],["G0235","but",98,101],["G1722","in",102,104],["G0203","uncircumcision",105,119]]},"4:11":{"text":"And he received the sign of circumcision, a seal of the righteousness of the faith which he had yet being uncircumcised: that he might be the father of all them that believe, though they be not circumcised; that righteousness might be imputed unto them also:","words":[["G2532","And",0,3],["G2983","he received",4,15],["G4592","the sign",16,24],["G4061","of circumcision",25,40],["G4973","a seal",42,48],["G1343","of the righteousness",49,69],["G4102","of the faith",70,82],["G3588","which",83,88],["G1722","he had yet being",89,105],["G0203","uncircumcised",106,119],["G1519","that",121,125],["G0846","he",126,128],["G1511","might be",129,137],["G3962","the father",138,148],["G3956","of all",149,155],["G4100","them that believe",156,173],["G1223","though",175,181],["G0203","they be not circumcised",182,205],["G1519","that",207,211],["G1343","righteousness",212,225],["G3049","might be imputed",226,242],["G0846","unto them",243,252],["G2532","also",253,257]]},"4:12":{"text":"And the father of circumcision to them who are not of the circumcision only, but who also walk in the steps of that faith of our father Abraham, which he had being yet uncircumcised.","words":[["G2532","And",0,3],["G3962","the father",4,14],["G4061","of circumcision",15,30],["G3756","to them who are not",31,50],["G1537","of",51,53],["G4061","the circumcision",54,70],["G3440","only",71,75],["G0235","but",77,80],["G2532","who also",81,89],["G4748","walk",90,94],["G2487","in the steps",95,107],["G4102","of that faith",108,121],["G2257","of our",122,128],["G3962","father",129,135],["G0011","Abraham",136,143],["G1722","which he had being",145,163],["G0203","yet uncircumcised",164,181]]},"4:13":{"text":"For the promise, that he should be the heir of the world, was not to Abraham, or to his seed, through the law, but through the righteousness of faith.","words":[["G1063","For",0,3],["G1860","the promise",4,15],["G1511","that he should be",17,34],["G0846","the",35,38],["G2818","heir",39,43],["G2889","of the world",44,56],["G3756","was not",58,65],["G0011","to Abraham",66,76],["G2228","or",78,80],["G0846","to his",81,87],["G4690","seed",88,92],["G1223","through",94,101],["G3551","the law",102,109],["G0235","but",111,114],["G1223","through",115,122],["G1343","the righteousness",123,140],["G4102","of faith",141,149]]},"4:14":{"text":"For if they which are of the law be heirs, faith is made void, and the promise made of none effect:","words":[["G1063","For",0,3],["G1487","if",4,6],["G1537","they which are of",7,24],["G3551","the law",25,32],["G2818","be heirs",33,41],["G4102","faith",43,48],["G2758","is made void",49,61],["G2532","and",63,66],["G1860","the promise",67,78],["G2673","made of none effect",79,98]]},"4:15":{"text":"Because the law worketh wrath: for where no law is, there is no transgression.","words":[["G1063","Because",0,7],["G3551","the law",8,15],["G2716","worketh",16,23],["G3709","wrath",24,29],["G1063","for",31,34],["G3757","where",35,40],["G3756","no",41,43],["G3551","law",44,47],["G2076","is",48,50],["G3761","there is no",52,63],["G3847","transgression",64,77]]},"4:16":{"text":"Therefore it is of faith, that it might be by grace; to the end the promise might be sure to all the seed; not to that only which is of the law, but to that also which is of the faith of Abraham; who is the father of us all,","words":[["G1223","Therefore",0,9],["G5124","Therefore",0,9],["G1537","it is of",10,18],["G4102","faith",19,24],["G2443","that",26,30],["G2596","it might be by",31,45],["G5485","grace",46,51],["G1519","to the end",53,63],["G1860","the promise",64,75],["G1511","might be",76,84],["G0949","sure",85,89],["G3956","to all",90,96],["G4690","the seed",97,105],["G3756","not",107,110],["G3440","to that only",111,123],["G1537","which is of",124,135],["G3551","the law",136,143],["G0235","but",145,148],["G2532","to that also",149,161],["G1537","which is of",162,173],["G4102","the faith",174,183],["G0011","of Abraham",184,194],["G3739","who",196,199],["G2076","is",200,202],["G3962","the father",203,213],["G2257","of us",214,219],["G3956","all",220,223]]},"4:17":{"text":"(As it is written, I have made thee a father of many nations,) before him whom he believed, even God, who quickeneth the dead, and calleth those things which be not as though they were.","words":[["G2531","(As",0,3],["G1125","it is written",4,17],["G3754","",-1,-1],["G5087","I have made",19,30],["G4571","thee",31,35],["G3962","a father",36,44],["G4183","of many",45,52],["G1484","nations",53,60],["G2713",") before",61,69],["G3739","him whom",70,78],["G4100","he believed",79,90],["G2316","even God",92,100],["G2227","who quickeneth",102,116],["G3498","the dead",117,125],["G2532","and",127,130],["G2564","calleth",131,138],["G5607","those things which be",139,160],["G3361","not",161,164],["G5613","as though",165,174],["G5607","they were",175,184]]},"4:18":{"text":"Who against hope believed in hope, that he might become the father of many nations; according to that which was spoken, So shall thy seed be.","words":[["G3739","Who",0,3],["G3844","against",4,11],["G1680","hope",12,16],["G4100","believed",17,25],["G1909","in",26,28],["G1680","hope",29,33],["G1519","that",35,39],["G0846","he",40,42],["G1096","might become",43,55],["G3962","the father",56,66],["G4183","of many",67,74],["G1484","nations",75,82],["G2596","according",84,93],["G2046","to that which was spoken",94,118],["G3779","So",120,122],["G2071","shall",123,128],["G4675","thy",129,132],["G4690","seed",133,137],["G2071","be",138,140]]},"4:19":{"text":"And being not weak in faith, he considered not his own body now dead, when he was about an hundred years old, neither yet the deadness of Sarah's womb:","words":[["G2532","And",0,3],["G3361","being not",4,13],["G0770","weak",14,18],["G4102","in faith",19,27],["G2657","he considered",29,42],["G3756","not",43,46],["G1438","his own",47,54],["G4983","body",55,59],["G2235","now",60,63],["G3499","dead",64,68],["G5225","when he was",70,81],["G4225","about",82,87],["G1541","an hundred years old",88,108],["G2532","neither yet",110,121],["G3500","the deadness",122,134],["G4564","of Sarah's",135,145],["G3388","womb",146,150]]},"4:20":{"text":"He staggered not at the promise of God through unbelief; but was strong in faith, giving glory to God;","words":[["G1161","",-1,-1],["G1252","He staggered",0,12],["G3756","not",13,16],["G1519","at",17,19],["G1860","the promise",20,31],["G2316","of God",32,38],["G0570","through unbelief",39,55],["G0235","but",57,60],["G1743","was strong",61,71],["G4102","in faith",72,80],["G1325","giving",82,88],["G1391","glory",89,94],["G2316","to God",95,101]]},"4:21":{"text":"And being fully persuaded that, what he had promised, he was able also to perform.","words":[["G2532","And",0,3],["G4135","being fully persuaded",4,25],["G3754","that",26,30],["G3739","what",32,36],["G1861","he had promised",37,52],["G2076","he was",54,60],["G1415","able",61,65],["G2532","also",66,70],["G4160","to perform",71,81]]},"4:22":{"text":"And therefore it was imputed to him for righteousness.","words":[["G2532","And",0,3],["G1352","therefore",4,13],["G3049","it was imputed",14,28],["G0846","to him",29,35],["G1519","for",36,39],["G1343","righteousness",40,53]]},"4:23":{"text":"Now it was not written for his sake alone, that it was imputed to him;","words":[["G1161","Now",0,3],["G1125","it was",4,10],["G3756","not",11,14],["G1125","written",15,22],["G1223","for his sake",23,35],["G0846","for his sake",23,35],["G3440","alone",36,41],["G3754","that",43,47],["G3049","it was imputed",48,62],["G0846","to him",63,69]]},"4:24":{"text":"But for us also, to whom it shall be imputed, if we believe on him that raised up Jesus our Lord from the dead;","words":[["G0235","But",0,3],["G1223","for",4,7],["G2248","us",8,10],["G2532","also",11,15],["G3739","to whom",17,24],["G3195","it shall be",25,36],["G3049","imputed",37,44],["G4100","if we believe",46,59],["G1909","on",60,62],["G1453","him that raised up",63,81],["G2424","Jesus",82,87],["G2257","our",88,91],["G2962","Lord",92,96],["G1537","from",97,101],["G3498","the dead",102,110]]},"4:25":{"text":"Who was delivered for our offences, and was raised again for our justification.","words":[["G3739","Who",0,3],["G3860","was delivered",4,17],["G1223","for",18,21],["G2257","our",22,25],["G3900","offences",26,34],["G2532","and",36,39],["G1453","was raised again",40,56],["G1223","for",57,60],["G2257","our",61,64],["G1347","justification",65,78]]},"5:1":{"text":"Therefore being justified by faith, we have peace with God through our Lord Jesus Christ:","words":[["G3767","Therefore",0,9],["G1344","being justified",10,25],["G1537","by",26,28],["G4102","faith",29,34],["G2192","we have",36,43],["G1515","peace",44,49],["G4314","with",50,54],["G2316","God",55,58],["G1223","through",59,66],["G2257","our",67,70],["G2962","Lord",71,75],["G2424","Jesus",76,81],["G5547","Christ",82,88]]},"5:2":{"text":"By whom also we have access by faith into this grace wherein we stand, and rejoice in hope of the glory of God.","words":[["G1223","By",0,2],["G3739","whom",3,7],["G2532","also",8,12],["G2192","we have",13,20],["G4318","access",21,27],["G4102","by faith",28,36],["G1519","into",37,41],["G5026","this",42,46],["G5485","grace",47,52],["G1722","wherein",53,60],["G3739","wherein",53,60],["G2476","we stand",61,69],["G2532","and",71,74],["G2744","rejoice",75,82],["G1909","in",83,85],["G1680","hope",86,90],["G1391","of the glory",91,103],["G2316","of God",104,110]]},"5:3":{"text":"And not only so, but we glory in tribulations also: knowing that tribulation worketh patience;","words":[["G1161","And",0,3],["G3756","not",4,7],["G3440","only",8,12],["G0235","so, but",13,20],["G2744","we glory",21,29],["G1722","in",30,32],["G2347","tribulations",33,45],["G2532","also",46,50],["G1492","knowing",52,59],["G3754","that",60,64],["G2347","tribulation",65,76],["G2716","worketh",77,84],["G5281","patience",85,93]]},"5:4":{"text":"And patience, experience; and experience, hope:","words":[["G1161","And",0,3],["G5281","patience",4,12],["G1382","experience",14,24],["G1161","and",26,29],["G1382","experience",30,40],["G1680","hope",42,46]]},"5:5":{"text":"And hope maketh not ashamed; because the love of God is shed abroad in our hearts by the Holy Ghost which is given unto us.","words":[["G1161","And",0,3],["G1680","hope",4,8],["G2617","maketh",9,15],["G3756","not",16,19],["G2617","ashamed",20,27],["G3754","because",29,36],["G0026","the love",37,45],["G2316","of God",46,52],["G1632","is shed abroad",53,67],["G1722","in",68,70],["G2257","our",71,74],["G2588","hearts",75,81],["G1223","by",82,84],["G0040","the Holy",85,93],["G4151","Ghost",94,99],["G3588","which",100,105],["G1325","is given",106,114],["G2254","unto us",115,122]]},"5:6":{"text":"For when we were yet without strength, in due time Christ died for the ungodly.","words":[["G1063","For",0,3],["G2257","when we",4,11],["G5607","were",12,16],["G2089","yet",17,20],["G0772","without strength",21,37],["G2596","in due",39,45],["G2540","time",46,50],["G5547","Christ",51,57],["G0599","died",58,62],["G5228","for",63,66],["G0765","the ungodly",67,78]]},"5:7":{"text":"For scarcely for a righteous man will one die: yet peradventure for a good man some would even dare to die.","words":[["G1063","For",0,3],["G3433","scarcely",4,12],["G5228","for",13,16],["G1342","a righteous man",17,32],["G0599","will",33,37],["G5100","one",38,41],["G0599","die",42,45],["G1063","yet",47,50],["G5029","peradventure",51,63],["G5228","for",64,67],["G0018","a good man",68,78],["G5100","some",79,83],["G5111","would",84,89],["G2532","even",90,94],["G5111","dare",95,99],["G0599","to die",100,106]]},"5:8":{"text":"But God commendeth his love toward us, in that, while we were yet sinners, Christ died for us.","words":[["G1161","But",0,3],["G2316","God",4,7],["G4921","commendeth",8,18],["G1438","his",19,22],["G0026","love",23,27],["G1519","toward",28,34],["G2248","us",35,37],["G3754","in that",39,46],["G2257","while we",48,56],["G5607","were",57,61],["G2089","yet",62,65],["G0268","sinners",66,73],["G5547","Christ",75,81],["G0599","died",82,86],["G5228","for",87,90],["G2257","us",91,93]]},"5:9":{"text":"Much more then, being now justified by his blood, we shall be saved from wrath through him.","words":[["G4183","Much",0,4],["G3123","more",5,9],["G3767","then",10,14],["G1344","being",16,21],["G3568","now",22,25],["G1344","justified",26,35],["G1722","by",36,38],["G0846","his",39,42],["G0129","blood",43,48],["G4982","we shall be saved",50,67],["G0575","from",68,72],["G3709","wrath",73,78],["G1223","through",79,86],["G0846","him",87,90]]},"5:10":{"text":"For if, when we were enemies, we were reconciled to God by the death of his Son, much more, being reconciled, we shall be saved by his life.","words":[["G1063","For",0,3],["G1487","if",4,6],["G5607","when we were",8,20],["G2190","enemies",21,28],["G2644","we were reconciled",30,48],["G2316","to God",49,55],["G1223","by",56,58],["G2288","the death",59,68],["G0846","of his",69,75],["G5207","Son",76,79],["G4183","much",81,85],["G3123","more",86,90],["G2644","being reconciled",92,108],["G4982","we shall be saved",110,127],["G1722","by",128,130],["G0846","his",131,134],["G2222","life",135,139]]},"5:11":{"text":"And not only so, but we also joy in God through our Lord Jesus Christ, by whom we have now received the atonement.","words":[["G1161","And",0,3],["G3756","not",4,7],["G3440","only",8,12],["G0235","so, but",13,20],["G2532","we also",21,28],["G2744","joy",29,32],["G1722","in",33,35],["G2316","God",36,39],["G1223","through",40,47],["G2257","our",48,51],["G2962","Lord",52,56],["G2424","Jesus",57,62],["G5547","Christ",63,69],["G1223","by",71,73],["G3739","whom",74,78],["G2983","we have",79,86],["G3568","now",87,90],["G2983","received",91,99],["G2643","the atonement",100,113]]},"5:12":{"text":"Wherefore, as by one man sin entered into the world, and death by sin; and so death passed upon all men, for that all have sinned:","words":[["G1223","Wherefore",0,9],["G5124","Wherefore",0,9],["G5618","as",11,13],["G1223","by",14,16],["G1520","one",17,20],["G0444","man",21,24],["G0266","sin",25,28],["G1525","entered",29,36],["G1519","into",37,41],["G2889","the world",42,51],["G2532","and",53,56],["G2288","death",57,62],["G1223","by",63,65],["G0266","sin",66,69],["G2532","and",71,74],["G3779","so",75,77],["G2288","death",78,83],["G1330","passed",84,90],["G1519","upon",91,95],["G3956","all",96,99],["G0444","men",100,103],["G1909","for",105,108],["G3739","that",109,113],["G3956","all",114,117],["G0264","have sinned",118,129]]},"5:13":{"text":"(For until the law sin was in the world: but sin is not imputed when there is no law.","words":[["G1063","(For",0,4],["G0891","until",5,10],["G3551","the law",11,18],["G0266","sin",19,22],["G2258","was",23,26],["G1722","in",27,29],["G2889","the world",30,39],["G1161","but",41,44],["G0266","sin",45,48],["G1677","is",49,51],["G3756","not",52,55],["G1677","imputed",56,63],["G5607","when there is",64,77],["G3361","no",78,80],["G3551","law",81,84]]},"5:14":{"text":"Nevertheless death reigned from Adam to Moses, even over them that had not sinned after the similitude of Adam's transgression, who is the figure of him that was to come.","words":[["G0235","Nevertheless",0,12],["G2288","death",13,18],["G0936","reigned",19,26],["G0575","from",27,31],["G0076","Adam",32,36],["G3360","to",37,39],["G3475","Moses",40,45],["G2532","even",47,51],["G1909","over",52,56],["G0264","them that had",57,70],["G3361","not",71,74],["G0264","sinned",75,81],["G1909","after",82,87],["G3667","the similitude",88,102],["G0076","of Adam's",103,112],["G3847","transgression",113,126],["G3739","who",128,131],["G2076","is",132,134],["G5179","the figure",135,145],["G3195","of him that was to come",146,169]]},"5:15":{"text":"But not as the offence, so also is the free gift. For if through the offence of one many be dead, much more the grace of God, and the gift by grace, which is by one man, Jesus Christ, hath abounded unto many.","words":[["G0235","But",0,3],["G3756","not",4,7],["G5613","as",8,10],["G3900","the offence",11,22],["G3779","so",24,26],["G2532","also",27,31],["G5486","is the free gift",32,48],["G1063","For",50,53],["G1487","if",54,56],["G3900","through the offence",57,76],["G1520","of one",77,83],["G4183","many",84,88],["G0599","be dead",89,96],["G4183","much",98,102],["G3123","more",103,107],["G5485","the grace",108,117],["G2316","of God",118,124],["G2532","and",126,129],["G1431","the gift",130,138],["G1722","by",139,141],["G5485","grace",142,147],["G3588","which is",149,157],["G1520","by one",158,164],["G0444","man",165,168],["G2424","Jesus",170,175],["G5547","Christ",176,182],["G4052","hath abounded",184,197],["G1519","unto",198,202],["G4183","many",203,207]]},"5:16":{"text":"And not as it was by one that sinned, so is the gift: for the judgment was by one to condemnation, but the free gift is of many offences unto justification.","words":[["G2532","And",0,3],["G3756","not",4,7],["G5613","as",8,10],["G1223","it was by",11,20],["G1520","one",21,24],["G0264","that sinned",25,36],["G1434","so is the gift",38,52],["G1063","for",54,57],["G3303","for",54,57],["G2917","the judgment",58,70],["G1537","was by",71,77],["G1520","one",78,81],["G1519","to",82,84],["G2631","condemnation",85,97],["G1161","but",99,102],["G5486","the free gift",103,116],["G1537","is of",117,122],["G4183","many",123,127],["G3900","offences",128,136],["G1519","unto",137,141],["G1345","justification",142,155]]},"5:17":{"text":"For if by one man's offence death reigned by one; much more they which receive abundance of grace and of the gift of righteousness shall reign in life by one, Jesus Christ.)","words":[["G1063","For",0,3],["G1487","if",4,6],["G1520","by one man's",7,19],["G3900","offence",20,27],["G2288","death",28,33],["G0936","reigned",34,41],["G1223","by",42,44],["G1520","one",45,48],["G4183","much",50,54],["G3123","more",55,59],["G2983","they which receive",60,78],["G4050","abundance",79,88],["G5485","of grace",89,97],["G2532","and",98,101],["G1431","of the gift",102,113],["G1343","of righteousness",114,130],["G0936","shall reign",131,142],["G1722","in",143,145],["G2222","life",146,150],["G1223","by",151,153],["G1520","one",154,157],["G2424","Jesus",159,164],["G5547","Christ",165,171]]},"5:18":{"text":"Therefore as by the offence of one judgment came upon all men to condemnation; even so by the righteousness of one the free gift came upon all men unto justification of life.","words":[["G0686","Therefore",0,9],["G3767","Therefore",0,9],["G5613","as",10,12],["G1223","by",13,15],["G3900","the offence",16,27],["G1520","of one",28,34],["G1519","judgment came upon",35,53],["G3956","all",54,57],["G0444","men",58,61],["G1519","to",62,64],["G2631","condemnation",65,77],["G2532","even",79,83],["G3779","so",84,86],["G1223","by",87,89],["G1345","the righteousness",90,107],["G1520","of one",108,114],["G1519","the free gift came upon",115,138],["G3956","all",139,142],["G0444","men",143,146],["G1519","unto",147,151],["G1347","justification",152,165],["G2222","of life",166,173]]},"5:19":{"text":"For as by one man's disobedience many were made sinners, so by the obedience of one shall many be made righteous.","words":[["G1063","For",0,3],["G5618","as",4,6],["G1223","by",7,9],["G1520","one",10,13],["G0444","man's",14,19],["G3876","disobedience",20,32],["G4183","many",33,37],["G2525","were made",38,47],["G0268","sinners",48,55],["G3779","so",57,59],["G2532","so",57,59],["G1223","by",60,62],["G5218","the obedience",63,76],["G1520","of one",77,83],["G2525","shall",84,89],["G4183","many",90,94],["G2525","be made",95,102],["G1342","righteous",103,112]]},"5:20":{"text":"Moreover the law entered, that the offence might abound. But where sin abounded, grace did much more abound:","words":[["G1161","Moreover",0,8],["G3551","the law",9,16],["G3922","entered",17,24],["G2443","that",26,30],["G3900","the offence",31,42],["G4121","might abound",43,55],["G1161","But",57,60],["G3757","where",61,66],["G0266","sin",67,70],["G4121","abounded",71,79],["G5485","grace",81,86],["G5248","did much more abound",87,107]]},"5:21":{"text":"That as sin hath reigned unto death, even so might grace reign through righteousness unto eternal life by Jesus Christ our Lord.","words":[["G2443","That",0,4],["G5618","as",5,7],["G0266","sin",8,11],["G0936","hath reigned",12,24],["G1722","unto",25,29],["G2288","death",30,35],["G2532","even",37,41],["G3779","so",42,44],["G0936","might",45,50],["G5485","grace",51,56],["G0936","reign",57,62],["G1223","through",63,70],["G1343","righteousness",71,84],["G1519","unto",85,89],["G0166","eternal",90,97],["G2222","life",98,102],["G1223","by",103,105],["G2424","Jesus",106,111],["G5547","Christ",112,118],["G2257","our",119,122],["G2962","Lord",123,127]]},"6:1":{"text":"What shall we say then? Shall we continue in sin, that grace may abound?","words":[["G5101","What",0,4],["G2046","shall we say",5,17],["G3767","then",18,22],["G1961","Shall we continue",24,41],["G0266","in sin",42,48],["G2443","that",50,54],["G5485","grace",55,60],["G4121","may abound",61,71]]},"6:2":{"text":"God forbid. How shall we, that are dead to sin, live any longer therein?","words":[["G3361","God forbid",0,10],["G1096","God forbid",0,10],["G4459","How",12,15],["G3748","shall we, that",16,30],["G0599","are dead",31,39],["G0266","to sin",40,46],["G2198","live",48,52],["G2089","any longer",53,63],["G1722","therein",64,71],["G0846","therein",64,71]]},"6:3":{"text":"Know ye not, that so many of us as were baptized into Jesus Christ were baptized into his death?","words":[["G2228","",-1,-1],["G0050","Know ye not",0,11],["G3754","that so",13,20],["G3745","many of us",21,31],["G0907","as were baptized",32,48],["G1519","into",49,53],["G2424","Jesus",54,59],["G5547","Christ",60,66],["G0907","were baptized",67,80],["G1519","into",81,85],["G0846","his",86,89],["G2288","death",90,95]]},"6:4":{"text":"Therefore we are buried with him by baptism into death: that like as Christ was raised up from the dead by the glory of the Father, even so we also should walk in newness of life.","words":[["G3767","Therefore",0,9],["G4916","we are buried with",10,28],["G0846","him",29,32],["G1223","by",33,35],["G0908","baptism",36,43],["G1519","into",44,48],["G2288","death",49,54],["G2443","that",56,60],["G5618","like as",61,68],["G5547","Christ",69,75],["G1453","was raised up",76,89],["G1537","from",90,94],["G3498","the dead",95,103],["G1223","by",104,106],["G1391","the glory",107,116],["G3962","of the Father",117,130],["G3779","even so",132,139],["G2249","we",140,142],["G2532","also",143,147],["G4043","should walk",148,159],["G1722","in",160,162],["G2538","newness",163,170],["G2222","of life",171,178]]},"6:5":{"text":"For if we have been planted together in the likeness of his death, we shall be also in the likeness of his resurrection:","words":[["G1063","For",0,3],["G1487","if",4,6],["G1096","we have been",7,19],["G4854","planted together",20,36],["G3667","in the likeness",37,52],["G0846","of his",53,59],["G2288","death",60,65],["G2071","we shall be",67,78],["G0235","also",79,83],["G2532","also",79,83],["G0386","in the likeness of his resurrection",84,119]]},"6:6":{"text":"Knowing this, that our old man is crucified with him, that the body of sin might be destroyed, that henceforth we should not serve sin.","words":[["G1097","Knowing",0,7],["G5124","this",8,12],["G3754","that",14,18],["G2257","our",19,22],["G3820","old",23,26],["G0444","man",27,30],["G4957","is crucified with",31,48],["G2443","him, that",49,58],["G4983","the body",59,67],["G0266","of sin",68,74],["G2673","might be destroyed",75,93],["G3371","that henceforth",95,110],["G2248","we",111,113],["G1398","should",114,120],["G3371","not",121,124],["G1398","serve",125,130],["G0266","sin",131,134]]},"6:7":{"text":"For he that is dead is freed from sin.","words":[["G1063","For",0,3],["G0599","he that is dead",4,19],["G1344","is freed",20,28],["G0575","from",29,33],["G0266","sin",34,37]]},"6:8":{"text":"Now if we be dead with Christ, we believe that we shall also live with him:","words":[["G1161","Now",0,3],["G1487","if",4,6],["G0599","we be dead",7,17],["G4862","with",18,22],["G5547","Christ",23,29],["G4100","we believe",31,41],["G3754","that",42,46],["G4800","we shall",47,55],["G2532","also",56,60],["G4800","live",61,65],["G0846","with him",66,74]]},"6:9":{"text":"Knowing that Christ being raised from the dead dieth no more; death hath no more dominion over him.","words":[["G1492","Knowing",0,7],["G3754","that",8,12],["G5547","Christ",13,19],["G1453","being raised",20,32],["G1537","from",33,37],["G3498","the dead",38,46],["G0599","dieth",47,52],["G3765","no more",53,60],["G2288","death",62,67],["G2961","hath",68,72],["G3765","no more",73,80],["G2961","dominion over",81,94],["G0846","him",95,98]]},"6:10":{"text":"For in that he died, he died unto sin once: but in that he liveth, he liveth unto God.","words":[["G3739","For",0,3],["G1063","For",0,3],["G0599","in that he died",4,19],["G0599","he died",21,28],["G0266","unto sin",29,37],["G2178","once",38,42],["G1161","but",44,47],["G3739","in that",48,55],["G2198","he liveth",56,65],["G2198","he liveth",67,76],["G2316","unto God",77,85]]},"6:11":{"text":"Likewise reckon ye also yourselves to be dead indeed unto sin, but alive unto God through Jesus Christ our Lord.","words":[["G3779","Likewise",0,8],["G3049","reckon",9,15],["G5210","ye",16,18],["G2532","also",19,23],["G1438","yourselves",24,34],["G1511","to be",35,40],["G3498","dead",41,45],["G3303","indeed",46,52],["G0266","unto sin",53,61],["G1161","but",63,66],["G2198","alive",67,72],["G2316","unto God",73,81],["G1722","through",82,89],["G2424","Jesus",90,95],["G5547","Christ",96,102],["G2257","our",103,106],["G2962","Lord",107,111]]},"6:12":{"text":"Let not sin therefore reign in your mortal body, that ye should obey it in the lusts thereof.","words":[["G0936","Let",0,3],["G3361","not",4,7],["G0266","sin",8,11],["G3767","therefore",12,21],["G0936","reign",22,27],["G1722","in",28,30],["G5216","your",31,35],["G2349","mortal",36,42],["G4983","body",43,47],["G1519","that",49,53],["G5219","ye should obey",54,68],["G0846","it",69,71],["G1722","in",72,74],["G1939","the lusts",75,84],["G0846","thereof",85,92]]},"6:13":{"text":"Neither yield ye your members as instruments of unrighteousness unto sin: but yield yourselves unto God, as those that are alive from the dead, and your members as instruments of righteousness unto God.","words":[["G3366","Neither",0,7],["G3936","yield ye",8,16],["G5216","your",17,21],["G3196","members",22,29],["G3696","as instruments",30,44],["G0093","of unrighteousness",45,63],["G0266","unto sin",64,72],["G0235","but",74,77],["G3936","yield",78,83],["G1438","yourselves",84,94],["G2316","unto God",95,103],["G5613","as",105,107],["G2198","those that are alive",108,128],["G1537","from",129,133],["G3498","the dead",134,142],["G2532","and",144,147],["G5216","your",148,152],["G3196","members",153,160],["G3696","as instruments",161,175],["G1343","of righteousness",176,192],["G2316","unto God",193,201]]},"6:14":{"text":"For sin shall not have dominion over you: for ye are not under the law, but under grace.","words":[["G1063","For",0,3],["G0266","sin",4,7],["G2961","shall",8,13],["G3756","not",14,17],["G2961","have dominion over",18,36],["G5216","you",37,40],["G1063","for",42,45],["G2075","ye are",46,52],["G3756","not",53,56],["G5259","under",57,62],["G3551","the law",63,70],["G0235","but",72,75],["G5259","under",76,81],["G5485","grace",82,87]]},"6:15":{"text":"What then? shall we sin, because we are not under the law, but under grace? God forbid.","words":[["G5101","What",0,4],["G3767","then",5,9],["G0264","shall we sin",11,23],["G3754","because",25,32],["G2070","we are",33,39],["G3756","not",40,43],["G5259","under",44,49],["G3551","the law",50,57],["G0235","but",59,62],["G5259","under",63,68],["G5485","grace",69,74],["G3361","God forbid",76,86],["G1096","God forbid",76,86]]},"6:16":{"text":"Know ye not, that to whom ye yield yourselves servants to obey, his servants ye are to whom ye obey; whether of sin unto death, or of obedience unto righteousness?","words":[["G1492","Know ye",0,7],["G3756","not",8,11],["G3754","that",13,17],["G3739","to whom",18,25],["G3936","ye yield",26,34],["G1438","yourselves",35,45],["G1401","servants",46,54],["G1519","to",55,57],["G5218","obey",58,62],["G1401","his servants",64,76],["G2075","ye are",77,83],["G3739","to whom",84,91],["G5219","ye obey",92,99],["G2273","whether",101,108],["G0266","of sin",109,115],["G1519","unto",116,120],["G2288","death",121,126],["G2228","or",128,130],["G5218","of obedience",131,143],["G1519","unto",144,148],["G1343","righteousness",149,162]]},"6:17":{"text":"But God be thanked, that ye were the servants of sin, but ye have obeyed from the heart that form of doctrine which was delivered you.","words":[["G1161","But",0,3],["G2316","God",4,7],["G5485","be thanked",8,18],["G3754","that",20,24],["G2258","ye were",25,32],["G1401","the servants",33,45],["G0266","of sin",46,52],["G1161","but",54,57],["G5219","ye have obeyed",58,72],["G1537","from",73,77],["G2588","the heart",78,87],["G5179","that form",88,97],["G1322","of doctrine",98,109],["G1519","which",110,115],["G3739","which",110,115],["G3860","was delivered you",116,133]]},"6:18":{"text":"Being then made free from sin, ye became the servants of righteousness.","words":[["G1659","Being",0,5],["G1161","then",6,10],["G1659","made free",11,20],["G0575","from",21,25],["G0266","sin",26,29],["G1402","ye became the servants",31,53],["G1343","of righteousness",54,70]]},"6:19":{"text":"I speak after the manner of men because of the infirmity of your flesh: for as ye have yielded your members servants to uncleanness and to iniquity unto iniquity; even so now yield your members servants to righteousness unto holiness.","words":[["G3004","I speak",0,7],["G0442","after the manner of men",8,31],["G1223","because",32,39],["G0769","of the infirmity",40,56],["G5216","of your",57,64],["G4561","flesh",65,70],["G1063","for",72,75],["G5618","as",76,78],["G3936","ye have yielded",79,94],["G5216","your",95,99],["G3196","members",100,107],["G1401","servants",108,116],["G0167","to uncleanness",117,131],["G2532","and",132,135],["G0458","to iniquity",136,147],["G1519","unto",148,152],["G0458","iniquity",153,161],["G3779","even so",163,170],["G3568","now",171,174],["G3936","yield",175,180],["G5216","your",181,185],["G3196","members",186,193],["G1401","servants",194,202],["G1343","to righteousness",203,219],["G1519","unto",220,224],["G0038","holiness",225,233]]},"6:20":{"text":"For when ye were the servants of sin, ye were free from righteousness.","words":[["G1063","For",0,3],["G3753","when",4,8],["G2258","ye were",9,16],["G1401","the servants",17,29],["G0266","of sin",30,36],["G2258","ye were",38,45],["G1658","free",46,50],["G1343","from righteousness",51,69]]},"6:21":{"text":"What fruit had ye then in those things whereof ye are now ashamed? for the end of those things is death.","words":[["G5101","What",0,4],["G3767","What",0,4],["G2590","fruit",5,10],["G2192","had ye",11,17],["G5119","then",18,22],["G1909","in",23,25],["G3739","those things whereof",26,46],["G1870","ye are",47,53],["G3568","now",54,57],["G1870","ashamed",58,65],["G1063","for",67,70],["G5056","the end",71,78],["G1565","of those things",79,94],["G2288","is death",95,103]]},"6:22":{"text":"But now being made free from sin, and become servants to God, ye have your fruit unto holiness, and the end everlasting life.","words":[["G1161","But",0,3],["G3570","now",4,7],["G1659","being made free",8,23],["G0575","from",24,28],["G0266","sin",29,32],["G1161","and",34,37],["G1402","become servants",38,53],["G2316","to God",54,60],["G2192","ye have",62,69],["G5216","your",70,74],["G2590","fruit",75,80],["G1519","unto",81,85],["G0038","holiness",86,94],["G1161","and",96,99],["G5056","the end",100,107],["G0166","everlasting",108,119],["G2222","life",120,124]]},"6:23":{"text":"For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord.","words":[["G1063","For",0,3],["G3800","the wages",4,13],["G0266","of sin",14,20],["G2288","is death",21,29],["G1161","but",31,34],["G5486","the gift",35,43],["G2316","of God",44,50],["G0166","is eternal",51,61],["G2222","life",62,66],["G1722","through",67,74],["G2424","Jesus",75,80],["G5547","Christ",81,87],["G2257","our",88,91],["G2962","Lord",92,96]]},"7:1":{"text":"Know ye not, brethren, (for I speak to them that know the law,) how that the law hath dominion over a man as long as he liveth?","words":[["G2228","",-1,-1],["G0050","Know ye not",0,11],["G0080","brethren",13,21],["G1063","(for",23,27],["G2980","I speak",28,35],["G1097","to them that know",36,53],["G3551","the law",54,61],["G3754",") how that",62,72],["G3551","the law",73,80],["G2961","hath dominion over",81,99],["G0444","a man",100,105],["G1909","as long as",106,116],["G3745","as long as",106,116],["G5550","as long as",106,116],["G2198","he liveth",117,126]]},"7:2":{"text":"For the woman which hath an husband is bound by the law to her husband so long as he liveth; but if the husband be dead, she is loosed from the law of her husband.","words":[["G1063","For",0,3],["G1135","the woman",4,13],["G5220","which hath an husband",14,35],["G1210","is bound",36,44],["G3551","by the law",45,55],["G0435","to her husband",56,70],["G2198","so long as he liveth",71,91],["G1161","but",93,96],["G1437","if",97,99],["G0435","the husband",100,111],["G0599","be dead",112,119],["G2673","she is loosed",121,134],["G0575","from",135,139],["G3551","the law",140,147],["G0435","of her husband",148,162]]},"7:3":{"text":"So then if, while her husband liveth, she be married to another man, she shall be called an adulteress: but if her husband be dead, she is free from that law; so that she is no adulteress, though she be married to another man.","words":[["G0686","So then",0,7],["G3767","So then",0,7],["G1437","if",8,10],["G0435","while her husband",12,29],["G2198","liveth",30,36],["G1096","she be married",38,52],["G2087","to another",53,63],["G0435","man",64,67],["G5537","she shall be called",69,88],["G3428","an adulteress",89,102],["G1161","but",104,107],["G1437","if",108,110],["G0435","her husband",111,122],["G0599","be dead",123,130],["G2076","she is",132,138],["G1658","free",139,143],["G0575","from",144,148],["G3551","that law",149,157],["G0846","so that she",159,170],["G1511","is",171,173],["G3361","no",174,176],["G3428","adulteress",177,187],["G1096","though she be married",189,210],["G2087","to another",211,221],["G0435","man",222,225]]},"7:4":{"text":"Wherefore, my brethren, ye also are become dead to the law by the body of Christ; that ye should be married to another, even to him who is raised from the dead, that we should bring forth fruit unto God.","words":[["G5620","Wherefore",0,9],["G3450","my",11,13],["G0080","brethren",14,22],["G5210","ye",24,26],["G2532","also",27,31],["G2289","are become dead",32,47],["G3551","to the law",48,58],["G1223","by",59,61],["G4983","the body",62,70],["G5547","of Christ",71,80],["G1519","that",82,86],["G5209","ye",87,89],["G1096","should be married",90,107],["G2087","to another",108,118],["G1453","even to him who is raised",120,145],["G1537","from",146,150],["G3498","the dead",151,159],["G2443","that",161,165],["G2592","we should bring forth fruit",166,193],["G2316","unto God",194,202]]},"7:5":{"text":"For when we were in the flesh, the motions of sins, which were by the law, did work in our members to bring forth fruit unto death.","words":[["G1063","For",0,3],["G3753","when",4,8],["G2258","we were",9,16],["G1722","in",17,19],["G4561","the flesh",20,29],["G3804","the motions",31,42],["G0266","of sins",43,50],["G3588","which",52,57],["G1223","were by",58,65],["G3551","the law",66,73],["G1754","did work",75,83],["G1722","in",84,86],["G2257","our",87,90],["G3196","members",91,98],["G1519","to bring",99,107],["G2592","forth fruit",108,119],["G2288","unto death",120,130]]},"7:6":{"text":"But now we are delivered from the law, that being dead wherein we were held; that we should serve in newness of spirit, and not in the oldness of the letter.","words":[["G1161","But",0,3],["G3570","now",4,7],["G2673","we are delivered",8,24],["G0575","from",25,29],["G3551","the law",30,37],["G0599","that being dead",39,54],["G0599","that being dead",39,54],["G1722","wherein",55,62],["G3739","wherein",55,62],["G2722","we were held",63,75],["G5620","that",77,81],["G2248","we",82,84],["G1398","should serve",85,97],["G1722","in",98,100],["G2538","newness",101,108],["G4151","of spirit",109,118],["G2532","and",120,123],["G3756","not",124,127],["G3821","in the oldness",128,142],["G1121","of the letter",143,156]]},"7:7":{"text":"What shall we say then? Is the law sin? God forbid. Nay, I had not known sin, but by the law: for I had not known lust, except the law had said, Thou shalt not covet.","words":[["G5101","What",0,4],["G2046","shall we say",5,17],["G3767","then",18,22],["G3551","Is the law",24,34],["G0266","sin",35,38],["G3361","God forbid",40,50],["G1096","God forbid",40,50],["G0235","Nay",52,55],["G1097","I had",57,62],["G3756","not",63,66],["G1097","known",67,72],["G0266","sin",73,76],["G1508","but",78,81],["G1223","by",82,84],["G3551","the law",85,92],["G1063","for",94,97],["G5037","for",94,97],["G1492","I had",98,103],["G3756","not",104,107],["G1492","known",108,113],["G1939","lust",114,118],["G1508","except",120,126],["G3551","the law",127,134],["G3004","had said",135,143],["G1937","Thou shalt",145,155],["G3756","not",156,159],["G1937","covet",160,165]]},"7:8":{"text":"But sin, taking occasion by the commandment, wrought in me all manner of concupiscence. For without the law sin was dead.","words":[["G1161","But",0,3],["G0266","sin",4,7],["G2983","taking",9,15],["G0874","occasion",16,24],["G1223","by",25,27],["G1785","the commandment",28,43],["G2716","wrought",45,52],["G1722","in",53,55],["G1698","me",56,58],["G3956","all manner of",59,72],["G1939","concupiscence",73,86],["G1063","For",88,91],["G5565","without",92,99],["G3551","the law",100,107],["G0266","sin",108,111],["G3498","was dead",112,120]]},"7:9":{"text":"For I was alive without the law once: but when the commandment came, sin revived, and I died.","words":[["G1161","For",0,3],["G1473","I",4,5],["G2198","was alive",6,15],["G5565","without",16,23],["G3551","the law",24,31],["G4218","once",32,36],["G1161","but",38,41],["G1785","when the commandment",42,62],["G2064","came",63,67],["G0266","sin",69,72],["G0326","revived",73,80],["G1161","and",82,85],["G1473","I",86,87],["G0599","died",88,92]]},"7:10":{"text":"And the commandment, which was ordained to life, I found to be unto death.","words":[["G2532","And",0,3],["G1785","the commandment",4,19],["G3588","which",21,26],["G1519","was ordained to",27,42],["G2222","life",43,47],["G3427","I",49,50],["G2147","found",51,56],["G3778","found",51,56],["G1519","to be unto",57,67],["G2288","death",68,73]]},"7:11":{"text":"For sin, taking occasion by the commandment, deceived me, and by it slew me.","words":[["G1063","For",0,3],["G0266","sin",4,7],["G2983","taking",9,15],["G0874","occasion",16,24],["G1223","by",25,27],["G1785","the commandment",28,43],["G1818","deceived",45,53],["G3165","me",54,56],["G2532","and",58,61],["G1223","by",62,64],["G0846","it",65,67],["G0615","slew",68,72]]},"7:12":{"text":"Wherefore the law is holy, and the commandment holy, and just, and good.","words":[["G5620","Wherefore",0,9],["G3303","Wherefore",0,9],["G3551","the law",10,17],["G0040","is holy",18,25],["G2532","and",27,30],["G1785","the commandment",31,46],["G0040","holy",47,51],["G2532","and",53,56],["G1342","just",57,61],["G2532","and",63,66],["G0018","good",67,71]]},"7:13":{"text":"Was then that which is good made death unto me? God forbid. But sin, that it might appear sin, working death in me by that which is good; that sin by the commandment might become exceeding sinful.","words":[["G3767","Was then",0,8],["G0018","that which is good",9,27],["G1096","made",28,32],["G2288","death",33,38],["G1698","unto me",39,46],["G3361","God forbid",48,58],["G1096","God forbid",48,58],["G0235","But",60,63],["G0266","sin",64,67],["G2443","that",69,73],["G5316","it might appear",74,89],["G0266","sin",90,93],["G2716","working",95,102],["G2288","death",103,108],["G3427","in me",109,114],["G1223","by",115,117],["G0018","that which is good",118,136],["G2443","that",138,142],["G0266","sin",143,146],["G1223","by",147,149],["G1785","the commandment",150,165],["G1096","might become",166,178],["G2596","exceeding",179,188],["G5236","exceeding",179,188],["G0268","sinful",189,195]]},"7:14":{"text":"For we know that the law is spiritual: but I am carnal, sold under sin.","words":[["G1063","For",0,3],["G1492","we know",4,11],["G3754","that",12,16],["G3551","the law",17,24],["G2076","is",25,27],["G4152","spiritual",28,37],["G1161","but",39,42],["G1473","I",43,44],["G1510","am",45,47],["G4559","carnal",48,54],["G4097","sold",56,60],["G5259","under",61,66],["G0266","sin",67,70]]},"7:15":{"text":"For that which I do I allow not: for what I would, that do I not; but what I hate, that do I.","words":[["G1063","For",0,3],["G3739","that which",4,14],["G2716","I do",15,19],["G1097","I allow",20,27],["G3756","not",28,31],["G1063","for",33,36],["G3739","what",37,41],["G2309","I would",42,49],["G5124","that",51,55],["G4238","do I",56,60],["G3756","not",61,64],["G0235","but",66,69],["G3739","what",70,74],["G3404","I hate",75,81],["G5124","that",83,87],["G4160","do I",88,92]]},"7:16":{"text":"If then I do that which I would not, I consent unto the law that it is good.","words":[["G1487","If",0,2],["G1161","then",3,7],["G4160","I do",8,12],["G5124","that",13,17],["G3739","which",18,23],["G2309","I would",24,31],["G3756","not",32,35],["G4852","I consent",37,46],["G3551","unto the law",47,59],["G3754","that",60,64],["G2570","it is good",65,75]]},"7:17":{"text":"Now then it is no more I that do it, but sin that dwelleth in me.","words":[["G3570","Now",0,3],["G1161","then",4,8],["G3765","it is no more",9,22],["G1473","I",23,24],["G2716","that do",25,32],["G0846","it",33,35],["G0235","but",37,40],["G0266","sin",41,44],["G3611","that dwelleth",45,58],["G1722","in",59,61],["G1698","me",62,64]]},"7:18":{"text":"For I know that in me (that is, in my flesh,) dwelleth no good thing: for to will is present with me; but how to perform that which is good I find not.","words":[["G1063","For",0,3],["G1492","I know",4,10],["G3754","that",11,15],["G1722","in",16,18],["G1698","me",19,21],["G5123","(that is",22,30],["G1722","in",32,34],["G3450","my",35,37],["G4561","flesh",38,43],["G3611",") dwelleth",44,54],["G3756","no",55,57],["G0018","good thing",58,68],["G1063","for",70,73],["G2309","to will",74,81],["G3873","is present",82,92],["G3427","with me",93,100],["G1161","but",102,105],["G2716","how to perform",106,120],["G2570","that which is good",121,139],["G2147","I find",140,146],["G3756","not",147,150]]},"7:19":{"text":"For the good that I would I do not: but the evil which I would not, that I do.","words":[["G1063","For",0,3],["G3739","For",0,3],["G0018","the good",4,12],["G2309","that I would",13,25],["G4160","I do",26,30],["G3756","not",31,34],["G0235","but",36,39],["G2556","the evil",40,48],["G3739","which",49,54],["G2309","I would",55,62],["G3756","not",63,66],["G5124","that",68,72],["G4238","I do",73,77]]},"7:20":{"text":"Now if I do that I would not, it is no more I that do it, but sin that dwelleth in me.","words":[["G1161","Now",0,3],["G1487","if",4,6],["G3739","if",4,6],["G4160","I do",7,11],["G5124","that",12,16],["G1473","I",17,18],["G2309","would",19,24],["G3756","not",25,28],["G2089","it is no more",30,43],["G3765","it is no more",30,43],["G1473","I",44,45],["G2716","that do",46,53],["G0846","it",54,56],["G0235","but",58,61],["G0266","sin",62,65],["G3611","that dwelleth",66,79],["G1722","in",80,82],["G1698","me",83,85]]},"7:21":{"text":"I find then a law, that, when I would do good, evil is present with me.","words":[["G2147","I find",0,6],["G0686","then",7,11],["G3551","a law",12,17],["G3754","that",19,23],["G1698","when I",25,31],["G2309","would",32,37],["G4160","do",38,40],["G2570","good",41,45],["G2556","evil",47,51],["G3873","is present",52,62],["G1698","with me",63,70]]},"7:22":{"text":"For I delight in the law of God after the inward man:","words":[["G1063","For",0,3],["G4913","I delight",4,13],["G3551","in the law",14,24],["G2316","of God",25,31],["G2596","after",32,37],["G2080","the inward",38,48],["G0444","man",49,52]]},"7:23":{"text":"But I see another law in my members, warring against the law of my mind, and bringing me into captivity to the law of sin which is in my members.","words":[["G1161","But",0,3],["G0991","I see",4,9],["G2087","another",10,17],["G3551","law",18,21],["G1722","in",22,24],["G3450","my",25,27],["G3196","members",28,35],["G0497","warring against",37,52],["G3551","the law",53,60],["G3450","of my",61,66],["G3563","mind",67,71],["G2532","and",73,76],["G0163","bringing",77,85],["G3165","me",86,88],["G0163","into captivity",89,103],["G3551","to the law",104,114],["G0266","of sin",115,121],["G3588","which",122,127],["G5607","is",128,130],["G1722","in",131,133],["G3450","my",134,136],["G3196","members",137,144]]},"7:24":{"text":"O wretched man that I am! who shall deliver me from the body of this death?","words":[["G5005","O wretched",0,10],["G0444","man",11,14],["G1473","that I am",15,24],["G5101","who",26,29],["G4506","shall deliver",30,43],["G3165","me",44,46],["G1537","from",47,51],["G4983","the body",52,60],["G5127","of this",61,68],["G2288","death",69,74]]},"7:25":{"text":"I thank God through Jesus Christ our Lord. So then with the mind I myself serve the law of God; but with the flesh the law of sin.","words":[["G2168","I thank",0,7],["G2316","God",8,11],["G1223","through",12,19],["G2424","Jesus",20,25],["G5547","Christ",26,32],["G2257","our",33,36],["G2962","Lord",37,41],["G0686","So then",43,50],["G3767","So then",43,50],["G3563","with the mind",51,64],["G1473","I",65,66],["G0846","myself",67,73],["G3303","serve",74,79],["G1398","serve",74,79],["G3551","the law",80,87],["G2316","of God",88,94],["G1161","but",96,99],["G4561","with the flesh",100,114],["G3551","the law",115,122],["G0266","of sin",123,129]]},"8:1":{"text":"There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit.","words":[["G0686","There is therefore",0,18],["G3568","now",19,22],["G3762","no",23,25],["G2631","condemnation",26,38],["G1722","to them which are in",39,59],["G5547","Christ",60,66],["G2424","Jesus",67,72],["G4043","who walk",74,82],["G3361","not",83,86],["G2596","after",87,92],["G4561","the flesh",93,102],["G0235","but",104,107],["G2596","after",108,113],["G4151","the Spirit",114,124]]},"8:2":{"text":"For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death.","words":[["G1063","For",0,3],["G3551","the law",4,11],["G4151","of the Spirit",12,25],["G2222","of life",26,33],["G1722","in",34,36],["G5547","Christ",37,43],["G2424","Jesus",44,49],["G1659","hath made",50,59],["G3165","me",60,62],["G1659","free",63,67],["G0575","from",68,72],["G3551","the law",73,80],["G0266","of sin",81,87],["G2532","and",88,91],["G2288","death",92,97]]},"8:3":{"text":"For what the law could not do, in that it was weak through the flesh, God sending his own Son in the likeness of sinful flesh, and for sin, condemned sin in the flesh:","words":[["G1063","For",0,3],["G3551","what the law",4,16],["G0102","could not do",17,29],["G1722","in",31,33],["G3739","that",34,38],["G0770","it was weak",39,50],["G1223","through",51,58],["G4561","the flesh",59,68],["G2316","God",70,73],["G3992","sending",74,81],["G1438","his own",82,89],["G5207","Son",90,93],["G1722","in",94,96],["G3667","the likeness",97,109],["G0266","of sinful",110,119],["G4561","flesh",120,125],["G2532","and",127,130],["G4012","for",131,134],["G0266","sin",135,138],["G2632","condemned",140,149],["G0266","sin",150,153],["G1722","in",154,156],["G4561","the flesh",157,166]]},"8:4":{"text":"That the righteousness of the law might be fulfilled in us, who walk not after the flesh, but after the Spirit.","words":[["G2443","That",0,4],["G1345","the righteousness",5,22],["G3551","of the law",23,33],["G4137","might be fulfilled",34,52],["G1722","in",53,55],["G2254","us",56,58],["G4043","who walk",60,68],["G3361","not",69,72],["G2596","after",73,78],["G4561","the flesh",79,88],["G0235","but",90,93],["G2596","after",94,99],["G4151","the Spirit",100,110]]},"8:5":{"text":"For they that are after the flesh do mind the things of the flesh; but they that are after the Spirit the things of the Spirit.","words":[["G1063","For",0,3],["G5607","they that are",4,17],["G2596","after",18,23],["G4561","the flesh",24,33],["G5426","do mind",34,41],["G3588","the things",42,52],["G4561","of the flesh",53,65],["G1161","but",67,70],["G2596","they that are after",71,90],["G4151","the Spirit",91,101],["G3588","the things",102,112],["G4151","of the Spirit",113,126]]},"8:6":{"text":"For to be carnally minded is death; but to be spiritually minded is life and peace.","words":[["G1063","For",0,3],["G5427","to be",4,9],["G4561","carnally",10,18],["G5427","minded",19,25],["G2288","is death",26,34],["G1161","but",36,39],["G5427","to be",40,45],["G4151","spiritually",46,57],["G5427","minded",58,64],["G2222","is life",65,72],["G2532","and",73,76],["G1515","peace",77,82]]},"8:7":{"text":"Because the carnal mind is enmity against God: for it is not subject to the law of God, neither indeed can be.","words":[["G1360","Because",0,7],["G4561","the carnal",8,18],["G5427","mind",19,23],["G2189","is enmity",24,33],["G1519","against",34,41],["G2316","God",42,45],["G1063","for",47,50],["G5293","it is",51,56],["G3756","not",57,60],["G5293","subject",61,68],["G3551","to the law",69,79],["G2316","of God",80,86],["G3761","neither",88,95],["G1063","indeed",96,102],["G1410","can be",103,109]]},"8:8":{"text":"So then they that are in the flesh cannot please God.","words":[["G1161","So then",0,7],["G5607","they that are",8,21],["G1722","in",22,24],["G4561","the flesh",25,34],["G3756","cannot",35,41],["G1410","cannot",35,41],["G0700","please",42,48],["G2316","God",49,52]]},"8:9":{"text":"But ye are not in the flesh, but in the Spirit, if so be that the Spirit of God dwell in you. Now if any man have not the Spirit of Christ, he is none of his.","words":[["G1161","But",0,3],["G5210","ye",4,6],["G2075","are",7,10],["G3756","not",11,14],["G1722","in",15,17],["G4561","the flesh",18,27],["G0235","but",29,32],["G1722","in",33,35],["G4151","the Spirit",36,46],["G1512","if so be",48,56],["G4151","that the Spirit",57,72],["G2316","of God",73,79],["G3611","dwell",80,85],["G1722","in",86,88],["G5213","you",89,92],["G1161","Now",94,97],["G1536","if any man",98,108],["G2192","have",109,113],["G3756","not",114,117],["G4151","the Spirit",118,128],["G5547","of Christ",129,138],["G3778","he",140,142],["G2076","is",143,145],["G3756","none",146,150],["G0846","of his",151,157]]},"8:10":{"text":"And if Christ be in you, the body is dead because of sin; but the Spirit is life because of righteousness.","words":[["G1161","And",0,3],["G1487","if",4,6],["G5547","Christ",7,13],["G1722","be in",14,19],["G5213","you",20,23],["G4983","the body",25,33],["G3303","the body",25,33],["G3498","is dead",34,41],["G1223","because",42,49],["G0266","of sin",50,56],["G1161","but",58,61],["G4151","the Spirit",62,72],["G2222","is life",73,80],["G1223","because",81,88],["G1343","of righteousness",89,105]]},"8:11":{"text":"But if the Spirit of him that raised up Jesus from the dead dwell in you, he that raised up Christ from the dead shall also quicken your mortal bodies by his Spirit that dwelleth in you.","words":[["G1161","But",0,3],["G1487","if",4,6],["G4151","the Spirit",7,17],["G1453","of him that raised up",18,39],["G2424","Jesus",40,45],["G1537","from",46,50],["G3498","the dead",51,59],["G3611","dwell",60,65],["G1722","in",66,68],["G5213","you",69,72],["G1453","he that raised up",74,91],["G5547","Christ",92,98],["G1537","from",99,103],["G3498","the dead",104,112],["G2227","shall",113,118],["G2532","also",119,123],["G2227","quicken",124,131],["G5216","your",132,136],["G2349","mortal",137,143],["G4983","bodies",144,150],["G1223","by",151,153],["G0846","his",154,157],["G4151","Spirit",158,164],["G1774","that dwelleth",165,178],["G1774","that dwelleth",165,178],["G1722","in",179,181],["G5213","you",182,185]]},"8:12":{"text":"Therefore, brethren, we are debtors, not to the flesh, to live after the flesh.","words":[["G0686","Therefore",0,9],["G3767","Therefore",0,9],["G0080","brethren",11,19],["G2070","we are",21,27],["G3781","debtors",28,35],["G3756","not",37,40],["G4561","to the flesh",41,53],["G2198","to live",55,62],["G2596","after",63,68],["G4561","the flesh",69,78]]},"8:13":{"text":"For if ye live after the flesh, ye shall die: but if ye through the Spirit do mortify the deeds of the body, ye shall live.","words":[["G1063","For",0,3],["G1487","if",4,6],["G2198","ye live",7,14],["G2596","after",15,20],["G4561","the flesh",21,30],["G3195","ye shall",32,40],["G0599","die",41,44],["G1161","but",46,49],["G1487","if",50,52],["G2289","ye",53,55],["G4151","through the Spirit",56,74],["G2289","do mortify",75,85],["G4234","the deeds",86,95],["G4983","of the body",96,107],["G2198","ye shall live",109,122]]},"8:14":{"text":"For as many as are led by the Spirit of God, they are the sons of God.","words":[["G1063","For",0,3],["G3745","as many as",4,14],["G0071","are led",15,22],["G4151","by the Spirit",23,36],["G2316","of God",37,43],["G3778","they",45,49],["G1526","are",50,53],["G5207","the sons",54,62],["G2316","of God",63,69]]},"8:15":{"text":"For ye have not received the spirit of bondage again to fear; but ye have received the Spirit of adoption, whereby we cry, Abba, Father.","words":[["G1063","For",0,3],["G2983","ye have",4,11],["G3756","not",12,15],["G2983","received",16,24],["G4151","the spirit",25,35],["G1397","of bondage",36,46],["G3825","again",47,52],["G1519","to",53,55],["G5401","fear",56,60],["G0235","but",62,65],["G2983","ye have received",66,82],["G4151","the Spirit",83,93],["G5206","of adoption",94,105],["G1722","whereby",107,114],["G3739","whereby",107,114],["G2896","we cry",115,121],["G0005","Abba",123,127],["G3962","Father",129,135]]},"8:16":{"text":"The Spirit itself beareth witness with our spirit, that we are the children of God:","words":[["G4151","The Spirit",0,10],["G0846","itself",11,17],["G4828","beareth witness",18,33],["G2257","with our",34,42],["G4151","spirit",43,49],["G3754","that",51,55],["G2070","we are",56,62],["G5043","the children",63,75],["G2316","of God",76,82]]},"8:17":{"text":"And if children, then heirs; heirs of God, and joint-heirs with Christ; if so be that we suffer with him, that we may be also glorified together.","words":[["G1161","And",0,3],["G1487","if",4,6],["G5043","children",7,15],["G2532","then",17,21],["G2818","heirs",22,27],["G2818","heirs",29,34],["G3303","of God",35,41],["G2316","of God",35,41],["G1161","and",43,46],["G4789","joint-heirs",47,58],["G5547","with Christ",59,70],["G1512","if so be",72,80],["G4841","that we suffer with",81,100],["G2443","him, that",101,110],["G4888","we may be",111,120],["G2532","also",121,125],["G4888","glorified together",126,144]]},"8:18":{"text":"For I reckon that the sufferings of this present time are not worthy to be compared with the glory which shall be revealed in us.","words":[["G1063","For",0,3],["G3049","I reckon",4,12],["G3754","that",13,17],["G3804","the sufferings",18,32],["G3568","of this present",33,48],["G2540","time",49,53],["G3756","are not",54,61],["G0514","worthy",62,68],["G4314","to be compared with",69,88],["G1391","the glory",89,98],["G3195","which shall",99,110],["G0601","be revealed",111,122],["G1519","in",123,125],["G2248","us",126,128]]},"8:19":{"text":"For the earnest expectation of the creature waiteth for the manifestation of the sons of God.","words":[["G1063","For",0,3],["G0603","the earnest expectation",4,27],["G2937","of the creature",28,43],["G0553","waiteth",44,51],["G0602","for the manifestation",52,73],["G5207","of the sons",74,85],["G2316","of God",86,92]]},"8:20":{"text":"For the creature was made subject to vanity, not willingly, but by reason of him who hath subjected the same in hope,","words":[["G1063","For",0,3],["G2937","the creature",4,16],["G5293","was made subject",17,33],["G3153","to vanity",34,43],["G3756","not",45,48],["G1635","willingly",49,58],["G0235","but",60,63],["G1223","by reason",64,73],["G5293","of him who hath subjected",74,99],["G1909","the same in",100,111],["G1680","hope",112,116]]},"8:21":{"text":"Because the creature itself also shall be delivered from the bondage of corruption into the glorious liberty of the children of God.","words":[["G3754","Because",0,7],["G2937","the creature",8,20],["G0846","itself",21,27],["G2532","also",28,32],["G1659","shall be delivered",33,51],["G0575","from",52,56],["G1397","the bondage",57,68],["G5356","of corruption",69,82],["G1519","into",83,87],["G1391","the glorious",88,100],["G1657","liberty",101,108],["G5043","of the children",109,124],["G2316","of God",125,131]]},"8:22":{"text":"For we know that the whole creation groaneth and travaileth in pain together until now.","words":[["G1063","For",0,3],["G1492","we know",4,11],["G3754","that",12,16],["G3956","the whole",17,26],["G2937","creation",27,35],["G4959","groaneth",36,44],["G2532","and",45,48],["G4944","travaileth in pain together",49,76],["G0891","until",77,82],["G3568","now",83,86]]},"8:23":{"text":"And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within ourselves, waiting for the adoption, to wit, the redemption of our body.","words":[["G1161","And",0,3],["G3756","not",4,7],["G3440","only",8,12],["G0235","they, but",13,22],["G0846","ourselves",23,32],["G2532","also",33,37],["G2192","which have",39,49],["G0536","the firstfruits",50,65],["G4151","of the Spirit",66,79],["G2532","even",81,85],["G2249","we",86,88],["G0846","ourselves",89,98],["G4727","groan",99,104],["G1722","within",105,111],["G1438","ourselves",112,121],["G0553","waiting",123,130],["G5206","for the adoption",131,147],["G0629","to wit, the redemption",149,171],["G2257","of our",172,178],["G4983","body",179,183]]},"8:24":{"text":"For we are saved by hope: but hope that is seen is not hope: for what a man seeth, why doth he yet hope for?","words":[["G1063","For",0,3],["G4982","we are saved",4,16],["G1680","by hope",17,24],["G1161","but",26,29],["G1680","hope",30,34],["G0991","that is seen",35,47],["G2076","is",48,50],["G3756","not",51,54],["G1680","hope",55,59],["G1063","for",61,64],["G3739","what",65,69],["G5100","a man",70,75],["G0991","seeth",76,81],["G5101","why",83,86],["G1679","doth he",87,94],["G2532","yet",95,98],["G1679","hope for",99,107]]},"8:25":{"text":"But if we hope for that we see not, then do we with patience wait for it.","words":[["G1161","But",0,3],["G1487","if",4,6],["G1679","we hope",7,14],["G3739","for that",15,23],["G0991","we see",24,30],["G3756","not",31,34],["G0553","then do we",36,46],["G1223","with",47,51],["G5281","patience",52,60],["G0553","wait for",61,69]]},"8:26":{"text":"Likewise the Spirit also helpeth our infirmities: for we know not what we should pray for as we ought: but the Spirit itself maketh intercession for us with groanings which cannot be uttered.","words":[["G1161","",-1,-1],["G5615","Likewise",0,8],["G4151","the Spirit",9,19],["G2532","also",20,24],["G4878","helpeth",25,32],["G2257","our",33,36],["G0769","infirmities",37,48],["G1063","for",50,53],["G1492","we know",54,61],["G3756","not",62,65],["G5101","what",66,70],["G4336","we should pray for",71,89],["G2526","as",90,92],["G1163","we ought",93,101],["G0235","but",103,106],["G4151","the Spirit",107,117],["G0846","itself",118,124],["G5241","maketh intercession",125,144],["G5228","for",145,148],["G2257","us",149,151],["G4726","with groanings",152,166],["G0215","which cannot be uttered",167,190]]},"8:27":{"text":"And he that searcheth the hearts knoweth what is the mind of the Spirit, because he maketh intercession for the saints according to the will of God.","words":[["G1161","And",0,3],["G2045","he that searcheth",4,21],["G2588","the hearts",22,32],["G1492","knoweth",33,40],["G5101","what",41,45],["G5427","is the mind",46,57],["G4151","of the Spirit",58,71],["G3754","because",73,80],["G1793","he maketh intercession",81,103],["G5228","for",104,107],["G0040","the saints",108,118],["G2596","according",119,128],["G2316","to the will of God",129,147]]},"8:28":{"text":"And we know that all things work together for good to them that love God, to them who are the called according to his purpose.","words":[["G1161","And",0,3],["G1492","we know",4,11],["G3956","that all things",12,27],["G4903","work together",28,41],["G1519","for",42,45],["G0018","good",46,50],["G3754","to them that",51,63],["G0025","love",64,68],["G2316","God",69,72],["G5607","to them who are",74,89],["G2822","the called",90,100],["G2596","according",101,110],["G4286","to his purpose",111,125]]},"8:29":{"text":"For whom he did foreknow, he also did predestinate to be conformed to the image of his Son, that he might be the firstborn among many brethren.","words":[["G3754","For",0,3],["G3739","whom",4,8],["G4267","he did foreknow",9,24],["G4309","he",26,28],["G2532","also",29,33],["G4309","did predestinate",34,50],["G4832","to be conformed",51,66],["G1504","to the image",67,79],["G0846","of his",80,86],["G5207","Son",87,90],["G1519","that",92,96],["G0846","he",97,99],["G1511","might be",100,108],["G4416","the firstborn",109,122],["G1722","among",123,128],["G4183","many",129,133],["G0080","brethren",134,142]]},"8:30":{"text":"Moreover whom he did predestinate, them he also called: and whom he called, them he also justified: and whom he justified, them he also glorified.","words":[["G1161","Moreover",0,8],["G3739","whom",9,13],["G4309","he did predestinate",14,33],["G5128","them",35,39],["G2564","he",40,42],["G2532","also",43,47],["G2564","called",48,54],["G2532","and",56,59],["G3739","whom",60,64],["G2564","he called",65,74],["G5128","them",76,80],["G1344","he",81,83],["G2532","also",84,88],["G1344","justified",89,98],["G1161","and",100,103],["G3739","whom",104,108],["G1344","he justified",109,121],["G5128","them",123,127],["G1392","he",128,130],["G2532","also",131,135],["G1392","glorified",136,145]]},"8:31":{"text":"What shall we then say to these things? If God be for us, who can be against us?","words":[["G5101","What",0,4],["G2046","shall we",5,13],["G3767","then",14,18],["G2046","say",19,22],["G4314","to",23,25],["G5023","these things",26,38],["G1487","If",40,42],["G2316","God",43,46],["G5228","be for",47,53],["G2257","us",54,56],["G5101","who",58,61],["G2596","can be against",62,76],["G2257","us",77,79]]},"8:32":{"text":"He that spared not his own Son, but delivered him up for us all, how shall he not with him also freely give us all things?","words":[["G3739","He that",0,7],["G1065","He that",0,7],["G5339","spared",8,14],["G3756","not",15,18],["G2398","his own",19,26],["G5207","Son",27,30],["G0235","but",32,35],["G3860","delivered",36,45],["G0846","him",46,49],["G3860","up",50,52],["G5228","for",53,56],["G2257","us",57,59],["G3956","all",60,63],["G4459","how",65,68],["G5483","shall he",69,77],["G3780","not",78,81],["G4862","with",82,86],["G0846","him",87,90],["G2532","also",91,95],["G5483","freely give",96,107],["G2254","us",108,110],["G3956","all things",111,121]]},"8:33":{"text":"Who shall lay any thing to the charge of God's elect? It is God that justifieth.","words":[["G5101","Who",0,3],["G1458","shall lay any thing",4,23],["G2596","to the charge",24,37],["G2316","of God's",38,46],["G1588","elect",47,52],["G2316","It is God",54,63],["G1344","that justifieth",64,79]]},"8:34":{"text":"Who is he that condemneth? It is Christ that died, yea rather, that is risen again, who is even at the right hand of God, who also maketh intercession for us.","words":[["G5101","Who",0,3],["G2632","is he that condemneth",4,25],["G5547","It is Christ",27,39],["G0599","that died",40,49],["G1161","yea",51,54],["G3123","rather",55,61],["G2532","rather",55,61],["G1453","that is risen again",63,82],["G3739","who",84,87],["G2076","is",88,90],["G2532","even",91,95],["G1722","at",96,98],["G1188","the right hand",99,113],["G2316","of God",114,120],["G3739","who",122,125],["G2532","also",126,130],["G1793","maketh intercession",131,150],["G5228","for",151,154],["G2257","us",155,157]]},"8:35":{"text":"Who shall separate us from the love of Christ? shall tribulation, or distress, or persecution, or famine, or nakedness, or peril, or sword?","words":[["G5101","Who",0,3],["G5563","shall separate",4,18],["G2248","us",19,21],["G0575","from",22,26],["G0026","the love",27,35],["G5547","of Christ",36,45],["G2347","shall tribulation",47,64],["G2228","or",66,68],["G4730","distress",69,77],["G2228","or",79,81],["G1375","persecution",82,93],["G2228","or",95,97],["G3042","famine",98,104],["G2228","or",106,108],["G1132","nakedness",109,118],["G2228","or",120,122],["G2794","peril",123,128],["G2228","or",130,132],["G3162","sword",133,138]]},"8:36":{"text":"As it is written, For thy sake we are killed all the day long; we are accounted as sheep for the slaughter.","words":[["G2531","As",0,2],["G1125","it is written",3,16],["G3754","",-1,-1],["G4675","For thy",18,25],["G1752","sake",26,30],["G2289","we are killed",31,44],["G3650","all",45,48],["G2250","the day long",49,61],["G3049","we are accounted",63,79],["G5613","as",80,82],["G4263","sheep",83,88],["G4967","for the slaughter",89,106]]},"8:37":{"text":"Nay, in all these things we are more than conquerors through him that loved us.","words":[["G0235","Nay",0,3],["G1722","in",5,7],["G3956","all",8,11],["G5125","these things",12,24],["G5245","we are more than conquerors",25,52],["G1223","through",53,60],["G0025","him that loved",61,75],["G2248","us",76,78]]},"8:38":{"text":"For I am persuaded, that neither death, nor life, nor angels, nor principalities, nor powers, nor things present, nor things to come,","words":[["G1063","For",0,3],["G3982","I am persuaded",4,18],["G3754","that",20,24],["G3777","neither",25,32],["G2288","death",33,38],["G3777","nor",40,43],["G2222","life",44,48],["G3777","nor",50,53],["G0032","angels",54,60],["G3777","nor",62,65],["G0746","principalities",66,80],["G3777","nor",82,85],["G1411","powers",86,92],["G3777","nor",94,97],["G1764","things present",98,112],["G3777","nor",114,117],["G3195","things to come",118,132]]},"8:39":{"text":"Nor height, nor depth, nor any other creature, shall be able to separate us from the love of God, which is in Christ Jesus our Lord.","words":[["G3777","Nor",0,3],["G5313","height",4,10],["G3777","nor",12,15],["G0899","depth",16,21],["G3777","nor",23,26],["G5100","any",27,30],["G2087","other",31,36],["G2937","creature",37,45],["G1410","shall be able",47,60],["G5563","to separate",61,72],["G2248","us",73,75],["G0575","from",76,80],["G0026","the love",81,89],["G2316","of God",90,96],["G1722","which is in",98,109],["G5547","Christ",110,116],["G2424","Jesus",117,122],["G2257","our",123,126],["G2962","Lord",127,131]]},"9:1":{"text":"I say the truth in Christ, I lie not, my conscience also bearing me witness in the Holy Ghost,","words":[["G3004","I say",0,5],["G0225","the truth",6,15],["G1722","in",16,18],["G5547","Christ",19,25],["G5574","I lie",27,32],["G3756","not",33,36],["G3450","my",38,40],["G4893","conscience",41,51],["G4828","also bearing",52,64],["G3427","me",65,67],["G4828","witness",68,75],["G1722","in",76,78],["G0040","the Holy",79,87],["G4151","Ghost",88,93]]},"9:2":{"text":"That I have great heaviness and continual sorrow in my heart.","words":[["G3754","That",0,4],["G3427","I",5,6],["G2076","have",7,11],["G3173","great",12,17],["G3077","heaviness",18,27],["G2532","and",28,31],["G0088","continual",32,41],["G3601","sorrow in",42,51],["G3450","my",52,54],["G2588","heart",55,60]]},"9:3":{"text":"For I could wish that myself were accursed from Christ for my brethren, my kinsmen according to the flesh:","words":[["G1063","For",0,3],["G1473","I",4,5],["G2172","could wish",6,16],["G0846","that myself",17,28],["G1511","were",29,33],["G0331","accursed",34,42],["G0575","from",43,47],["G5547","Christ",48,54],["G5228","for",55,58],["G3450","my",59,61],["G0080","brethren",62,70],["G3450","my",72,74],["G4773","kinsmen",75,82],["G2596","according",83,92],["G4561","to the flesh",93,105]]},"9:4":{"text":"Who are Israelites; to whom pertaineth the adoption, and the glory, and the covenants, and the giving of the law, and the service of God, and the promises;","words":[["G3748","Who",0,3],["G1526","are",4,7],["G2475","Israelites",8,18],["G3739","to whom",20,27],["G5206","pertaineth the adoption",28,51],["G2532","and",53,56],["G1391","the glory",57,66],["G2532","and",68,71],["G1242","the covenants",72,85],["G2532","and",87,90],["G3548","the giving of the law",91,112],["G2532","and",114,117],["G2999","the service",118,129],["G2532","of God, and",130,141],["G1860","the promises",142,154]]},"9:5":{"text":"Whose are the fathers, and of whom as concerning the flesh Christ came, who is over all, God blessed for ever. Amen.","words":[["G3739","Whose",0,5],["G3962","are the fathers",6,21],["G2532","and",23,26],["G1537","of",27,29],["G3739","whom",30,34],["G2596","as concerning",35,48],["G4561","the flesh",49,58],["G5547","Christ",59,65],["G5607","came, who",66,75],["G1909","is over",76,83],["G3956","all",84,87],["G2316","God",89,92],["G2128","blessed",93,100],["G1519","for",101,104],["G0165","ever",105,109],["G0281","Amen",111,115]]},"9:6":{"text":"Not as though the word of God hath taken none effect. For they are not all Israel, which are of Israel:","words":[["G3756","Not",0,3],["G3634","as",4,6],["G1161","though",7,13],["G3754","though",7,13],["G3056","the word",14,22],["G2316","of God",23,29],["G1601","hath taken none effect",30,52],["G1063","For",54,57],["G3756","they are not",58,70],["G3956","all",71,74],["G1537","all",71,74],["G2474","Israel",75,81],["G3588","which",83,88],["G3778","which",83,88],["G2474","are of Israel",89,102]]},"9:7":{"text":"Neither, because they are the seed of Abraham, are they all children: but, In Isaac shall thy seed be called.","words":[["G3761","Neither",0,7],["G3754","because",9,16],["G1526","they are",17,25],["G4690","the seed",26,34],["G0011","of Abraham",35,45],["G3956","are they all",47,59],["G5043","children",60,68],["G0235","but",70,73],["G1722","In",75,77],["G2464","Isaac",78,83],["G2564","shall",84,89],["G4671","thy",90,93],["G4690","seed",94,98],["G2564","be called",99,108]]},"9:8":{"text":"That is, They which are the children of the flesh, these are not the children of God: but the children of the promise are counted for the seed.","words":[["G5123","That is",0,7],["G5043","They which are the children",9,36],["G4561","of the flesh",37,49],["G5023","these",51,56],["G3756","are not",57,64],["G5043","the children",65,77],["G2316","of God",78,84],["G0235","but",86,89],["G5043","the children",90,102],["G1860","of the promise",103,117],["G3049","are counted",118,129],["G1519","for",130,133],["G4690","the seed",134,142]]},"9:9":{"text":"For this is the word of promise, At this time will I come, and Sarah shall have a son.","words":[["G1063","For",0,3],["G3778","this",4,8],["G3056","is the word",9,20],["G1860","of promise",21,31],["G2596","At",33,35],["G5126","this",36,40],["G2540","time",41,45],["G2064","will I come",46,57],["G2532","and",59,62],["G4564","Sarah",63,68],["G2071","shall have",69,79],["G5207","a son",80,85]]},"9:10":{"text":"And not only this; but when Rebecca also had conceived by one, even by our father Isaac;","words":[["G1161","And",0,3],["G3756","not",4,7],["G3440","only",8,12],["G0235","this; but",13,22],["G4479","when Rebecca",23,35],["G2532","also",36,40],["G2845","had conceived",41,54],["G1537","by",55,57],["G1520","one",58,61],["G2192","one",58,61],["G2257","even by our",63,74],["G3962","father",75,81],["G2464","Isaac",82,87]]},"9:11":{"text":"(For the children being not yet born, neither having done any good or evil, that the purpose of God according to election might stand, not of works, but of him that calleth;)","words":[["G1063","(For",0,4],["G1080","the children being",5,23],["G3380","not yet",24,31],["G1080","born",32,36],["G3366","neither",38,45],["G4238","having done",46,57],["G5100","any",58,61],["G0018","good",62,66],["G2228","or",67,69],["G2556","evil",70,74],["G2443","that",76,80],["G4286","the purpose",81,92],["G2316","of God",93,99],["G2596","according",100,109],["G1589","to election",110,121],["G3306","might stand",122,133],["G3756","not",135,138],["G1537","of",139,141],["G2041","works",142,147],["G0235","but",149,152],["G1537","of",153,155],["G2564","him that calleth",156,172]]},"9:12":{"text":"It was said unto her, The elder shall serve the younger.","words":[["G3754","",-1,-1],["G4483","It was said",0,11],["G0846","unto her",12,20],["G3187","The elder",22,31],["G1398","shall serve",32,43],["G1640","the younger",44,55]]},"9:13":{"text":"As it is written, Jacob have I loved, but Esau have I hated.","words":[["G2531","As",0,2],["G1125","it is written",3,16],["G2384","Jacob",18,23],["G0025","have I loved",24,36],["G1161","but",38,41],["G2269","Esau",42,46],["G3404","have I hated",47,59]]},"9:14":{"text":"What shall we say then? Is there unrighteousness with God? God forbid.","words":[["G5101","What",0,4],["G2046","shall we say",5,17],["G3767","then",18,22],["G3361","",-1,-1],["G0093","Is there unrighteousness",24,48],["G3844","with",49,53],["G2316","God",54,57],["G3361","God forbid",59,69],["G1096","God forbid",59,69]]},"9:15":{"text":"For he saith to Moses, I will have mercy on whom I will have mercy, and I will have compassion on whom I will have compassion.","words":[["G1063","For",0,3],["G3004","he saith",4,12],["G3475","to Moses",13,21],["G1653","I will have mercy on",23,43],["G3739","whom",44,48],["G0302","whom",44,48],["G1653","I will have mercy",49,66],["G2532","and",68,71],["G3627","I will have compassion",72,94],["G3739","on whom",95,102],["G0302","on whom",95,102],["G3627","I will have compassion",103,125]]},"9:16":{"text":"So then it is not of him that willeth, nor of him that runneth, but of God that sheweth mercy.","words":[["G0686","So",0,2],["G3767","then",3,7],["G3756","it is not",8,17],["G2309","of him that willeth",18,37],["G3761","nor",39,42],["G5143","of him that runneth",43,62],["G0235","but",64,67],["G2316","of God",68,74],["G1653","that sheweth mercy",75,93]]},"9:17":{"text":"For the scripture saith unto Pharaoh, Even for this same purpose have I raised thee up, that I might shew my power in thee, and that my name might be declared throughout all the earth.","words":[["G1063","For",0,3],["G1124","the scripture",4,17],["G3004","saith",18,23],["G5328","unto Pharaoh",24,36],["G3754","Even for",38,46],["G1519","Even for",38,46],["G5124","this",47,51],["G0846","same purpose",52,64],["G1825","have I raised",65,78],["G4571","thee",79,83],["G1825","up",84,86],["G3704","that",88,92],["G1731","I might shew",93,105],["G3450","my",106,108],["G1411","power",109,114],["G1722","in",115,117],["G4671","thee",118,122],["G2532","and",124,127],["G3704","that",128,132],["G3450","my",133,135],["G3686","name",136,140],["G1229","might be declared",141,158],["G1722","throughout",159,169],["G3956","all",170,173],["G1093","the earth",174,183]]},"9:18":{"text":"Therefore hath he mercy on whom he will have mercy, and whom he will he hardeneth.","words":[["G0686","Therefore",0,9],["G3767","Therefore",0,9],["G1653","hath he mercy",10,23],["G3739","on whom",24,31],["G2309","he will",32,39],["G1161","have mercy, and",40,55],["G3739","whom",56,60],["G2309","he will",61,68],["G4645","he hardeneth",69,81]]},"9:19":{"text":"Thou wilt say then unto me, Why doth he yet find fault? For who hath resisted his will?","words":[["G2046","Thou wilt say",0,13],["G3767","then",14,18],["G3427","unto me",19,26],["G5101","Why",28,31],["G2089","doth he yet",32,43],["G3201","find fault",44,54],["G1063","For",56,59],["G5101","who",60,63],["G0436","hath resisted",64,77],["G0846","his",78,81],["G1013","will",82,86]]},"9:20":{"text":"Nay but, O man, who art thou that repliest against God? Shall the thing formed say to him that formed it, Why hast thou made me thus?","words":[["G3304","Nay but",0,7],["G5599","O",9,10],["G0444","man",11,14],["G5101","who",16,19],["G1488","art",20,23],["G4771","thou",24,28],["G0470","that repliest against",29,50],["G2316","God",51,54],["G3361","",-1,-1],["G2046","Shall",56,61],["G4110","the thing formed",62,78],["G2046","say",79,82],["G4111","to him that formed",83,101],["G5101","it, Why",102,109],["G4160","hast thou made",110,124],["G3165","me",125,127],["G3779","thus",128,132]]},"9:21":{"text":"Hath not the potter power over the clay, of the same lump to make one vessel unto honour, and another unto dishonour?","words":[["G2228","",-1,-1],["G2192","Hath",0,4],["G3756","not",5,8],["G2763","the potter",9,19],["G1849","power",20,25],["G4081","over the clay",26,39],["G1537","of",41,43],["G0846","the same",44,52],["G5445","lump",53,57],["G3739","to",58,60],["G3303","to",58,60],["G4160","make",61,65],["G4632","one vessel",66,76],["G1519","unto",77,81],["G5092","honour",82,88],["G1161","and",90,93],["G3739","another",94,101],["G1519","unto",102,106],["G0819","dishonour",107,116]]},"9:22":{"text":"What if God, willing to shew his wrath, and to make his power known, endured with much longsuffering the vessels of wrath fitted to destruction:","words":[["G1487","What if",0,7],["G1161","What if",0,7],["G2316","God",8,11],["G2309","willing",13,20],["G1731","to shew",21,28],["G3709","his wrath",29,38],["G2532","and",40,43],["G1107","to make",44,51],["G0846","his",52,55],["G1415","power",56,61],["G1107","known",62,67],["G5342","endured",69,76],["G1722","with",77,81],["G4183","much",82,86],["G3115","longsuffering",87,100],["G4632","the vessels",101,112],["G3709","of wrath",113,121],["G2675","fitted",122,128],["G1519","to",129,131],["G0684","destruction",132,143]]},"9:23":{"text":"And that he might make known the riches of his glory on the vessels of mercy, which he had afore prepared unto glory,","words":[["G2532","And",0,3],["G2443","that",4,8],["G1107","he might make known",9,28],["G4149","the riches",29,39],["G0846","of his",40,46],["G1391","glory",47,52],["G1909","on",53,55],["G4632","the vessels",56,67],["G1656","of mercy",68,76],["G3739","which",78,83],["G4282","he had afore prepared",84,105],["G1519","unto",106,110],["G1391","glory",111,116]]},"9:24":{"text":"Even us, whom he hath called, not of the Jews only, but also of the Gentiles?","words":[["G3739","",-1,-1],["G2532","Even",0,4],["G2248","us",5,7],["G3739","whom",9,13],["G2564","he hath called",14,28],["G3756","not",30,33],["G1537","of",34,36],["G2453","the Jews",37,45],["G3440","only",46,50],["G0235","but",52,55],["G2532","also",56,60],["G1537","of",61,63],["G1484","the Gentiles",64,76]]},"9:25":{"text":"As he saith also in Osee, I will call them my people, which were not my people; and her beloved, which was not beloved.","words":[["G3004","As he saith",0,11],["G2532","also",12,16],["G1722","in",17,19],["G5617","Osee",20,24],["G2564","I will call",26,37],["G3450","them my",38,45],["G2992","people",46,52],["G3756","which were not",54,68],["G3450","my",69,71],["G2992","people",72,78],["G2532","and",80,83],["G0025","her beloved",84,95],["G0025","which was",97,106],["G3756","not",107,110],["G0025","beloved",111,118]]},"9:26":{"text":"And it shall come to pass, that in the place where it was said unto them, Ye are not my people; there shall they be called the children of the living God.","words":[["G2532","And",0,3],["G2071","it shall come to pass",4,25],["G1722","that in",27,34],["G5117","the place",35,44],["G3757","where",45,50],["G3739","where",45,50],["G4483","it was said",51,62],["G0846","unto them",63,72],["G5210","Ye",74,76],["G3756","are not",77,84],["G3450","my",85,87],["G2992","people",88,94],["G1563","there",96,101],["G2564","shall they be called",102,122],["G5207","the children",123,135],["G2198","of the living",136,149],["G2316","God",150,153]]},"9:27":{"text":"Esaias also crieth concerning Israel, Though the number of the children of Israel be as the sand of the sea, a remnant shall be saved:","words":[["G2268","Esaias",0,6],["G1161","also",7,11],["G2896","crieth",12,18],["G5228","concerning",19,29],["G2474","Israel",30,36],["G1437","Though",38,44],["G0706","the number",45,55],["G5207","of the children",56,71],["G2474","of Israel",72,81],["G5600","be",82,84],["G5613","as",85,87],["G0285","the sand",88,96],["G2281","of the sea",97,107],["G2640","a remnant",109,118],["G4982","shall be saved",119,133]]},"9:28":{"text":"For he will finish the work, and cut it short in righteousness: because a short work will the Lord make upon the earth.","words":[["G1063","For",0,3],["G4931","he will finish",4,18],["G3056","the work",19,27],["G2532","and",29,32],["G4932","cut it short",33,45],["G1722","in",46,48],["G1343","righteousness",49,62],["G3754","because",64,71],["G4932","a short",72,79],["G3056","work",80,84],["G4160","will",85,89],["G2962","the Lord",90,98],["G4160","make",99,103],["G1909","upon",104,108],["G1093","the earth",109,118]]},"9:29":{"text":"And as Esaias said before, Except the Lord of Sabaoth had left us a seed, we had been as Sodoma, and been made like unto Gomorrha.","words":[["G2532","And",0,3],["G2531","as",4,6],["G2268","Esaias",7,13],["G4280","said before",14,25],["G1508","Except",27,33],["G2962","the Lord",34,42],["G4519","of Sabaoth",43,53],["G1459","had left",54,62],["G2254","us",63,65],["G4690","a seed",66,72],["G0302","we had been",74,85],["G1096","we had been",74,85],["G5613","as",86,88],["G4670","Sodoma",89,95],["G2532","and",97,100],["G0302","been made like",101,115],["G3666","been made like",101,115],["G5613","unto",116,120],["G1116","Gomorrha",121,129]]},"9:30":{"text":"What shall we say then? That the Gentiles, which followed not after righteousness, have attained to righteousness, even the righteousness which is of faith.","words":[["G5101","What",0,4],["G2046","shall we say",5,17],["G3767","then",18,22],["G3754","That",24,28],["G1484","the Gentiles",29,41],["G3588","which",43,48],["G1377","followed",49,57],["G3361","not",58,61],["G1343","after righteousness",62,81],["G2638","have attained",83,96],["G1343","to righteousness",97,113],["G1161","even",115,119],["G1343","the righteousness",120,137],["G3588","which",138,143],["G1537","is of",144,149],["G4102","faith",150,155]]},"9:31":{"text":"But Israel, which followed after the law of righteousness, hath not attained to the law of righteousness.","words":[["G1161","But",0,3],["G2474","Israel",4,10],["G1377","which followed",12,26],["G3551","after the law",27,40],["G1343","of righteousness",41,57],["G5348","hath",59,63],["G3756","not",64,67],["G5348","attained",68,76],["G1519","to",77,79],["G3551","the law",80,87],["G1343","of righteousness",88,104]]},"9:32":{"text":"Wherefore? Because they sought it not by faith, but as it were by the works of the law. For they stumbled at that stumblingstone;","words":[["G1302","Wherefore",0,9],["G3754","Because",11,18],["G3756","they sought it not",19,37],["G1537","by",38,40],["G4102","faith",41,46],["G0235","but",48,51],["G5613","as",52,54],["G1537","it were by",55,65],["G2041","the works",66,75],["G3551","of the law",76,86],["G1063","For",88,91],["G4350","they stumbled",92,105],["G3037","at that stumblingstone",106,128],["G4348","at that stumblingstone",106,128]]},"9:33":{"text":"As it is written, Behold, I lay in Sion a stumblingstone and rock of offence: and whosoever believeth on him shall not be ashamed.","words":[["G2531","As",0,2],["G1125","it is written",3,16],["G2400","Behold",18,24],["G5087","I lay",26,31],["G1722","in",32,34],["G4622","Sion",35,39],["G3037","a stumblingstone",40,56],["G4348","a stumblingstone",40,56],["G2532","and",57,60],["G4073","rock",61,65],["G4625","of offence",66,76],["G2532","and",78,81],["G3956","whosoever",82,91],["G4100","believeth",92,101],["G1909","on",102,104],["G0846","him",105,108],["G2617","shall",109,114],["G3756","not",115,118],["G2617","be ashamed",119,129]]},"10:1":{"text":"Brethren, my heart's desire and prayer to God for Israel is, that they might be saved.","words":[["G0080","Brethren",0,8],["G1699","my",10,12],["G2588","heart's",13,20],["G2107","desire",21,27],["G2532","and",28,31],["G1162","prayer",32,38],["G4314","to",39,41],["G2316","God",42,45],["G5228","for",46,49],["G2474","Israel",50,56],["G2076","is",57,59],["G3303","that",61,65],["G1519","that",61,65],["G4991","they might be saved",66,85]]},"10:2":{"text":"For I bear them record that they have a zeal of God, but not according to knowledge.","words":[["G1063","For",0,3],["G3140","I bear",4,10],["G0846","them",11,15],["G3140","record",16,22],["G3754","that",23,27],["G2192","they have",28,37],["G2205","a zeal",38,44],["G2316","of God",45,51],["G0235","but",53,56],["G3756","not",57,60],["G2596","according",61,70],["G1922","to knowledge",71,83]]},"10:3":{"text":"For they being ignorant of God's righteousness, and going about to establish their own righteousness, have not submitted themselves unto the righteousness of God.","words":[["G1063","For",0,3],["G0050","they being ignorant",4,23],["G2316","of God's",24,32],["G1343","righteousness",33,46],["G2532","and",48,51],["G2212","going about",52,63],["G2476","to establish",64,76],["G2398","their own",77,86],["G1343","righteousness",87,100],["G5293","have",102,106],["G3756","not",107,110],["G5293","submitted themselves",111,131],["G1343","unto the righteousness",132,154],["G2316","of God",155,161]]},"10:4":{"text":"For Christ is the end of the law for righteousness to every one that believeth.","words":[["G1063","For",0,3],["G5547","Christ",4,10],["G5056","is the end",11,21],["G3551","of the law",22,32],["G1519","for",33,36],["G1343","righteousness",37,50],["G3956","to every one",51,63],["G4100","that believeth",64,78]]},"10:5":{"text":"For Moses describeth the righteousness which is of the law, That the man which doeth those things shall live by them.","words":[["G1063","For",0,3],["G3475","Moses",4,9],["G1125","describeth",10,20],["G1343","the righteousness",21,38],["G3588","which",39,44],["G1537","is of",45,50],["G3551","the law",51,58],["G3754","That",60,64],["G0444","the man",65,72],["G4160","which doeth",73,84],["G0846","those things",85,97],["G2198","shall live",98,108],["G1722","by",109,111],["G0846","them",112,116]]},"10:6":{"text":"But the righteousness which is of faith speaketh on this wise, Say not in thine heart, Who shall ascend into heaven? (that is, to bring Christ down from above:)","words":[["G1161","But",0,3],["G1343","the righteousness",4,21],["G1537","which is of",22,33],["G4102","faith",34,39],["G3004","speaketh",40,48],["G3779","on this wise",49,61],["G2036","Say",63,66],["G3361","not",67,70],["G1722","in",71,73],["G4675","thine",74,79],["G2588","heart",80,85],["G5101","Who",87,90],["G0305","shall ascend",91,103],["G1519","into",104,108],["G3772","heaven",109,115],["G5123","(that is",117,125],["G2609","to bring",127,135],["G5547","Christ",136,142],["G2609","down",143,147]]},"10:7":{"text":"Or, Who shall descend into the deep? (that is, to bring up Christ again from the dead.)","words":[["G2228","Or",0,2],["G5101","Who",4,7],["G2597","shall descend",8,21],["G1519","into",22,26],["G0012","the deep",27,35],["G5123","(that is",37,45],["G0321","to bring up",47,58],["G5547","Christ",59,65],["G0321","again",66,71],["G1537","from",72,76],["G3498","the dead",77,85]]},"10:8":{"text":"But what saith it? The word is nigh thee, even in thy mouth, and in thy heart: that is, the word of faith, which we preach;","words":[["G0235","But",0,3],["G5101","what",4,8],["G3004","saith it",9,17],["G4487","The word",19,27],["G2076","is",28,30],["G1451","nigh",31,35],["G4675","thee",36,40],["G1722","even in",42,49],["G4675","thy",50,53],["G4750","mouth",54,59],["G2532","and",61,64],["G1722","in",65,67],["G4675","thy",68,71],["G2588","heart",72,77],["G5123","that is",79,86],["G4487","the word",88,96],["G4102","of faith",97,105],["G3739","which",107,112],["G2784","we preach",113,122]]},"10:9":{"text":"That if thou shalt confess with thy mouth the Lord Jesus, and shalt believe in thine heart that God hath raised him from the dead, thou shalt be saved.","words":[["G3754","That",0,4],["G1437","if",5,7],["G3670","thou shalt confess",8,26],["G1722","with",27,31],["G4675","thy",32,35],["G4750","mouth",36,41],["G2962","the Lord",42,50],["G2424","Jesus",51,56],["G2532","and",58,61],["G4100","shalt believe",62,75],["G1722","in",76,78],["G4675","thine",79,84],["G2588","heart",85,90],["G3754","that",91,95],["G2316","God",96,99],["G1453","hath raised",100,111],["G0846","him",112,115],["G1537","from",116,120],["G3498","the dead",121,129],["G4982","thou shalt be saved",131,150]]},"10:10":{"text":"For with the heart man believeth unto righteousness; and with the mouth confession is made unto salvation.","words":[["G1063","For",0,3],["G2588","with the heart",4,18],["G4100","man believeth",19,32],["G1519","unto",33,37],["G1343","righteousness",38,51],["G1161","and",53,56],["G4750","with the mouth",57,71],["G3670","confession is made",72,90],["G1519","unto",91,95],["G4991","salvation",96,105]]},"10:11":{"text":"For the scripture saith, Whosoever believeth on him shall not be ashamed.","words":[["G1063","For",0,3],["G1124","the scripture",4,17],["G3004","saith",18,23],["G3956","Whosoever",25,34],["G4100","believeth",35,44],["G1909","on",45,47],["G0846","him",48,51],["G2617","shall",52,57],["G3756","not",58,61],["G2617","be ashamed",62,72]]},"10:12":{"text":"For there is no difference between the Jew and the Greek: for the same Lord over all is rich unto all that call upon him.","words":[["G1063","For",0,3],["G2076","there is",4,12],["G3756","no",13,15],["G1293","difference",16,26],["G5037","between",27,34],["G2453","the Jew",35,42],["G2532","and",43,46],["G1672","the Greek",47,56],["G1063","for",58,61],["G0846","the same",62,70],["G2962","Lord",71,75],["G3956","over all",76,84],["G4147","is rich",85,92],["G1519","unto",93,97],["G3956","all",98,101],["G1941","that call upon",102,116],["G0846","him",117,120]]},"10:13":{"text":"For whosoever shall call upon the name of the Lord shall be saved.","words":[["G3956","For",0,3],["G1063","For",0,3],["G3739","whosoever",4,13],["G0302","whosoever",4,13],["G1941","shall call upon",14,29],["G3686","the name",30,38],["G2962","of the Lord",39,50],["G4982","shall be saved",51,65]]},"10:14":{"text":"How then shall they call on him in whom they have not believed? and how shall they believe in him of whom they have not heard? and how shall they hear without a preacher?","words":[["G4459","How",0,3],["G3767","then",4,8],["G1941","shall they call on",9,27],["G1519","him in",28,34],["G3739","whom",35,39],["G4100","they have",40,49],["G3756","not",50,53],["G4100","believed",54,62],["G1161","and",64,67],["G4459","how",68,71],["G4100","shall they believe in",72,93],["G3739","him of whom",94,105],["G0191","they have",106,115],["G3756","not",116,119],["G0191","heard",120,125],["G1161","and",127,130],["G4459","how",131,134],["G0191","shall they hear",135,150],["G5565","without",151,158],["G2784","a preacher",159,169]]},"10:15":{"text":"And how shall they preach, except they be sent? as it is written, How beautiful are the feet of them that preach the gospel of peace, and bring glad tidings of good things!","words":[["G1161","And",0,3],["G4459","how",4,7],["G2784","shall they preach",8,25],["G3362","except",27,33],["G0649","they be sent",34,46],["G2531","as",48,50],["G1125","it is written",51,64],["G5613","How",66,69],["G5611","beautiful",70,79],["G4228","are the feet of them",80,100],["G2097","that preach the gospel",101,123],["G1515","of peace",124,132],["G2097","and bring glad tidings",134,156],["G0018","of good things",157,171]]},"10:16":{"text":"But they have not all obeyed the gospel. For Esaias saith, Lord, who hath believed our report?","words":[["G0235","But",0,3],["G5219","they have",4,13],["G3756","not",14,17],["G3956","all",18,21],["G5219","obeyed",22,28],["G2098","the gospel",29,39],["G1063","For",41,44],["G2268","Esaias",45,51],["G3004","saith",52,57],["G2962","Lord",59,63],["G5101","who",65,68],["G4100","hath believed",69,82],["G2257","our",83,86],["G0189","report",87,93]]},"10:17":{"text":"So then faith cometh by hearing, and hearing by the word of God.","words":[["G0686","So then",0,7],["G4102","faith",8,13],["G1537","cometh by",14,23],["G0189","hearing",24,31],["G1161","and",33,36],["G0189","hearing",37,44],["G1223","by",45,47],["G4487","the word",48,56],["G2316","of God",57,63]]},"10:18":{"text":"But I say, Have they not heard? Yes verily, their sound went into all the earth, and their words unto the ends of the world.","words":[["G0235","But",0,3],["G3004","I say",4,9],["G0191","Have",11,15],["G3378","they not",16,24],["G0191","heard",25,30],["G3304","Yes verily",32,42],["G0846","their",44,49],["G5353","sound",50,55],["G1831","went",56,60],["G1519","into",61,65],["G3956","all",66,69],["G1093","the earth",70,79],["G2532","and",81,84],["G0846","their",85,90],["G4487","words",91,96],["G1519","unto",97,101],["G4009","the ends",102,110],["G3625","of the world",111,123]]},"10:19":{"text":"But I say, Did not Israel know? First Moses saith, I will provoke you to jealousy by them that are no people, and by a foolish nation I will anger you.","words":[["G0235","But",0,3],["G3004","I say",4,9],["G1097","Did",11,14],["G3378","not",15,18],["G2474","Israel",19,25],["G1097","know",26,30],["G4413","First",32,37],["G3475","Moses",38,43],["G3004","saith",44,49],["G1473","I",51,52],["G3863","will provoke",53,65],["G5209","you",66,69],["G3863","to jealousy",70,81],["G1909","by",82,84],["G3756","them that are no",85,101],["G1484","people",102,108],["G1909","and by",110,116],["G0801","a foolish",117,126],["G1484","nation",127,133],["G3949","I will anger",134,146],["G5209","you",147,150]]},"10:20":{"text":"But Esaias is very bold, and saith, I was found of them that sought me not; I was made manifest unto them that asked not after me.","words":[["G1161","But",0,3],["G2268","Esaias",4,10],["G0662","is very bold",11,23],["G2532","and",25,28],["G3004","saith",29,34],["G2147","I was found",36,47],["G2212","of them that sought",48,67],["G1691","me",68,70],["G3361","not",71,74],["G1096","I was made",76,86],["G1717","manifest",87,95],["G1905","unto them that asked",96,116],["G3361","not",117,120],["G1905","after",121,126],["G1691","me",127,129]]},"10:21":{"text":"But to Israel he saith, All day long I have stretched forth my hands unto a disobedient and gainsaying people.","words":[["G1161","But",0,3],["G4314","to",4,6],["G2474","Israel",7,13],["G3004","he saith",14,22],["G3650","All",24,27],["G2250","day long",28,36],["G1600","I have stretched forth",37,59],["G3450","my",60,62],["G5495","hands",63,68],["G4314","unto",69,73],["G0544","a disobedient",74,87],["G2532","and",88,91],["G0483","gainsaying",92,102],["G2992","people",103,109]]},"11:1":{"text":"I say then, Hath God cast away his people? God forbid. For I also am an Israelite, of the seed of Abraham, of the tribe of Benjamin.","words":[["G3004","I say",0,5],["G3767","then",6,10],["G3361","",-1,-1],["G0683","Hath",12,16],["G2316","God",17,20],["G0683","cast away",21,30],["G0846","his",31,34],["G2992","people",35,41],["G3361","God forbid",43,53],["G1096","God forbid",43,53],["G1063","For",55,58],["G1473","I",59,60],["G2532","also",61,65],["G1510","am",66,68],["G2475","an Israelite",69,81],["G1537","of",83,85],["G4690","the seed",86,94],["G0011","of Abraham",95,105],["G5443","of the tribe",107,119],["G0958","of Benjamin",120,131]]},"11:2":{"text":"God hath not cast away his people which he foreknew. Wot ye not what the scripture saith of Elias? how he maketh intercession to God against Israel, saying,","words":[["G2316","God",0,3],["G0683","hath",4,8],["G3756","not",9,12],["G0683","cast away",13,22],["G0846","his",23,26],["G2992","people",27,33],["G3739","which",34,39],["G4267","he foreknew",40,51],["G2228","",-1,-1],["G1492","Wot ye",53,59],["G3756","not",60,63],["G5101","what",64,68],["G1124","the scripture",69,82],["G3004","saith",83,88],["G1722","of",89,91],["G2243","Elias",92,97],["G5613","how",99,102],["G1793","he maketh intercession",103,125],["G2316","to God",126,132],["G2596","against",133,140],["G2474","Israel",141,147],["G3004","saying",149,155]]},"11:3":{"text":"Lord, they have killed thy prophets, and digged down thine altars; and I am left alone, and they seek my life.","words":[["G2962","Lord",0,4],["G0615","they have killed",6,22],["G4675","thy",23,26],["G4396","prophets",27,35],["G2532","and",37,40],["G2679","digged down",41,52],["G4675","thine",53,58],["G2379","altars",59,65],["G2504","and I",67,72],["G5275","am left",73,80],["G3441","alone",81,86],["G2532","and",88,91],["G2212","they seek",92,101],["G3450","my",102,104],["G5590","life",105,109]]},"11:4":{"text":"But what saith the answer of God unto him? I have reserved to myself seven thousand men, who have not bowed the knee to the image of Baal.","words":[["G0235","But",0,3],["G5101","what",4,8],["G3004","saith",9,14],["G5538","the answer of God",15,32],["G0846","unto him",33,41],["G2641","I have reserved",43,58],["G1683","to myself",59,68],["G2035","seven thousand",69,83],["G0435","men",84,87],["G3748","who",89,92],["G2578","have",93,97],["G3756","not",98,101],["G2578","bowed",102,107],["G1119","the knee",108,116],["G0896","to the image of Baal",117,137]]},"11:5":{"text":"Even so then at this present time also there is a remnant according to the election of grace.","words":[["G3779","Even so",0,7],["G3767","then",8,12],["G1722","at",13,15],["G3568","this present",16,28],["G2540","time",29,33],["G2532","also",34,38],["G1096","there is",39,47],["G3005","a remnant",48,57],["G2596","according",58,67],["G1589","to the election",68,83],["G5485","of grace",84,92]]},"11:6":{"text":"And if by grace, then is it no more of works: otherwise grace is no more grace. But if it be of works, then is it no more grace: otherwise work is no more work.","words":[["G1161","And",0,3],["G1487","if",4,6],["G5485","by grace",7,15],["G2089","then is it no more",17,35],["G3765","then is it no more",17,35],["G1537","of",36,38],["G2041","works",39,44],["G1893","otherwise",46,55],["G5485","grace",56,61],["G1096","is",62,64],["G2089","no more",65,72],["G3765","no more",65,72],["G5485","grace",73,78],["G1161","But",80,83],["G1487","if",84,86],["G1537","it be of",87,95],["G2041","works",96,101],["G2076","then is it",103,113],["G2089","no more",114,121],["G3765","no more",114,121],["G5485","grace",122,127],["G1893","otherwise",129,138],["G2041","work",139,143],["G2076","is",144,146],["G2089","no more",147,154],["G3765","no more",147,154],["G2041","work",155,159]]},"11:7":{"text":"What then? Israel hath not obtained that which he seeketh for; but the election hath obtained it, and the rest were blinded","words":[["G5101","What",0,4],["G3767","then",5,9],["G2474","Israel",11,17],["G2013","hath",18,22],["G3756","not",23,26],["G2013","obtained",27,35],["G5127","that",36,40],["G3739","which",41,46],["G1934","he seeketh for",47,61],["G1161","but",63,66],["G1589","the election",67,79],["G2013","hath obtained it",80,96],["G1161","and",98,101],["G3062","the rest",102,110],["G4456","were blinded",111,123]]},"11:8":{"text":"(According as it is written, God hath given them the spirit of slumber, eyes that they should not see, and ears that they should not hear;) unto this day.","words":[["G2531","(According as",0,13],["G1125","it is written",14,27],["G2316","God",29,32],["G1325","hath given",33,43],["G0846","them",44,48],["G4151","the spirit",49,59],["G2659","of slumber",60,70],["G3788","eyes",72,76],["G0991","that they should",77,93],["G3361","not",94,97],["G0991","see",98,101],["G2532","and",103,106],["G3775","ears",107,111],["G0191","that they should",112,128],["G3361","not",129,132],["G0191","hear",133,137],["G2193",") unto",138,144],["G4594","this",145,149],["G2250","day",150,153]]},"11:9":{"text":"And David saith, Let their table be made a snare, and a trap, and a stumblingblock, and a recompence unto them:","words":[["G2532","And",0,3],["G1138","David",4,9],["G3004","saith",10,15],["G1096","Let",17,20],["G0846","their",21,26],["G5132","table",27,32],["G1096","be made",33,40],["G1519","a snare",41,48],["G3803","a snare",41,48],["G2532","and",50,53],["G1519","a trap",54,60],["G2339","a trap",54,60],["G2532","and",62,65],["G1519","a stumblingblock",66,82],["G4625","a stumblingblock",66,82],["G2532","and",84,87],["G1519","a recompence",88,100],["G0468","a recompence",88,100],["G0846","unto them",101,110]]},"11:10":{"text":"Let their eyes be darkened, that they may not see, and bow down their back alway.","words":[["G4654","Let",0,3],["G0846","their",4,9],["G3788","eyes",10,14],["G4654","be darkened",15,26],["G0991","that they may",28,41],["G3361","not",42,45],["G0991","see",46,49],["G2532","and",51,54],["G4781","bow down",55,63],["G0846","their",64,69],["G3577","back",70,74],["G1275","alway",75,80]]},"11:11":{"text":"I say then, Have they stumbled that they should fall? God forbid: but rather through their fall salvation is come unto the Gentiles, for to provoke them to jealousy.","words":[["G3004","I say",0,5],["G3767","then",6,10],["G3361","",-1,-1],["G4417","Have they stumbled",12,30],["G2443","that",31,35],["G4098","they should fall",36,52],["G3361","God forbid",54,64],["G1096","God forbid",54,64],["G0235","but",66,69],["G0846","rather through their",70,90],["G3900","fall",91,95],["G4991","salvation",96,105],["G1484","is come unto the Gentiles",106,131],["G1519","for to",133,139],["G3863","provoke",140,147],["G0846","them",148,152],["G3863","to jealousy",153,164]]},"11:12":{"text":"Now if the fall of them be the riches of the world, and the diminishing of them the riches of the Gentiles; how much more their fulness?","words":[["G1161","Now",0,3],["G1487","if",4,6],["G3900","the fall",7,15],["G0846","of them",16,23],["G4149","be the riches",24,37],["G2889","of the world",38,50],["G2532","and",52,55],["G2275","the diminishing",56,71],["G0846","of them",72,79],["G4149","the riches",80,90],["G1484","of the Gentiles",91,106],["G4214","how",108,111],["G3123","much more",112,121],["G0846","their",122,127],["G4138","fulness",128,135]]},"11:13":{"text":"For I speak to you Gentiles, inasmuch as I am the apostle of the Gentiles, I magnify mine office:","words":[["G1063","For",0,3],["G3004","I speak",4,11],["G5213","to you",12,18],["G1484","Gentiles",19,27],["G1909","inasmuch as",29,40],["G3745","inasmuch as",29,40],["G3303","inasmuch as",29,40],["G1473","I",41,42],["G1510","am",43,45],["G0652","the apostle",46,57],["G1484","of the Gentiles",58,73],["G1392","I magnify",75,84],["G3450","mine",85,89],["G1248","office",90,96]]},"11:14":{"text":"If by any means I may provoke to emulation them which are my flesh, and might save some of them.","words":[["G1513","If by any means",0,15],["G4458","If by any means",0,15],["G3863","I may provoke to emulation",16,42],["G3450","them which are my",43,60],["G4561","flesh",61,66],["G2532","and",68,71],["G4982","might save",72,82],["G5100","some",83,87],["G1537","of",88,90],["G0846","them",91,95]]},"11:15":{"text":"For if the casting away of them be the reconciling of the world, what shall the receiving of them be, but life from the dead?","words":[["G1063","For",0,3],["G1487","if",4,6],["G0580","the casting away",7,23],["G0846","of them",24,31],["G2643","be the reconciling",32,50],["G2889","of the world",51,63],["G5101","what",65,69],["G4356","shall the receiving",70,89],["G1508","of them be, but",90,105],["G2222","life",106,110],["G1537","from",111,115],["G3498","the dead",116,124]]},"11:16":{"text":"For if the firstfruit be holy, the lump is also holy: and if the root be holy, so are the branches.","words":[["G1161","For",0,3],["G1487","if",4,6],["G0536","the firstfruit",7,21],["G0040","be holy",22,29],["G5445","the lump",31,39],["G2532","is also",40,47],["G2532","holy: and",48,57],["G1487","if",58,60],["G4491","the root",61,69],["G0040","be holy",70,77],["G2532","so",79,81],["G2798","are the branches",82,98]]},"11:17":{"text":"And if some of the branches be broken off, and thou, being a wild olive tree, wert graffed in among them, and with them partakest of the root and fatness of the olive tree;","words":[["G1161","And",0,3],["G1536","if some",4,11],["G2798","of the branches",12,27],["G1575","be broken off",28,41],["G1161","and",43,46],["G4771","thou",47,51],["G5607","being",53,58],["G0065","a wild olive tree",59,76],["G1461","wert graffed in",78,93],["G1722","among",94,99],["G0846","them",100,104],["G2532","and",106,109],["G4791","with",110,114],["G1096","them",115,119],["G4791","partakest",120,129],["G4491","of the root",130,141],["G2532","and",142,145],["G4096","fatness",146,153],["G1636","of the olive tree",154,171]]},"11:18":{"text":"Boast not against the branches. But if thou boast, thou bearest not the root, but the root thee.","words":[["G2620","Boast",0,5],["G3361","not",6,9],["G2620","against",10,17],["G2798","the branches",18,30],["G1161","But",32,35],["G1487","if",36,38],["G2620","thou boast",39,49],["G4771","thou",51,55],["G0941","bearest",56,63],["G3756","not",64,67],["G4491","the root",68,76],["G0235","but",78,81],["G4491","the root",82,90],["G4571","thee",91,95]]},"11:19":{"text":"Thou wilt say then, The branches were broken off, that I might be graffed in.","words":[["G2046","Thou wilt say",0,13],["G3767","then",14,18],["G2798","The branches",20,32],["G1575","were broken off",33,48],["G2443","that",50,54],["G1473","I",55,56],["G1461","might be graffed in",57,76]]},"11:20":{"text":"Well; because of unbelief they were broken off, and thou standest by faith. Be not highminded, but fear:","words":[["G2573","Well",0,4],["G0570","because of unbelief",6,25],["G1575","they were broken off",26,46],["G1161","and",48,51],["G4771","thou",52,56],["G2476","standest",57,65],["G4102","by faith",66,74],["G5309","Be",76,78],["G3361","not",79,82],["G5309","highminded",83,93],["G0235","but",95,98],["G5399","fear",99,103]]},"11:21":{"text":"For if God spared not the natural branches, take heed lest he also spare not thee.","words":[["G1063","For",0,3],["G1487","if",4,6],["G2316","God",7,10],["G5339","spared",11,17],["G3756","not",18,21],["G5449","the natural",22,33],["G2798","branches",34,42],["G2596","branches",34,42],["G4458","take heed lest",44,58],["G3381","take heed lest",44,58],["G5339","he",59,61],["G3381","also",62,66],["G5339","spare",67,72],["G3761","not",73,76],["G4675","thee",77,81]]},"11:22":{"text":"Behold therefore the goodness and severity of God: on them which fell, severity; but toward thee, goodness, if thou continue in his goodness: otherwise thou also shalt be cut off.","words":[["G1492","Behold",0,6],["G3767","therefore",7,16],["G5544","the goodness",17,29],["G2532","and",30,33],["G0663","severity",34,42],["G2316","of God",43,49],["G1909","on",51,53],["G4098","them which fell",54,69],["G3303","them which fell",54,69],["G0663","severity",71,79],["G1161","but",81,84],["G1909","toward",85,91],["G4571","thee",92,96],["G5544","goodness",98,106],["G1437","if",108,110],["G1961","thou continue",111,124],["G5544","in his goodness",125,140],["G1893","otherwise",142,151],["G4771","thou",152,156],["G2532","also",157,161],["G1581","shalt be cut off",162,178]]},"11:23":{"text":"And they also, if they abide not still in unbelief, shall be graffed in: for God is able to graff them in again.","words":[["G1161","And",0,3],["G1565","they",4,8],["G2532","also",9,13],["G3362","if",15,17],["G1961","they abide",18,28],["G3362","not",29,32],["G0570","still in unbelief",33,50],["G1461","shall be graffed in",52,71],["G1063","for",73,76],["G2316","God",77,80],["G2076","is",81,83],["G1415","able",84,88],["G1461","to graff",89,97],["G0846","them",98,102],["G1461","in",103,105],["G3825","again",106,111]]},"11:24":{"text":"For if thou wert cut out of the olive tree which is wild by nature, and wert graffed contrary to nature into a good olive tree: how much more shall these, which be the natural branches, be graffed into their own olive tree?","words":[["G1063","For",0,3],["G1487","if",4,6],["G4771","thou",7,11],["G1581","wert cut",12,20],["G1537","out of",21,27],["G0065","the olive tree which is wild",28,56],["G2596","by",57,59],["G5449","nature",60,66],["G2532","and",68,71],["G1461","wert graffed",72,84],["G3844","contrary to",85,96],["G5449","nature",97,103],["G1519","into",104,108],["G2565","a good olive tree",109,126],["G4214","how much",128,136],["G3123","more",137,141],["G3778","shall these",142,153],["G2596","which be the natural",155,175],["G5449","which be the natural",155,175],["G1461","branches, be graffed into",176,201],["G2398","their own",202,211],["G1636","olive tree",212,222]]},"11:25":{"text":"For I would not, brethren, that ye should be ignorant of this mystery, lest ye should be wise in your own conceits; that blindness in part is happened to Israel, until the fulness of the Gentiles be come in.","words":[["G1063","For",0,3],["G2309","I would",4,11],["G3756","not",12,15],["G0080","brethren",17,25],["G5209","that ye",27,34],["G0050","should be ignorant",35,53],["G5124","of this",54,61],["G3466","mystery",62,69],["G3363","lest",71,75],["G5600","ye should be",76,88],["G5429","wise",89,93],["G3844","in",94,96],["G1438","your own conceits",97,114],["G3754","that",116,120],["G4457","blindness",121,130],["G0575","in",131,133],["G3313","part",134,138],["G1096","is happened",139,150],["G2474","to Israel",151,160],["G0891","until",162,167],["G3739","until",162,167],["G4138","the fulness",168,179],["G1484","of the Gentiles",180,195],["G1525","be come in",196,206]]},"11:26":{"text":"And so all Israel shall be saved: as it is written, There shall come out of Sion the Deliverer, and shall turn away ungodliness from Jacob:","words":[["G2532","And",0,3],["G3779","so",4,6],["G3956","all",7,10],["G2474","Israel",11,17],["G4982","shall be saved",18,32],["G2531","as",34,36],["G1125","it is written",37,50],["G2240","There shall come",52,68],["G1537","out of",69,75],["G4622","Sion",76,80],["G4506","the Deliverer",81,94],["G2532","and",96,99],["G0654","shall turn away",100,115],["G0763","ungodliness",116,127],["G0575","from",128,132],["G2384","Jacob",133,138]]},"11:27":{"text":"For this is my covenant unto them, when I shall take away their sins.","words":[["G2532","For",0,3],["G3778","this",4,8],["G3844","is my",9,14],["G1700","is my",9,14],["G1242","covenant",15,23],["G0846","unto them",24,33],["G3752","when",35,39],["G0851","I shall take away",40,57],["G0846","their",58,63],["G0266","sins",64,68]]},"11:28":{"text":"As concerning the gospel, they are enemies for your sakes: but as touching the election, they are beloved for the fathers' sakes.","words":[["G2596","As concerning",0,13],["G3303","As concerning",0,13],["G2098","the gospel",14,24],["G2190","they are enemies",26,42],["G1223","for your sakes",43,57],["G5209","for your sakes",43,57],["G1161","but",59,62],["G2596","as touching",63,74],["G1589","the election",75,87],["G0027","they are beloved",89,105],["G1223","for",106,109],["G3962","the fathers'",110,122],["G1223","sakes",123,128]]},"11:29":{"text":"For the gifts and calling of God are without repentance.","words":[["G1063","For",0,3],["G5486","the gifts",4,13],["G2532","and",14,17],["G2821","calling",18,25],["G2316","of God",26,32],["G0278","are without repentance",33,55]]},"11:30":{"text":"For as ye in times past have not believed God, yet have now obtained mercy through their unbelief:","words":[["G1063","For",0,3],["G5618","as",4,6],["G2532","as",4,6],["G5210","ye",7,9],["G4218","in times past",10,23],["G0544","have not believed",24,41],["G2316","God",42,45],["G1161","yet",47,50],["G1653","have",51,55],["G3568","now",56,59],["G1653","obtained mercy",60,74],["G5130","through",75,82],["G0543","their unbelief",83,97]]},"11:31":{"text":"Even so have these also now not believed, that through your mercy they also may obtain mercy.","words":[["G3779","Even so",0,7],["G0544","have",8,12],["G3778","these",13,18],["G2532","also",19,23],["G3568","now",24,27],["G0544","not believed",28,40],["G2443","that",42,46],["G5212","through your",47,59],["G1656","mercy",60,65],["G0846","they",66,70],["G2532","also",71,75],["G1653","may obtain mercy",76,92]]},"11:32":{"text":"For God hath concluded them all in unbelief, that he might have mercy upon all.","words":[["G1063","For",0,3],["G2316","God",4,7],["G4788","hath concluded",8,22],["G3956","them all",23,31],["G1519","in",32,34],["G0543","unbelief",35,43],["G2443","that",45,49],["G1653","he might have mercy",50,69],["G3956","upon all",70,78]]},"11:33":{"text":"O the depth of the riches both of the wisdom and knowledge of God! how unsearchable are his judgments, and his ways past finding out!","words":[["G5599","O",0,1],["G0899","the depth",2,11],["G4149","of the riches",12,25],["G2532","both",26,30],["G4678","of the wisdom",31,44],["G2532","and",45,48],["G1108","knowledge",49,58],["G2316","of God",59,65],["G5613","how",67,70],["G0419","unsearchable",71,83],["G0846","are his",84,91],["G2917","judgments",92,101],["G2532","and",103,106],["G0846","his",107,110],["G3598","ways",111,115],["G0421","past finding out",116,132]]},"11:34":{"text":"For who hath known the mind of the Lord? or who hath been his counsellor?","words":[["G1063","For",0,3],["G5101","who",4,7],["G1097","hath known",8,18],["G3563","the mind",19,27],["G2962","of the Lord",28,39],["G2228","or",41,43],["G5101","who",44,47],["G1096","hath been",48,57],["G0846","his",58,61],["G4825","counsellor",62,72]]},"11:35":{"text":"Or who hath first given to him, and it shall be recompensed unto him again?","words":[["G2228","Or",0,2],["G5101","who",3,6],["G4272","hath first given",7,23],["G0846","to him",24,30],["G2532","and",32,35],["G0467","it shall be recompensed",36,59],["G0846","unto him",60,68],["G0467","again",69,74]]},"11:36":{"text":"For of him, and through him, and to him, are all things: to whom be glory for ever. Amen.","words":[["G3754","For",0,3],["G1537","of",4,6],["G0846","him",7,10],["G2532","and",12,15],["G1223","through",16,23],["G0846","him",24,27],["G2532","and",29,32],["G1519","to",33,35],["G0846","him",36,39],["G3956","are all things",41,55],["G0846","to whom",57,64],["G1391","be glory",65,73],["G1519","for",74,77],["G0165","ever",78,82],["G0281","Amen",84,88]]},"12:1":{"text":"I beseech you therefore, brethren, by the mercies of God, that ye present your bodies a living sacrifice, holy, acceptable unto God, which is your reasonable service.","words":[["G3870","I beseech",0,9],["G5209","you",10,13],["G3767","therefore",14,23],["G0080","brethren",25,33],["G1223","by",35,37],["G3628","the mercies",38,49],["G2316","of God",50,56],["G3936","that ye present",58,73],["G5216","your",74,78],["G4983","bodies",79,85],["G2198","a living",86,94],["G2378","sacrifice",95,104],["G0040","holy",106,110],["G2101","acceptable",112,122],["G2316","unto God",123,131],["G5216","which is your",133,146],["G3050","reasonable",147,157],["G2999","service",158,165]]},"12:2":{"text":"And be not conformed to this world: but be ye transformed by the renewing of your mind, that ye may prove what is that good, and acceptable, and perfect, will of God.","words":[["G2532","And",0,3],["G4964","be",4,6],["G3361","not",7,10],["G4964","conformed",11,20],["G5129","to this",21,28],["G0165","world",29,34],["G0235","but",36,39],["G3339","be ye transformed",40,57],["G0342","by the renewing",58,73],["G5216","of your",74,81],["G3563","mind",82,86],["G1519","that",88,92],["G5209","ye",93,95],["G1381","may prove",96,105],["G5101","what",106,110],["G0018","is that good",111,123],["G2532","and",125,128],["G2101","acceptable",129,139],["G2532","and",141,144],["G5046","perfect",145,152],["G2307","will",154,158],["G2316","of God",159,165]]},"12:3":{"text":"For I say, through the grace given unto me, to every man that is among you, not to think of himself more highly than he ought to think; but to think soberly, according as God hath dealt to every man the measure of faith.","words":[["G1063","For",0,3],["G3004","I say",4,9],["G1223","through",11,18],["G5485","the grace",19,28],["G1325","given",29,34],["G3427","unto me",35,42],["G3956","to every man",44,56],["G5607","that is",57,64],["G1722","among",65,70],["G5213","you",71,74],["G3361","not",76,79],["G3844","to think of himself more",80,104],["G5252","highly",105,111],["G3739","than",112,116],["G1163","he ought",117,125],["G5426","to think",126,134],["G0235","but",136,139],["G5426","to think",140,148],["G1519","soberly",149,156],["G4993","soberly",149,156],["G5613","according as",158,170],["G2316","God",171,174],["G3307","hath dealt",175,185],["G1538","to every man",186,198],["G3358","the measure",199,210],["G4102","of faith",211,219]]},"12:4":{"text":"For as we have many members in one body, and all members have not the same office:","words":[["G1063","For",0,3],["G2509","as",4,6],["G2192","we have",7,14],["G4183","many",15,19],["G3196","members",20,27],["G1722","in",28,30],["G1520","one",31,34],["G4983","body",35,39],["G1161","and",41,44],["G3956","all",45,48],["G3196","members",49,56],["G2192","have",57,61],["G3756","not",62,65],["G0846","the same",66,74],["G4234","office",75,81]]},"12:5":{"text":"So we, being many, are one body in Christ, and every one members one of another.","words":[["G3779","So",0,2],["G2070","we",3,5],["G4183","being many",7,17],["G2070","are",19,22],["G1520","one",23,26],["G4983","body",27,31],["G1722","in",32,34],["G5547","Christ",35,41],["G1161","and",43,46],["G2596","every",47,52],["G1520","one",53,56],["G3196","members",57,64],["G0240","one of another",65,79]]},"12:6":{"text":"Having then gifts differing according to the grace that is given to us, whether prophecy, let us prophesy according to the proportion of faith;","words":[["G2192","Having",0,6],["G1161","then",7,11],["G5486","gifts",12,17],["G1313","differing",18,27],["G2596","according",28,37],["G5485","to the grace",38,50],["G1325","that is given",51,64],["G2254","to us",65,70],["G1535","whether",72,79],["G4394","prophecy",80,88],["G2596","let us prophesy according",90,115],["G0356","to the proportion",116,133],["G4102","of faith",134,142]]},"12:7":{"text":"Or ministry, let us wait on our ministering: or he that teacheth, on teaching;","words":[["G1535","Or",0,2],["G1248","ministry",3,11],["G1722","let us wait on",13,27],["G1248","our ministering",28,43],["G1535","or",45,47],["G1321","he that teacheth",48,64],["G1722","on",66,68],["G1319","teaching",69,77]]},"12:8":{"text":"Or he that exhorteth, on exhortation: he that giveth, let him do it with simplicity; he that ruleth, with diligence; he that sheweth mercy, with cheerfulness.","words":[["G1535","Or",0,2],["G3870","he that exhorteth",3,20],["G1722","on",22,24],["G3874","exhortation",25,36],["G3330","he that giveth",38,52],["G1722","let him do it with",54,72],["G0572","simplicity",73,83],["G4291","he that ruleth",85,99],["G1722","with",101,105],["G4710","diligence",106,115],["G1653","he that sheweth mercy",117,138],["G1722","with",140,144],["G2432","cheerfulness",145,157]]},"12:9":{"text":"Let love be without dissimulation. Abhor that which is evil; cleave to that which is good.","words":[["G0026","Let love",0,8],["G0505","be without dissimulation",9,33],["G0655","Abhor",35,40],["G4190","that which is evil",41,59],["G2853","cleave",61,67],["G0018","to that which is good",68,89]]},"12:10":{"text":"Be kindly affectioned one to another with brotherly love; in honour preferring one another;","words":[["G5387","Be kindly affectioned",0,21],["G1519","one to another",22,36],["G0240","one to another",22,36],["G5360","with brotherly love",37,56],["G5092","in honour",58,67],["G4285","preferring",68,78],["G0240","one another",79,90]]},"12:11":{"text":"Not slothful in business; fervent in spirit; serving the Lord;","words":[["G3361","Not",0,3],["G3636","slothful",4,12],["G4710","in business",13,24],["G2204","fervent",26,33],["G4151","in spirit",34,43],["G1398","serving",45,52],["G2962","the Lord",53,61]]},"12:12":{"text":"Rejoicing in hope; patient in tribulation; continuing instant in prayer;","words":[["G5463","Rejoicing",0,9],["G1680","in hope",10,17],["G5278","patient",19,26],["G2347","in tribulation",27,41],["G4342","continuing instant",43,61],["G4335","in prayer",62,71]]},"12:13":{"text":"Distributing to the necessity of saints; given to hospitality.","words":[["G2841","Distributing",0,12],["G5532","to the necessity",13,29],["G0040","of saints",30,39],["G1377","given",41,46],["G5381","to hospitality",47,61]]},"12:14":{"text":"Bless them which persecute you: bless, and curse not.","words":[["G2127","Bless",0,5],["G1377","them which persecute",6,26],["G5209","you",27,30],["G2127","bless",32,37],["G2532","and",39,42],["G2672","curse",43,48],["G3361","not",49,52]]},"12:15":{"text":"Rejoice with them that do rejoice, and weep with them that weep.","words":[["G5463","Rejoice",0,7],["G3326","with",8,12],["G5463","them that do rejoice",13,33],["G2532","and",35,38],["G2799","weep",39,43],["G3326","with",44,48],["G2799","them that weep",49,63]]},"12:16":{"text":"Be of the same mind one toward another. Mind not high things, but condescend to men of low estate. Be not wise in your own conceits.","words":[["G0846","Be of the same",0,14],["G5426","mind",15,19],["G1519","one toward another",20,38],["G0240","one toward another",20,38],["G5426","Mind",40,44],["G3361","not",45,48],["G5308","high things",49,60],["G0235","but",62,65],["G4879","condescend",66,76],["G5011","to men of low estate",77,97],["G1096","Be",99,101],["G3361","not",102,105],["G5429","wise",106,110],["G3844","in",111,113],["G1438","your own conceits",114,131]]},"12:17":{"text":"Recompense to no man evil for evil. Provide things honest in the sight of all men.","words":[["G0591","Recompense",0,10],["G3367","to no man",11,20],["G2556","evil",21,25],["G0473","for",26,29],["G2556","evil",30,34],["G4306","Provide",36,43],["G2570","things honest",44,57],["G1799","in the sight",58,70],["G3956","of all",71,77],["G0444","men",78,81]]},"12:18":{"text":"If it be possible, as much as lieth in you, live peaceably with all men.","words":[["G1487","If",0,2],["G1415","it be possible",3,17],["G1537","as much as lieth in",19,38],["G5216","you",39,42],["G1514","live peaceably",44,58],["G3326","with",59,63],["G3956","all",64,67],["G0444","men",68,71]]},"12:19":{"text":"Dearly beloved, avenge not yourselves, but rather give place unto wrath: for it is written, Vengeance is mine; I will repay, saith the Lord.","words":[["G0027","Dearly beloved",0,14],["G1556","avenge",16,22],["G3361","not",23,26],["G1438","yourselves",27,37],["G0235","but",39,42],["G1325","rather give",43,54],["G5117","place",55,60],["G3709","unto wrath",61,71],["G1063","for",73,76],["G1125","it is written",77,90],["G1557","Vengeance",92,101],["G1698","is mine",102,109],["G1473","I",111,112],["G0467","will repay",113,123],["G3004","saith",125,130],["G2962","the Lord",131,139]]},"12:20":{"text":"Therefore if thine enemy hunger, feed him; if he thirst, give him drink: for in so doing thou shalt heap coals of fire on his head.","words":[["G3767","Therefore",0,9],["G1437","if",10,12],["G4675","thine",13,18],["G2190","enemy",19,24],["G3983","hunger",25,31],["G5595","feed",33,37],["G0846","him",38,41],["G1437","if",43,45],["G1372","he thirst",46,55],["G4222","give",57,61],["G0846","him",62,65],["G4222","drink",66,71],["G1063","for",73,76],["G5124","in so",77,82],["G4160","doing",83,88],["G4987","thou shalt heap",89,104],["G0440","coals",105,110],["G4442","of fire",111,118],["G1909","on",119,121],["G0846","his",122,125],["G2776","head",126,130]]},"12:21":{"text":"Be not overcome of evil, but overcome evil with good.","words":[["G3528","Be",0,2],["G3361","not",3,6],["G3528","overcome",7,15],["G5259","of",16,18],["G2556","evil",19,23],["G0235","but",25,28],["G3528","overcome",29,37],["G2556","evil",38,42],["G1722","with",43,47],["G0018","good",48,52]]},"13:1":{"text":"Let every soul be subject unto the higher powers. For there is no power but of God: the powers that be are ordained of God.","words":[["G3956","Let every",0,9],["G5590","soul",10,14],["G5293","be subject",15,25],["G5242","unto the higher",26,41],["G1849","powers",42,48],["G1063","For",50,53],["G2076","there is",54,62],["G3756","no",63,65],["G1849","power",66,71],["G1508","but",72,75],["G0575","of",76,78],["G2316","God",79,82],["G1161","",-1,-1],["G1849","the powers",84,94],["G5607","that be",95,102],["G1526","are",103,106],["G5021","ordained",107,115],["G5259","of",116,118],["G2316","God",119,122]]},"13:2":{"text":"Whosoever therefore resisteth the power, resisteth the ordinance of God: and they that resist shall receive to themselves damnation.","words":[["G5620","Whosoever therefore",0,19],["G0498","resisteth",20,29],["G1849","the power",30,39],["G0436","resisteth",41,50],["G1296","the ordinance",51,64],["G2316","of God",65,71],["G1161","and",73,76],["G0436","they that resist",77,93],["G2983","shall receive",94,107],["G1438","to themselves",108,121],["G2917","damnation",122,131]]},"13:3":{"text":"For rulers are not a terror to good works, but to the evil. Wilt thou then not be afraid of the power? do that which is good, and thou shalt have praise of the same:","words":[["G1063","For",0,3],["G0758","rulers",4,10],["G1526","are",11,14],["G3756","not",15,18],["G5401","a terror",19,27],["G0018","to good",28,35],["G2041","works",36,41],["G0235","but",43,46],["G2556","to the evil",47,58],["G2309","Wilt thou",60,69],["G1161","then",70,74],["G3361","not",75,78],["G5399","be afraid",79,88],["G1849","of the power",89,101],["G4160","do",103,105],["G0018","that which is good",106,124],["G2532","and",126,129],["G2192","thou shalt have",130,145],["G1868","praise",146,152],["G1537","of",153,155],["G0846","the same",156,164]]},"13:4":{"text":"For he is the minister of God to thee for good. But if thou do that which is evil, be afraid; for he beareth not the sword in vain: for he is the minister of God, a revenger to execute wrath upon him that doeth evil.","words":[["G1063","For",0,3],["G2076","he is",4,9],["G1249","the minister",10,22],["G2316","of God",23,29],["G4671","to thee",30,37],["G1519","for",38,41],["G0018","good",42,46],["G1161","But",48,51],["G1437","if",52,54],["G4160","thou do",55,62],["G2556","that which is evil",63,81],["G5399","be afraid",83,92],["G1063","for",94,97],["G5409","he beareth",98,108],["G3756","not",109,112],["G3162","the sword",113,122],["G1500","in vain",123,130],["G1063","for",132,135],["G2076","he is",136,141],["G1249","the minister",142,154],["G2316","of God",155,161],["G1558","a revenger",163,173],["G3709","to execute wrath",174,190],["G1519","upon",191,195],["G4238","him that doeth",196,210],["G2556","evil",211,215]]},"13:5":{"text":"Wherefore ye must needs be subject, not only for wrath, but also for conscience sake.","words":[["G1352","Wherefore",0,9],["G0318","ye must needs",10,23],["G5293","be subject",24,34],["G3756","not",36,39],["G3440","only",40,44],["G1223","for",45,48],["G3709","wrath",49,54],["G0235","but",56,59],["G2532","also",60,64],["G4893","for conscience",65,79],["G1223","sake",80,84]]},"13:6":{"text":"For for this cause pay ye tribute also: for they are God's ministers, attending continually upon this very thing.","words":[["G1063","For",0,3],["G1223","for",4,7],["G5124","this",8,12],["G1223","cause",13,18],["G5055","pay ye",19,25],["G5411","tribute",26,33],["G2532","also",34,38],["G1063","for",40,43],["G1526","they are",44,52],["G2316","God's",53,58],["G3011","ministers",59,68],["G4342","attending continually",70,91],["G1519","upon",92,96],["G5124","this",97,101],["G0846","very thing",102,112]]},"13:7":{"text":"Render therefore to all their dues: tribute to whom tribute is due; custom to whom custom; fear to whom fear; honour to whom honour.","words":[["G0591","Render",0,6],["G3767","therefore",7,16],["G3956","to all",17,23],["G3782","their dues",24,34],["G5411","tribute",36,43],["G3588","to whom",44,51],["G5411","tribute",52,59],["G5056","is due; custom",60,74],["G3588","to whom",75,82],["G5056","custom",83,89],["G5401","fear",91,95],["G3588","to whom",96,103],["G5401","fear",104,108],["G5092","honour",110,116],["G3588","to whom",117,124],["G5092","honour",125,131]]},"13:8":{"text":"Owe no man any thing, but to love one another: for he that loveth another hath fulfilled the law.","words":[["G3784","Owe",0,3],["G3367","no man",4,10],["G3367","any thing",11,20],["G1508","but",22,25],["G0025","to love",26,33],["G0240","one another",34,45],["G1063","for",47,50],["G0025","he that loveth",51,65],["G2087","another",66,73],["G4137","hath fulfilled",74,88],["G3551","the law",89,96]]},"13:9":{"text":"For this, Thou shalt not commit adultery, Thou shalt not kill, Thou shalt not steal, Thou shalt not bear false witness, Thou shalt not covet; and if there be any other commandment, it is briefly comprehended in this saying, namely, Thou shalt love thy neighbour as thyself.","words":[["G1063","For",0,3],["G3431","this, Thou shalt",4,20],["G3756","not",21,24],["G3431","commit adultery",25,40],["G5407","Thou shalt",42,52],["G3756","not",53,56],["G5407","kill",57,61],["G2813","Thou shalt",63,73],["G3756","not",74,77],["G2813","steal",78,83],["G5576","Thou shalt",85,95],["G3756","not",96,99],["G5576","bear false witness",100,118],["G1937","Thou shalt",120,130],["G3756","not",131,134],["G1937","covet",135,140],["G2532","and",142,145],["G1536","if there be any",146,161],["G2087","other",162,167],["G1785","commandment",168,179],["G0346","it is briefly comprehended",181,207],["G1722","in",208,210],["G5129","this",211,215],["G3056","saying",216,222],["G1722","namely",224,230],["G0025","Thou shalt love",232,247],["G4675","thy",248,251],["G4139","neighbour",252,261],["G5613","as",262,264],["G1438","thyself",265,272]]},"13:10":{"text":"Love worketh no ill to his neighbour: therefore love is the fulfilling of the law.","words":[["G0026","Love",0,4],["G2038","worketh",5,12],["G3756","no",13,15],["G2556","ill",16,19],["G4139","to his neighbour",20,36],["G3767","therefore",38,47],["G0026","love",48,52],["G4138","is the fulfilling",53,70],["G3551","of the law",71,81]]},"13:11":{"text":"And that, knowing the time, that now it is high time to awake out of sleep: for now is our salvation nearer than when we believed.","words":[["G2532","And",0,3],["G5124","that",4,8],["G1492","knowing",10,17],["G2540","the time",18,26],["G3754","that",28,32],["G2235","now",33,36],["G5610","it is high time",37,52],["G2248","to awake",53,61],["G1453","to awake",53,61],["G1537","out of",62,68],["G5258","sleep",69,74],["G1063","for",76,79],["G3568","now",80,83],["G2257","is our",84,90],["G4991","salvation",91,100],["G1452","nearer",101,107],["G2228","than",108,112],["G3753","when",113,117],["G4100","we believed",118,129]]},"13:12":{"text":"The night is far spent, the day is at hand: let us therefore cast off the works of darkness, and let us put on the armour of light.","words":[["G3571","The night",0,9],["G4298","is far spent",10,22],["G1161","",-1,-1],["G2250","the day",24,31],["G1448","is at hand",32,42],["G0659","let us",44,50],["G3767","therefore",51,60],["G0659","cast off",61,69],["G2041","the works",70,79],["G4655","of darkness",80,91],["G2532","and",93,96],["G1746","let us put on",97,110],["G3696","the armour",111,121],["G5457","of light",122,130]]},"13:13":{"text":"Let us walk honestly, as in the day; not in rioting and drunkenness, not in chambering and wantonness, not in strife and envying.","words":[["G4043","Let us walk",0,11],["G2156","honestly",12,20],["G5613","as",22,24],["G1722","in",25,27],["G2250","the day",28,35],["G3361","not",37,40],["G2970","in rioting",41,51],["G2532","and",52,55],["G3178","drunkenness",56,67],["G3361","not",69,72],["G2845","in chambering",73,86],["G2532","and",87,90],["G0766","wantonness",91,101],["G3361","not",103,106],["G2054","in strife",107,116],["G2532","and",117,120],["G2205","envying",121,128]]},"13:14":{"text":"But put ye on the Lord Jesus Christ, and make not provision for the flesh, to fulfil the lusts thereof.","words":[["G0235","But",0,3],["G1746","put ye on",4,13],["G2962","the Lord",14,22],["G2424","Jesus",23,28],["G5547","Christ",29,35],["G2532","and",37,40],["G4160","make",41,45],["G3361","not",46,49],["G4307","provision",50,59],["G1519","for",60,63],["G4561","the flesh",64,73],["G1939","to fulfil the lusts",75,94]]},"14:1":{"text":"Him that is weak in the faith receive ye, but not to doubtful disputations.","words":[["G0770","Him that is weak",0,16],["G4102","in the faith",17,29],["G4355","receive ye",30,40],["G1161","but",42,45],["G3361","not",46,49],["G1519","to",50,52],["G1261","doubtful",53,61],["G1253","disputations",62,74]]},"14:2":{"text":"For one believeth that he may eat all things: another, who is weak, eateth herbs.","words":[["G3303","For",0,3],["G3739","one",4,7],["G4100","believeth",8,17],["G5315","that he may eat",18,33],["G3956","all things",34,44],["G1161","another",46,53],["G0770","who is weak",55,66],["G2068","eateth",68,74],["G3001","herbs",75,80]]},"14:3":{"text":"Let not him that eateth despise him that eateth not; and let not him which eateth not judge him that eateth: for God hath received him.","words":[["G1848","Let",0,3],["G3361","not",4,7],["G2068","him that eateth",8,23],["G1848","despise",24,31],["G2068","him that eateth",32,47],["G3361","not",48,51],["G2532","and",53,56],["G2068","let",57,60],["G3361","not",61,64],["G2068","him which eateth",65,81],["G3361","not",82,85],["G2919","judge",86,91],["G2068","him that eateth",92,107],["G1063","for",109,112],["G2316","God",113,116],["G4355","hath received",117,130],["G0846","him",131,134]]},"14:4":{"text":"Who art thou that judgest another man's servant? to his own master he standeth or falleth. Yea, he shall be holden up: for God is able to make him stand.","words":[["G5101","Who",0,3],["G1488","art",4,7],["G4771","thou",8,12],["G2919","that judgest",13,25],["G0245","another man's",26,39],["G3610","servant",40,47],["G2398","to his own",49,59],["G2962","master",60,66],["G4739","he standeth",67,78],["G2228","or",79,81],["G4098","falleth",82,89],["G1161","Yea",91,94],["G2476","he shall be holden up",96,117],["G1063","for",119,122],["G2316","God",123,126],["G2076","is",127,129],["G1415","able",130,134],["G2476","to make",135,142],["G0846","him",143,146],["G2476","stand",147,152]]},"14:5":{"text":"One man esteemeth one day above another: another esteemeth every day alike. Let every man be fully persuaded in his own mind.","words":[["G3303","One",0,3],["G3739","man",4,7],["G2919","esteemeth",8,17],["G2250","one day",18,25],["G3844","above",26,31],["G2250","another",32,39],["G1161","",-1,-1],["G3739","another",41,48],["G2919","esteemeth",49,58],["G3956","every",59,64],["G2250","day",65,68],["G4135","alike. Let",69,79],["G1538","every man",80,89],["G4135","be fully persuaded",90,108],["G1722","in",109,111],["G2398","his own",112,119],["G3563","mind",120,124]]},"14:6":{"text":"He that regardeth the day, regardeth it unto the Lord; and he that regardeth not the day, to the Lord he doth not regard it. He that eateth, eateth to the Lord, for he giveth God thanks; and he that eateth not, to the Lord he eateth not, and giveth God thanks.","words":[["G5426","He that regardeth",0,17],["G2250","the day",18,25],["G5426","regardeth",27,36],["G2962","it unto the Lord",37,53],["G2532","and",55,58],["G5426","he that regardeth",59,76],["G3361","not",77,80],["G2250","the day",81,88],["G2962","to the Lord",90,101],["G5426","he doth",102,109],["G3756","not",110,113],["G5426","regard",114,120],["G2068","it. He that eateth",121,139],["G2068","eateth",141,147],["G2962","to the Lord",148,159],["G1063","for",161,164],["G2316","he giveth God",165,178],["G2168","thanks",179,185],["G2532","and",187,190],["G2068","he that eateth",191,205],["G3361","not",206,209],["G2962","to the Lord",211,222],["G2068","he eateth",223,232],["G3756","not",233,236],["G2532","and",238,241],["G2316","giveth God",242,252],["G2168","thanks",253,259]]},"14:7":{"text":"For none of us liveth to himself, and no man dieth to himself.","words":[["G1063","For",0,3],["G3762","none",4,8],["G2257","of us",9,14],["G2198","liveth",15,21],["G1438","to himself",22,32],["G2532","and",34,37],["G3762","no man",38,44],["G0599","dieth",45,50],["G1438","to himself",51,61]]},"14:8":{"text":"For whether we live, we live unto the Lord; and whether we die, we die unto the Lord: whether we live therefore, or die, we are the Lord's.","words":[["G1063","For",0,3],["G1437","whether",4,11],["G5037","whether",4,11],["G2198","we live",12,19],["G2198","we live",21,28],["G2962","unto the Lord",29,42],["G1437","and whether",44,55],["G5037","and whether",44,55],["G0599","we die",56,62],["G0599","we die",64,70],["G2962","unto the Lord",71,84],["G1437","whether",86,93],["G5037","whether",86,93],["G2198","we live",94,101],["G3767","therefore",102,111],["G1437","or",113,115],["G5037","or",113,115],["G0599","die",116,119],["G2070","we are",121,127],["G2962","the Lord's",128,138]]},"14:9":{"text":"For to this end Christ both died, and rose, and revived, that he might be Lord both of the dead and living.","words":[["G1063","For",0,3],["G1519","to",4,6],["G5124","this",7,11],["G5547","end Christ",12,22],["G2532","both",23,27],["G0599","died",28,32],["G2532","and",34,37],["G0450","rose",38,42],["G2532","and",44,47],["G0326","revived",48,55],["G2443","that",57,61],["G2961","he might be Lord",62,78],["G2532","both",79,83],["G3498","of the dead",84,95],["G2532","and",96,99],["G2198","living",100,106]]},"14:10":{"text":"But why dost thou judge thy brother? or why dost thou set at nought thy brother? for we shall all stand before the judgment seat of Christ.","words":[["G1161","But",0,3],["G5101","why",4,7],["G2919","dost",8,12],["G4771","thou",13,17],["G2919","judge",18,23],["G4675","thy",24,27],["G0080","brother",28,35],["G2228","or",37,39],["G2532","or",37,39],["G5101","why",40,43],["G1848","dost",44,48],["G4771","thou",49,53],["G1848","set at nought",54,67],["G4675","thy",68,71],["G0080","brother",72,79],["G1063","for",81,84],["G3936","we shall",85,93],["G3956","all",94,97],["G3936","stand before",98,110],["G0968","the judgment seat",111,128],["G5547","of Christ",129,138]]},"14:11":{"text":"For it is written, As I live, saith the Lord, every knee shall bow to me, and every tongue shall confess to God.","words":[["G1063","For",0,3],["G1125","it is written",4,17],["G1473","As I",19,23],["G2198","live",24,28],["G3004","saith",30,35],["G2962","the Lord",36,44],["G3754","",-1,-1],["G3956","every",46,51],["G1119","knee",52,56],["G2578","shall bow",57,66],["G1698","to me",67,72],["G2532","and",74,77],["G3956","every",78,83],["G1100","tongue",84,90],["G1843","shall confess",91,104],["G2316","to God",105,111]]},"14:12":{"text":"So then every one of us shall give account of himself to God.","words":[["G3767","So",0,2],["G0686","then",3,7],["G1538","every one",8,17],["G2257","of us",18,23],["G1325","shall give",24,34],["G3056","account",35,42],["G4012","of",43,45],["G1438","himself",46,53],["G2316","to God",54,60]]},"14:13":{"text":"Let us not therefore judge one another any more: but judge this rather, that no man put a stumblingblock or an occasion to fall in his brother's way.","words":[["G2919","Let us",0,6],["G3767","not therefore",7,20],["G2919","judge",21,26],["G0240","one another",27,38],["G3371","any more",39,47],["G0235","but",49,52],["G2919","judge",53,58],["G5124","this",59,63],["G3123","rather",64,70],["G3361","that no man",72,83],["G5087","put",84,87],["G4348","a stumblingblock",88,104],["G2228","or",105,107],["G4625","an occasion to fall",108,127],["G0080","in his brother's way",128,148]]},"14:14":{"text":"I know, and am persuaded by the Lord Jesus, that there is nothing unclean of itself: but to him that esteemeth any thing to be unclean, to him it is unclean.","words":[["G1492","I know",0,6],["G2532","and",8,11],["G3982","am persuaded",12,24],["G1722","by",25,27],["G2962","the Lord",28,36],["G2424","Jesus",37,42],["G3754","that",44,48],["G3762","there is nothing",49,65],["G2839","unclean",66,73],["G1223","of",74,76],["G1438","itself",77,83],["G1508","but",85,88],["G3049","to him that esteemeth",89,110],["G5100","any thing",111,120],["G1511","to be",121,126],["G2839","unclean",127,134],["G1565","to him",136,142],["G2839","it is unclean",143,156]]},"14:15":{"text":"But if thy brother be grieved with thy meat, now walkest thou not charitably. Destroy not him with thy meat, for whom Christ died.","words":[["G1161","But",0,3],["G1487","if",4,6],["G4675","thy",7,10],["G0080","brother",11,18],["G3076","be grieved",19,29],["G1223","with",30,34],["G1033","thy meat",35,43],["G3765","now",45,48],["G4043","walkest thou",49,61],["G3765","not",62,65],["G0026","charitably",66,76],["G2596","charitably",66,76],["G0622","Destroy",78,85],["G3361","not",86,89],["G1565","him",90,93],["G4675","with thy",94,102],["G1033","meat",103,107],["G5228","for",109,112],["G3739","whom",113,117],["G5547","Christ",118,124],["G0599","died",125,129]]},"14:16":{"text":"Let not then your good be evil spoken of:","words":[["G0987","Let",0,3],["G3361","not",4,7],["G3767","then",8,12],["G5216","your",13,17],["G0018","good",18,22],["G0987","be evil spoken of",23,40]]},"14:17":{"text":"For the kingdom of God is not meat and drink; but righteousness, and peace, and joy in the Holy Ghost.","words":[["G1063","For",0,3],["G0932","the kingdom",4,15],["G2316","of God",16,22],["G2076","is",23,25],["G3756","not",26,29],["G1035","meat",30,34],["G2532","and",35,38],["G4213","drink",39,44],["G0235","but",46,49],["G1343","righteousness",50,63],["G2532","and",65,68],["G1515","peace",69,74],["G2532","and",76,79],["G5479","joy",80,83],["G1722","in",84,86],["G0040","the Holy",87,95],["G4151","Ghost",96,101]]},"14:18":{"text":"For he that in these things serveth Christ is acceptable to God, and approved of men.","words":[["G1063","For",0,3],["G1722","he that in",4,14],["G5125","these things",15,27],["G1398","serveth",28,35],["G5547","Christ",36,42],["G2101","is acceptable",43,56],["G2316","to God",57,63],["G2532","and",65,68],["G1384","approved",69,77],["G0444","of men",78,84]]},"14:19":{"text":"Let us therefore follow after the things which make for peace, and things wherewith one may edify another.","words":[["G1377","Let us",0,6],["G0686","therefore",7,16],["G3767","therefore",7,16],["G1377","follow after",17,29],["G3588","the things which make for",30,55],["G1515","peace",56,61],["G2532","and",63,66],["G1519","things wherewith",67,83],["G0240","one",84,87],["G3619","may edify",88,97],["G0240","another",98,105]]},"14:20":{"text":"For meat destroy not the work of God. All things indeed are pure; but it is evil for that man who eateth with offence.","words":[["G1752","For",0,3],["G1033","meat",4,8],["G2647","destroy",9,16],["G3361","not",17,20],["G2041","the work",21,29],["G2316","of God",30,36],["G3956","All things",38,48],["G3303","indeed",49,55],["G2513","are pure",56,64],["G0235","but",66,69],["G2556","it is evil",70,80],["G0444","for that man",81,93],["G2068","who eateth",94,104],["G1223","with",105,109],["G4348","offence",110,117]]},"14:21":{"text":"It is good neither to eat flesh, nor to drink wine, nor any thing whereby thy brother stumbleth, or is offended, or is made weak.","words":[["G2570","It is good",0,10],["G3361","neither",11,18],["G5315","to eat",19,25],["G2907","flesh",26,31],["G3366","nor",33,36],["G4095","to drink",37,45],["G3631","wine",46,50],["G3366","nor",52,55],["G1722","any thing whereby",56,73],["G3739","any thing whereby",56,73],["G4675","thy",74,77],["G0080","brother",78,85],["G4350","stumbleth",86,95],["G2228","or",97,99],["G4624","is offended",100,111],["G2228","or",113,115],["G0770","is made weak",116,128]]},"14:22":{"text":"Hast thou faith? have it to thyself before God. Happy is he that condemneth not himself in that thing which he alloweth.","words":[["G2192","Hast",0,4],["G4771","thou",5,9],["G4102","faith",10,15],["G2192","have",17,21],["G2596","it to",22,27],["G4572","thyself",28,35],["G1799","before",36,42],["G2316","God",43,46],["G3107","Happy",48,53],["G2919","is he that condemneth",54,75],["G3361","not",76,79],["G1438","himself",80,87],["G1722","in",88,90],["G3739","that thing which",91,107],["G1381","he alloweth",108,119]]},"14:23":{"text":"And he that doubteth is damned if he eat, because he eateth not of faith: for whatsoever is not of faith is sin.","words":[["G1161","And",0,3],["G1252","he that doubteth",4,20],["G2632","is damned",21,30],["G1437","if",31,33],["G5315","he eat",34,40],["G3754","because",42,49],["G3756","he eateth not",50,63],["G1537","of",64,66],["G4102","faith",67,72],["G1161","for",74,77],["G3739","whatsoever",78,88],["G3956","whatsoever",78,88],["G3756","is not",89,95],["G1537","of",96,98],["G4102","faith",99,104],["G2076","is",105,107],["G0266","sin",108,111]]},"15:1":{"text":"We then that are strong ought to bear the infirmities of the weak, and not to please ourselves.","words":[["G2249","We",0,2],["G1161","then",3,7],["G1415","that are strong",8,23],["G3784","ought",24,29],["G0941","to bear",30,37],["G0771","the infirmities",38,53],["G0102","of the weak",54,65],["G2532","and",67,70],["G3361","not",71,74],["G0700","to please",75,84],["G1438","ourselves",85,94]]},"15:2":{"text":"Let every one of us please his neighbour for his good to edification.","words":[["G1063","",-1,-1],["G0700","Let",0,3],["G1538","every one",4,13],["G2257","of us",14,19],["G0700","please",20,26],["G4139","his neighbour",27,40],["G1519","for",41,44],["G0018","his good",45,53],["G4314","to",54,56],["G3619","edification",57,68]]},"15:3":{"text":"For even Christ pleased not himself; but, as it is written, The reproaches of them that reproached thee fell on me.","words":[["G1063","For",0,3],["G2532","even",4,8],["G5547","Christ",9,15],["G0700","pleased",16,23],["G3756","not",24,27],["G1438","himself",28,35],["G0235","but",37,40],["G2531","as",42,44],["G1125","it is written",45,58],["G3680","The reproaches",60,74],["G3679","of them that reproached",75,98],["G4571","thee",99,103],["G1968","fell",104,108],["G1909","on",109,111],["G1691","me",112,114]]},"15:4":{"text":"For whatsoever things were written aforetime were written for our learning, that we through patience and comfort of the scriptures might have hope.","words":[["G1063","For",0,3],["G3745","whatsoever things",4,21],["G4270","were written aforetime",22,44],["G4270","were written",45,57],["G1519","for",58,61],["G2251","our",62,65],["G1319","learning",66,74],["G2443","that",76,80],["G2192","we",81,83],["G1223","through",84,91],["G5281","patience",92,100],["G2532","and",101,104],["G3874","comfort",105,112],["G1124","of the scriptures",113,130],["G2192","might have",131,141],["G1680","hope",142,146]]},"15:5":{"text":"Now the God of patience and consolation grant you to be likeminded one toward another according to Christ Jesus:","words":[["G1161","Now",0,3],["G2316","the God",4,11],["G5281","of patience",12,23],["G2532","and",24,27],["G3874","consolation",28,39],["G1325","grant",40,45],["G5213","you",46,49],["G0846","to be",50,55],["G5426","likeminded",56,66],["G0240","one",67,70],["G1722","toward another",71,85],["G0240","toward another",71,85],["G2596","according",86,95],["G5547","to Christ",96,105],["G2424","Jesus",106,111]]},"15:6":{"text":"That ye may with one mind and one mouth glorify God, even the Father of our Lord Jesus Christ.","words":[["G2443","That",0,4],["G1392","ye may",5,11],["G3661","with one mind",12,25],["G1722","and",26,29],["G1520","one",30,33],["G4750","mouth",34,39],["G1392","glorify",40,47],["G2316","God",48,51],["G2532","even",53,57],["G3962","the Father",58,68],["G2257","of our",69,75],["G2962","Lord",76,80],["G2424","Jesus",81,86],["G5547","Christ",87,93]]},"15:7":{"text":"Wherefore receive ye one another, as Christ also received us to the glory of God.","words":[["G1352","Wherefore",0,9],["G4355","receive ye",10,20],["G0240","one another",21,32],["G2531","as",34,36],["G2532","as",34,36],["G5547","Christ",37,43],["G2531","also",44,48],["G4355","received",49,57],["G2248","us",58,60],["G1519","to",61,63],["G1391","the glory",64,73],["G2316","of God",74,80]]},"15:8":{"text":"Now I say that Jesus Christ was a minister of the circumcision for the truth of God, to confirm the promises made unto the fathers:","words":[["G1161","Now",0,3],["G3004","I say",4,9],["G2424","that Jesus",10,20],["G5547","Christ",21,27],["G1096","was",28,31],["G1249","a minister",32,42],["G4061","of the circumcision",43,62],["G5228","for",63,66],["G0225","the truth",67,76],["G2316","of God",77,83],["G1519","to",85,87],["G0950","confirm",88,95],["G1860","the promises",96,108],["G3962","made unto the fathers",109,130]]},"15:9":{"text":"And that the Gentiles might glorify God for his mercy; as it is written, For this cause I will confess to thee among the Gentiles, and sing unto thy name.","words":[["G1161","And",0,3],["G1484","that the Gentiles",4,21],["G1392","might glorify",22,35],["G2316","God",36,39],["G5228","for",40,43],["G1656","his mercy",44,53],["G2531","as",55,57],["G1125","it is written",58,71],["G1223","For",73,76],["G5124","this",77,81],["G1223","cause",82,87],["G1843","I will confess",88,102],["G4671","to thee",103,110],["G1722","among",111,116],["G1484","the Gentiles",117,129],["G2532","and",131,134],["G5567","sing",135,139],["G4675","unto thy",140,148],["G3686","name",149,153]]},"15:10":{"text":"And again he saith, Rejoice, ye Gentiles, with his people.","words":[["G2532","And",0,3],["G3825","again",4,9],["G3004","he saith",10,18],["G2165","Rejoice, ye",20,31],["G1484","Gentiles",32,40],["G3326","with",42,46],["G0846","his",47,50],["G2992","people",51,57]]},"15:11":{"text":"And again, Praise the Lord, all ye Gentiles; and laud him, all ye people.","words":[["G2532","And",0,3],["G3825","again",4,9],["G0134","Praise",11,17],["G2962","the Lord",18,26],["G3956","all",28,31],["G0134","ye",32,34],["G1484","Gentiles",35,43],["G2532","and",45,48],["G1867","laud",49,53],["G0846","him",54,57],["G3956","all ye",59,65],["G2992","people",66,72]]},"15:12":{"text":"And again, Esaias saith, There shall be a root of Jesse, and he that shall rise to reign over the Gentiles; in him shall the Gentiles trust.","words":[["G2532","And",0,3],["G3825","again",4,9],["G2268","Esaias",11,17],["G3004","saith",18,23],["G2071","There shall be",25,39],["G4491","a root",40,46],["G2421","of Jesse",47,55],["G2532","and",57,60],["G0450","he that shall rise",61,79],["G0757","to reign over",80,93],["G1484","the Gentiles",94,106],["G1909","in",108,110],["G0846","him",111,114],["G1679","shall",115,120],["G1484","the Gentiles",121,133],["G1679","trust",134,139]]},"15:13":{"text":"Now the God of hope fill you with all joy and peace in believing, that ye may abound in hope, through the power of the Holy Ghost.","words":[["G1161","Now",0,3],["G2316","the God",4,11],["G1680","of hope",12,19],["G4137","fill",20,24],["G5209","you",25,28],["G3956","with all",29,37],["G5479","joy",38,41],["G2532","and",42,45],["G1515","peace",46,51],["G1722","in",52,54],["G4100","believing",55,64],["G1519","that",66,70],["G5209","ye",71,73],["G4052","may abound",74,84],["G1722","in",85,87],["G1680","hope",88,92],["G1722","through",94,101],["G1411","the power",102,111],["G0040","of the Holy",112,123],["G4151","Ghost",124,129]]},"15:14":{"text":"And I myself also am persuaded of you, my brethren, that ye also are full of goodness, filled with all knowledge, able also to admonish one another.","words":[["G1161","And",0,3],["G1473","I",4,5],["G0846","myself",6,12],["G2532","also",13,17],["G3982","am persuaded",18,30],["G4012","of",31,33],["G5216","you",34,37],["G3450","my",39,41],["G0080","brethren",42,50],["G3754","that",52,56],["G0846","ye",57,59],["G2532","also",60,64],["G2075","are",65,68],["G3324","full",69,73],["G0019","of goodness",74,85],["G4137","filled",87,93],["G3956","with all",94,102],["G1108","knowledge",103,112],["G1410","able",114,118],["G2532","also",119,123],["G3560","to admonish",124,135],["G0240","one another",136,147]]},"15:15":{"text":"Nevertheless, brethren, I have written the more boldly unto you in some sort, as putting you in mind, because of the grace that is given to me of God,","words":[["G1161","Nevertheless",0,12],["G0080","brethren",14,22],["G1125","I have written",24,38],["G5112","the more boldly",39,54],["G5213","unto you",55,63],["G0575","in",64,66],["G3313","some sort",67,76],["G5613","as",78,80],["G1878","putting",81,88],["G5209","you",89,92],["G1878","in mind",93,100],["G1223","because",102,109],["G5485","of the grace",110,122],["G1325","that is given",123,136],["G3427","to me",137,142],["G5259","of",143,145],["G2316","God",146,149]]},"15:16":{"text":"That I should be the minister of Jesus Christ to the Gentiles, ministering the gospel of God, that the offering up of the Gentiles might be acceptable, being sanctified by the Holy Ghost.","words":[["G3165","That I",0,6],["G1519","should be",7,16],["G1511","should be",7,16],["G3011","the minister",17,29],["G2424","of Jesus",30,38],["G5547","Christ",39,45],["G1519","to",46,48],["G1484","the Gentiles",49,61],["G2418","ministering",63,74],["G2098","the gospel",75,85],["G2316","of God",86,92],["G2443","that",94,98],["G4376","the offering up",99,114],["G1484","of the Gentiles",115,130],["G1096","might be",131,139],["G2144","acceptable",140,150],["G0037","being sanctified",152,168],["G1722","by",169,171],["G0040","the Holy",172,180],["G4151","Ghost",181,186]]},"15:17":{"text":"I have therefore whereof I may glory through Jesus Christ in those things which pertain to God.","words":[["G2192","I have",0,6],["G3767","therefore whereof",7,24],["G2746","I may glory",25,36],["G1722","through",37,44],["G2424","Jesus",45,50],["G5547","Christ",51,57],["G4314","in those things which pertain to",58,90],["G2316","God",91,94]]},"15:18":{"text":"For I will not dare to speak of any of those things which Christ hath not wrought by me, to make the Gentiles obedient, by word and deed,","words":[["G1063","For",0,3],["G5111","I will",4,10],["G3756","not",11,14],["G5111","dare",15,19],["G2980","to speak",20,28],["G5100","of any",29,35],["G3739","of those things which",36,57],["G5547","Christ",58,64],["G2716","hath",65,69],["G3756","not",70,73],["G2716","wrought",74,81],["G1223","by",82,84],["G1700","me",85,87],["G1519","to make",89,96],["G1484","the Gentiles",97,109],["G5218","obedient",110,118],["G3056","by word",120,127],["G2532","and",128,131],["G2041","deed",132,136]]},"15:19":{"text":"Through mighty signs and wonders, by the power of the Spirit of God; so that from Jerusalem, and round about unto Illyricum, I have fully preached the gospel of Christ.","words":[["G1722","Through",0,7],["G1411","mighty",8,14],["G4592","signs",15,20],["G2532","and",21,24],["G5059","wonders",25,32],["G1722","by",34,36],["G1411","the power",37,46],["G4151","of the Spirit",47,60],["G2316","of God",61,67],["G5620","so",69,71],["G0575","that from",72,81],["G2419","Jerusalem",82,91],["G2532","and",93,96],["G2945","round about",97,108],["G3360","unto",109,113],["G2437","Illyricum",114,123],["G3165","I",125,126],["G4137","have fully preached",127,146],["G2098","the gospel",147,157],["G5547","of Christ",158,167]]},"15:20":{"text":"Yea, so have I strived to preach the gospel, not where Christ was named, lest I should build upon another man's foundation:","words":[["G1161","Yea",0,3],["G3779","so",5,7],["G5389","have I strived",8,22],["G2097","to preach the gospel",23,43],["G3756","not",45,48],["G3699","where",49,54],["G5547","Christ",55,61],["G3687","was named",62,71],["G3363","lest",73,77],["G3618","I should build",78,92],["G1909","upon",93,97],["G0245","another man's",98,111],["G2310","foundation",112,122]]},"15:21":{"text":"But as it is written, To whom he was not spoken of, they shall see: and they that have not heard shall understand.","words":[["G0235","But",0,3],["G2531","as",4,6],["G1125","it is written",7,20],["G3739","To whom",22,29],["G0846","he",30,32],["G0312","was",33,36],["G3756","not",37,40],["G0312","spoken",41,47],["G4012","of",48,50],["G3700","they shall see",52,66],["G2532","and",68,71],["G3739","they",72,76],["G0191","that have",77,86],["G3756","not",87,90],["G0191","heard",91,96],["G4920","shall understand",97,113]]},"15:22":{"text":"For which cause also I have been much hindered from coming to you.","words":[["G1352","For which cause",0,15],["G2532","also",16,20],["G1465","I have been",21,32],["G4183","much",33,37],["G1465","hindered",38,46],["G2064","from coming",47,58],["G4314","to",59,61],["G5209","you",62,65]]},"15:23":{"text":"But now having no more place in these parts, and having a great desire these many years to come unto you;","words":[["G1161","But",0,3],["G3570","now",4,7],["G2192","having",8,14],["G3371","no more",15,22],["G5117","place",23,28],["G1722","in",29,31],["G0575","these",32,37],["G5125","these",32,37],["G2824","parts",38,43],["G1161","and",45,48],["G2192","having",49,55],["G1974","a great desire",56,70],["G4183","these many",71,81],["G2094","years",82,87],["G2064","to come",88,95],["G4314","unto",96,100],["G5209","you",101,104]]},"15:24":{"text":"Whensoever I take my journey into Spain, I will come to you: for I trust to see you in my journey, and to be brought on my way thitherward by you, if first I be somewhat filled with your company.","words":[["G5613","Whensoever",0,10],["G1437","Whensoever",0,10],["G4198","I take my journey",11,28],["G1519","into",29,33],["G4681","Spain",34,39],["G2064","I will come",41,52],["G4314","to",53,55],["G5209","you",56,59],["G1063","for",61,64],["G1679","I trust",65,72],["G2300","to see",73,79],["G5209","you",80,83],["G1279","in my journey",84,97],["G2532","and",99,102],["G4311","to be brought on my way",103,126],["G1563","thitherward",127,138],["G5259","by",139,141],["G5216","you",142,145],["G1437","if",147,149],["G4412","first",150,155],["G1705","I be",156,160],["G3313","somewhat",161,169],["G1705","filled",170,176],["G0575","with",177,181],["G5216","your",182,186]]},"15:25":{"text":"But now I go unto Jerusalem to minister unto the saints.","words":[["G1161","But",0,3],["G3570","now",4,7],["G4198","I go",8,12],["G1519","unto",13,17],["G2419","Jerusalem",18,27],["G1247","to minister",28,39],["G0040","unto the saints",40,55]]},"15:26":{"text":"For it hath pleased them of Macedonia and Achaia to make a certain contribution for the poor saints which are at Jerusalem.","words":[["G1063","For",0,3],["G2106","it hath pleased them",4,24],["G3109","of Macedonia",25,37],["G2532","and",38,41],["G0882","Achaia",42,48],["G4160","to make",49,56],["G5100","a certain",57,66],["G2842","contribution",67,79],["G1519","for",80,83],["G4434","the poor",84,92],["G0040","saints",93,99],["G3588","which",100,105],["G1722","are at",106,112],["G2419","Jerusalem",113,122]]},"15:27":{"text":"It hath pleased them verily; and their debtors they are. For if the Gentiles have been made partakers of their spiritual things, their duty is also to minister unto them in carnal things.","words":[["G2106","It hath pleased them",0,20],["G1063","verily",21,27],["G2532","and",29,32],["G0846","their",33,38],["G3781","debtors",39,46],["G1526","they are",47,55],["G1063","For",57,60],["G1487","if",61,63],["G1484","the Gentiles",64,76],["G2841","have been made partakers",77,101],["G0846","of their",102,110],["G4152","spiritual things",111,127],["G3784","their duty is",129,142],["G2532","also",143,147],["G3008","to minister",148,159],["G0846","unto them",160,169],["G1722","in",170,172],["G4559","carnal things",173,186]]},"15:28":{"text":"When therefore I have performed this, and have sealed to them this fruit, I will come by you into Spain.","words":[["G3767","When therefore",0,14],["G2005","I have performed",15,31],["G5124","this",32,36],["G2532","and",38,41],["G4972","have sealed",42,53],["G0846","to them",54,61],["G5126","this",62,66],["G2590","fruit",67,72],["G0565","I will come",74,85],["G1223","by",86,88],["G5216","you",89,92],["G1519","into",93,97],["G4681","Spain",98,103]]},"15:29":{"text":"And I am sure that, when I come unto you, I shall come in the fulness of the blessing of the gospel of Christ.","words":[["G1161","And",0,3],["G1492","I am sure",4,13],["G3754","that",14,18],["G2064","when I come",20,31],["G4314","unto",32,36],["G5209","you",37,40],["G2064","I shall come",42,54],["G1722","in",55,57],["G4138","the fulness",58,69],["G2129","of the blessing",70,85],["G2098","of the gospel",86,99],["G5547","of Christ",100,109]]},"15:30":{"text":"Now I beseech you, brethren, for the Lord Jesus Christ's sake, and for the love of the Spirit, that ye strive together with me in your prayers to God for me;","words":[["G1161","Now",0,3],["G3870","I beseech",4,13],["G5209","you",14,17],["G0080","brethren",19,27],["G1223","for",29,32],["G2962","the Lord",33,41],["G2424","Jesus",42,47],["G5547","Christ's",48,56],["G2257","sake",57,61],["G2532","and",63,66],["G1223","for",67,70],["G0026","the love",71,79],["G4151","of the Spirit",80,93],["G4865","that ye strive together",95,118],["G3427","with me",119,126],["G1722","in",127,129],["G4335","your prayers",130,142],["G4314","to",143,145],["G2316","God",146,149],["G5228","for",150,153],["G1700","me",154,156]]},"15:31":{"text":"That I may be delivered from them that do not believe in Judaea; and that my service which I have for Jerusalem may be accepted of the saints;","words":[["G2443","That",0,4],["G4506","I may be delivered",5,23],["G0575","from",24,28],["G0544","them that do not believe",29,53],["G1722","in",54,56],["G2449","Judaea",57,63],["G2532","and",65,68],["G2443","that",69,73],["G3450","my",74,76],["G1248","service",77,84],["G3588","which",85,90],["G1519","I have for",91,101],["G2419","Jerusalem",102,111],["G1096","may be",112,118],["G2144","accepted",119,127],["G0040","of the saints",128,141]]},"15:32":{"text":"That I may come unto you with joy by the will of God, and may with you be refreshed.","words":[["G2443","That",0,4],["G2064","I may come",5,15],["G4314","unto",16,20],["G5209","you",21,24],["G1722","with",25,29],["G5479","joy",30,33],["G1223","by",34,36],["G2307","the will",37,45],["G2316","of God",46,52],["G2532","and",54,57],["G4875","may",58,61],["G5213","with you",62,70],["G4875","be refreshed",71,83]]},"15:33":{"text":"Now the God of peace be with you all. Amen.","words":[["G1161","Now",0,3],["G2316","the God",4,11],["G1515","of peace",12,20],["G3326","be with",21,28],["G5216","you",29,32],["G3956","all",33,36],["G0281","Amen",38,42]]},"16:1":{"text":"I commend unto you Phebe our sister, which is a servant of the church which is at Cenchrea:","words":[["G1161","",-1,-1],["G4921","I commend",0,9],["G5213","unto you",10,18],["G5402","Phebe",19,24],["G2257","our",25,28],["G0079","sister",29,35],["G5607","which is",37,45],["G1249","a servant",46,55],["G1577","of the church",56,69],["G3588","which",70,75],["G1722","is at",76,81],["G2747","Cenchrea",82,90]]},"16:2":{"text":"That ye receive her in the Lord, as becometh saints, and that ye assist her in whatsoever business she hath need of you: for she hath been a succourer of many, and of myself also.","words":[["G2443","That",0,4],["G4327","ye receive",5,15],["G0846","her",16,19],["G1722","in",20,22],["G2962","the Lord",23,31],["G0516","as becometh",33,44],["G0040","saints",45,51],["G2532","and",53,56],["G3936","that ye assist",57,71],["G0846","her",72,75],["G1722","in",76,78],["G3739","whatsoever",79,89],["G0302","whatsoever",79,89],["G4229","business",90,98],["G5535","she hath need",99,112],["G5216","of you",113,119],["G1063","for",121,124],["G3778","she",125,128],["G0846","she",125,128],["G1096","hath been",129,138],["G4368","a succourer",139,150],["G4183","of many",151,158],["G2532","and",160,163],["G0846","of myself",164,173],["G1700","of myself",164,173],["G2532","also",174,178]]},"16:3":{"text":"Greet Priscilla and Aquila my helpers in Christ Jesus:","words":[["G0782","Greet",0,5],["G4252","Priscilla",6,15],["G2532","and",16,19],["G0207","Aquila",20,26],["G3450","my",27,29],["G4904","helpers",30,37],["G1722","in",38,40],["G5547","Christ",41,47],["G2424","Jesus",48,53]]},"16:4":{"text":"Who have for my life laid down their own necks: unto whom not only I give thanks, but also all the churches of the Gentiles.","words":[["G3748","Who",0,3],["G5294","have",4,8],["G5228","for",9,12],["G3450","my",13,15],["G5590","life",16,20],["G5294","laid down",21,30],["G1438","their own",31,40],["G5137","necks",41,46],["G3739","unto whom",48,57],["G3756","not",58,61],["G3441","only",62,66],["G1473","I",67,68],["G2168","give thanks",69,80],["G0235","but",82,85],["G2532","also",86,90],["G3956","all",91,94],["G1577","the churches",95,107],["G1484","of the Gentiles",108,123]]},"16:5":{"text":"Likewise greet the church that is in their house. Salute my wellbeloved Epaenetus, who is the firstfruits of Achaia unto Christ.","words":[["G2532","Likewise",0,8],["G1577","greet the church",9,25],["G2596","that is in",26,36],["G0846","their",37,42],["G3624","house",43,48],["G0782","Salute",50,56],["G3450","my",57,59],["G0027","wellbeloved",60,71],["G1866","Epaenetus",72,81],["G3739","who",83,86],["G2076","is",87,89],["G0536","the firstfruits",90,105],["G0882","of Achaia",106,115],["G1519","unto",116,120],["G5547","Christ",121,127]]},"16:6":{"text":"Greet Mary, who bestowed much labour on us.","words":[["G0782","Greet",0,5],["G3137","Mary",6,10],["G3748","who",12,15],["G2872","bestowed",16,24],["G4183","much",25,29],["G2872","labour",30,36],["G1519","on",37,39],["G2248","us",40,42]]},"16:7":{"text":"Salute Andronicus and Junia, my kinsmen, and my fellowprisoners, who are of note among the apostles, who also were in Christ before me.","words":[["G0782","Salute",0,6],["G0408","Andronicus",7,17],["G2532","and",18,21],["G2458","Junia",22,27],["G3450","my",29,31],["G4773","kinsmen",32,39],["G2532","and",41,44],["G3450","my",45,47],["G4869","fellowprisoners",48,63],["G3748","who",65,68],["G1526","are",69,72],["G1978","of note",73,80],["G1722","among",81,86],["G0652","the apostles",87,99],["G3739","who",101,104],["G2532","also",105,109],["G1096","were",110,114],["G1722","in",115,117],["G5547","Christ",118,124],["G4253","before",125,131],["G1700","me",132,134]]},"16:8":{"text":"Greet Amplias my beloved in the Lord.","words":[["G0782","Greet",0,5],["G0291","Amplias",6,13],["G3450","my",14,16],["G0027","beloved",17,24],["G1722","in",25,27],["G2962","the Lord",28,36]]},"16:9":{"text":"Salute Urbane, our helper in Christ, and Stachys my beloved.","words":[["G0782","Salute",0,6],["G3773","Urbane",7,13],["G2257","our",15,18],["G4904","helper",19,25],["G1722","in",26,28],["G5547","Christ",29,35],["G2532","and",37,40],["G4720","Stachys",41,48],["G3450","my",49,51],["G0027","beloved",52,59]]},"16:10":{"text":"Salute Apelles approved in Christ. Salute them which are of Aristobulus' household.","words":[["G0782","Salute",0,6],["G0559","Apelles",7,14],["G1384","approved",15,23],["G1722","in",24,26],["G5547","Christ",27,33],["G0782","Salute",35,41],["G3588","them",42,46],["G1537","which are of",47,59],["G0711","Aristobulus'",60,72]]},"16:11":{"text":"Salute Herodion my kinsman. Greet them that be of the household of Narcissus, which are in the Lord.","words":[["G0782","Salute",0,6],["G2267","Herodion",7,15],["G3450","my",16,18],["G4773","kinsman",19,26],["G0782","Greet",28,33],["G3588","them",34,38],["G1537","that be of",39,49],["G3488","the household of Narcissus",50,76],["G3588","which",78,83],["G5607","are",84,87],["G1722","in",88,90],["G2962","the Lord",91,99]]},"16:12":{"text":"Salute Tryphena and Tryphosa, who labour in the Lord. Salute the beloved Persis, which laboured much in the Lord.","words":[["G0782","Salute",0,6],["G5170","Tryphena",7,15],["G2532","and",16,19],["G5173","Tryphosa",20,28],["G2872","who labour",30,40],["G1722","in",41,43],["G2962","the Lord",44,52],["G0782","Salute",54,60],["G0027","the beloved",61,72],["G4069","Persis",73,79],["G3748","which",81,86],["G2872","laboured",87,95],["G4183","much",96,100],["G1722","in",101,103],["G2962","the Lord",104,112]]},"16:13":{"text":"Salute Rufus chosen in the Lord, and his mother and mine.","words":[["G0782","Salute",0,6],["G4504","Rufus",7,12],["G1588","chosen",13,19],["G1722","in",20,22],["G2962","the Lord",23,31],["G2532","and",33,36],["G0846","his",37,40],["G3384","mother",41,47],["G2532","and",48,51],["G1700","mine",52,56]]},"16:14":{"text":"Salute Asyncritus, Phlegon, Hermas, Patrobas, Hermes, and the brethren which are with them.","words":[["G0782","Salute",0,6],["G0799","Asyncritus",7,17],["G5393","Phlegon",19,26],["G2057","Hermas",28,34],["G3969","Patrobas",36,44],["G2060","Hermes",46,52],["G2532","and",54,57],["G0080","the brethren",58,70],["G4862","which are with",71,85],["G0846","them",86,90]]},"16:15":{"text":"Salute Philologus, and Julia, Nereus, and his sister, and Olympas, and all the saints which are with them.","words":[["G0782","Salute",0,6],["G5378","Philologus",7,17],["G2532","and",19,22],["G2456","Julia",23,28],["G3517","Nereus",30,36],["G2532","and",38,41],["G0846","his",42,45],["G0079","sister",46,52],["G2532","and",54,57],["G3652","Olympas",58,65],["G2532","and",67,70],["G3956","all",71,74],["G0040","the saints",75,85],["G4862","which are with",86,100],["G0846","them",101,105]]},"16:16":{"text":"Salute one another with an holy kiss. The churches of Christ salute you.","words":[["G0782","Salute",0,6],["G0240","one another",7,18],["G1722","with",19,23],["G0040","an holy",24,31],["G5370","kiss",32,36],["G1577","The churches",38,50],["G5547","of Christ",51,60],["G0782","salute",61,67],["G5209","you",68,71]]},"16:17":{"text":"Now I beseech you, brethren, mark them which cause divisions and offences contrary to the doctrine which ye have learned; and avoid them.","words":[["G1161","Now",0,3],["G3870","I beseech",4,13],["G5209","you",14,17],["G0080","brethren",19,27],["G4648","mark",29,33],["G4160","them which cause",34,50],["G1370","divisions",51,60],["G2532","and",61,64],["G4625","offences",65,73],["G3844","contrary",74,82],["G1322","to the doctrine",83,98],["G3739","which",99,104],["G5210","ye",105,107],["G3129","have learned",108,120],["G2532","and",122,125],["G1578","avoid",126,131],["G0575","them",132,136],["G0846","them",132,136]]},"16:18":{"text":"For they that are such serve not our Lord Jesus Christ, but their own belly; and by good words and fair speeches deceive the hearts of the simple.","words":[["G1063","For",0,3],["G5108","they that are such",4,22],["G1398","serve",23,28],["G3756","not",29,32],["G2257","our",33,36],["G2962","Lord",37,41],["G2424","Jesus",42,47],["G5547","Christ",48,54],["G0235","but",56,59],["G1438","their own",60,69],["G2836","belly",70,75],["G2532","and",77,80],["G1223","by",81,83],["G5542","good words",84,94],["G2532","and",95,98],["G2129","fair speeches",99,112],["G1818","deceive",113,120],["G2588","the hearts",121,131],["G0172","of the simple",132,145]]},"16:19":{"text":"For your obedience is come abroad unto all men. I am glad therefore on your behalf: but yet I would have you wise unto that which is good, and simple concerning evil.","words":[["G1063","For",0,3],["G5216","your",4,8],["G5218","obedience",9,18],["G0864","is come abroad",19,33],["G1519","unto",34,38],["G3956","all",39,42],["G5463","men. I am glad",43,57],["G3767","therefore",58,67],["G1909","on",68,70],["G5213","your",71,75],["G1909","behalf",76,82],["G1161","but yet",84,91],["G2309","I would have",92,104],["G5209","you",105,108],["G4680","wise",109,113],["G1519","unto",114,118],["G1511","that which is",119,132],["G3303","good",133,137],["G0018","good",133,137],["G1161","and",139,142],["G0185","simple",143,149],["G1519","concerning",150,160],["G2556","evil",161,165]]},"16:20":{"text":"And the God of peace shall bruise Satan under your feet shortly. The grace of our Lord Jesus Christ be with you. Amen.","words":[["G1161","And",0,3],["G2316","the God",4,11],["G1515","of peace",12,20],["G4937","shall bruise",21,33],["G4567","Satan",34,39],["G5259","under",40,45],["G5216","your",46,50],["G4228","feet",51,55],["G1722","shortly",56,63],["G5034","shortly",56,63],["G5485","The grace",65,74],["G2257","of our",75,81],["G2962","Lord",82,86],["G2424","Jesus",87,92],["G5547","Christ",93,99],["G3326","be with",100,107],["G5216","you",108,111],["G0281","Amen",113,117]]},"16:21":{"text":"Timotheus my workfellow, and Lucius, and Jason, and Sosipater, my kinsmen, salute you.","words":[["G5095","Timotheus",0,9],["G3450","my",10,12],["G4904","workfellow",13,23],["G2532","and",25,28],["G3066","Lucius",29,35],["G2532","and",37,40],["G2394","Jason",41,46],["G2532","and",48,51],["G4989","Sosipater",52,61],["G3450","my",63,65],["G4773","kinsmen",66,73],["G0782","salute",75,81],["G5209","you",82,85]]},"16:22":{"text":"I Tertius, who wrote this epistle, salute you in the Lord.","words":[["G1473","I",0,1],["G5060","Tertius",2,9],["G1125","who wrote",11,20],["G1992","this epistle",21,33],["G0782","salute",35,41],["G5209","you",42,45],["G1722","in",46,48],["G2962","the Lord",49,57]]},"16:23":{"text":"Gaius mine host, and of the whole church, saluteth you. Erastus the chamberlain of the city saluteth you, and Quartus a brother.","words":[["G1050","Gaius",0,5],["G3450","mine",6,10],["G3581","host",11,15],["G2532","and",17,20],["G3650","of the whole",21,33],["G1577","church",34,40],["G0782","saluteth",42,50],["G5209","you",51,54],["G2037","Erastus",56,63],["G3623","the chamberlain",64,79],["G4172","of the city",80,91],["G0782","saluteth",92,100],["G5209","you",101,104],["G2532","and",106,109],["G2890","Quartus",110,117],["G0080","a brother",118,127]]},"16:24":{"text":"The grace of our Lord Jesus Christ be with you all. Amen.","words":[["G5485","The grace",0,9],["G2257","of our",10,16],["G2962","Lord",17,21],["G2424","Jesus",22,27],["G5547","Christ",28,34],["G3326","be with",35,42],["G5216","you",43,46],["G3956","all",47,50],["G0281","Amen",52,56]]},"16:25":{"text":"Now to him that is of power to stablish you according to my gospel, and the preaching of Jesus Christ, according to the revelation of the mystery, which was kept secret since the world began,","words":[["G1161","Now",0,3],["G1410","to him that is of power",4,27],["G4741","to stablish",28,39],["G5209","you",40,43],["G2596","according",44,53],["G3450","to my",54,59],["G2098","gospel",60,66],["G2532","and",68,71],["G2782","the preaching",72,85],["G2424","of Jesus",86,94],["G5547","Christ",95,101],["G2596","according",103,112],["G0602","to the revelation",113,130],["G3466","of the mystery",131,145],["G4601","which was kept secret",147,168],["G5550","since the world began",169,190],["G0166","since the world began",169,190]]},"16:26":{"text":"But now is made manifest, and by the scriptures of the prophets, according to the commandment of the everlasting God, made known to all nations for the obedience of faith:","words":[["G1161","But",0,3],["G3568","now",4,7],["G5319","is made manifest",8,24],["G5037","and",26,29],["G1223","by",30,32],["G1124","the scriptures",33,47],["G4397","of the prophets",48,63],["G2596","according",65,74],["G2003","to the commandment",75,93],["G0166","of the everlasting",94,112],["G2316","God",113,116],["G1107","made known",118,128],["G1519","to",129,131],["G3956","all",132,135],["G1484","nations",136,143],["G1519","for",144,147],["G5218","the obedience",148,161],["G4102","of faith",162,170]]},"16:27":{"text":"To God only wise, be glory through Jesus Christ for ever. Amen.","words":[["G2316","To God",0,6],["G3441","only",7,11],["G4680","wise",12,16],["G1391","be glory",18,26],["G1223","through",27,34],["G2424","Jesus",35,40],["G5547","Christ",41,47],["G1519","for",48,51],["G0165","ever",52,56],["G0281","Amen",58,62]]}}};
